@dataclass(frozen=True)
class FHIRAcquisitionContext:
    self_url: str | None = None
    fetch_url: str | None = None
    fetch_mode: str | None = None

    def __post_init__(self) -> None:
        if self.fetch_mode is not None and self.fetch_mode not in FHIR_FETCH_MODES:
            raise ValueError(f"unsupported FHIR fetch mode: {self.fetch_mode}")


@dataclass(frozen=True)
class ResourceFetchResult:
    model: type
    rows: list[dict[str, Any]]
    rows_fetched: int
    rows_written: int
    pages_fetched: int
    complete: bool
    row_limit_reached: bool
    page_limit_reached: bool
    hard_page_limit_reached: bool
    next_url_remaining: bool
    error: str | None = None
    fetch_mode: str = "paged"
    deadline_reached: bool = False
    retry_not_before: str | None = None
    fetch_diagnostic: dict[str, Any] | None = None
    pagination_cooldown_retries: int = 0
    pagination_cooldown_wait_seconds: float = 0.0
    is_pagination_cooldown_recovered: bool = False
    is_pagination_cooldown_exhausted: bool = False
    is_pagination_cooldown_deadline_blocked: bool = False

    @property
    def bounded(self) -> bool:
        """Return a fetch result constrained to the requested row limit."""
        return (
            self.row_limit_reached
            or self.page_limit_reached
            or self.hard_page_limit_reached
            or self.deadline_reached
        )


@dataclass(frozen=True)
class RestPaginationCooldownResult:
    fetch_result: tuple[int | None, dict[str, Any] | None, str | None, int]
    retries: int = 0
    wait_seconds: float = 0.0
    recovered: bool = False
    exhausted: bool = False
    deadline_blocked: bool = False


@dataclass(frozen=True)
class LastUpdatedPartitionConfig:
    """Strict source metadata for one resource's fail-closed acquisition."""

    start: datetime.datetime
    end: datetime.datetime | None
    end_mode: str
    ceiling: int
    minimum_width: datetime.timedelta
    page_count: int
    volatile_metadata_paths: tuple[str, ...]

    def identity(self) -> dict[str, Any]:
        """Return stable metadata identity without a moving resolved cutoff."""
        return {
            "start": self.start.isoformat(timespec="microseconds"),
            "end": (
                self.end.isoformat(timespec="microseconds")
                if self.end is not None
                else self.end_mode
            ),
            "ceiling": self.ceiling,
            "minimum_width_microseconds": int(
                self.minimum_width.total_seconds() * 1_000_000
            ),
            "page_count": self.page_count,
            "volatile_metadata_paths": list(self.volatile_metadata_paths),
            "strategy_version": LAST_UPDATED_PARTITION_STRATEGY_VERSION,
        }

    def root_end(self) -> datetime.datetime:
        """Resolve a fixed UTC root cutoff for a newly created acquisition."""
        if self.end is not None:
            return self.end
        return datetime.datetime.now(datetime.UTC)


