def _administrative_gender(resource: dict[str, Any]) -> str | None:
    gender = _clean_text(resource.get("gender"))
    return gender if gender in {"male", "female", "other", "unknown"} else None


def _period(resource: dict[str, Any]) -> tuple[str | None, str | None]:
    period = resource.get("period")
    if not isinstance(period, dict):
        return None, None
    return _clean_text(period.get("start")), _clean_text(period.get("end"))


def _address(resource: dict[str, Any]) -> dict[str, Any]:
    addresses = resource.get("address")
    if isinstance(addresses, dict):
        addresses = [addresses]
    first = next((item for item in addresses or [] if isinstance(item, dict)), {})
    lines = [str(value).strip() for value in first.get("line") or [] if _clean_text(value)]
    postal_code = _clean_text(first.get("postalCode"))
    zip5 = None
    if postal_code:
        match = ZIP5_RE.search(postal_code)
        zip5 = match.group(1) if match else None
    city = _clean_text(first.get("city"))
    raw_state = _clean_text(first.get("state"))
    state = _normalize_state_name(raw_state)
    state_code = _normalize_state_code(raw_state)
    country_code = _normalize_country_code(first.get("country"))
    position = resource.get("position") if isinstance(resource.get("position"), dict) else {}
    latitude, longitude = _normalize_fhir_position(position, country_code=country_code)
    return {
        "first_line": lines[0] if lines else None,
        "second_line": lines[1] if len(lines) > 1 else None,
        "city_name": city,
        "state_name": state,
        "state_code": state_code,
        "postal_code": postal_code,
        "zip5": zip5,
        "city_norm": city.upper() if city else None,
        "country_code": country_code,
        "latitude": latitude,
        "longitude": longitude,
        "address_json": first if first else None,
    }


def parse_capability(source: dict[str, Any], payload: dict[str, Any], probe: dict[str, Any]) -> dict[str, Any]:
    """Parse capability into normalized provider-directory records."""
    rest_resources: list[str] = []
    search_params: dict[str, list[str]] = {}
    for rest in payload.get("rest") or []:
        if not isinstance(rest, dict):
            continue
        for resource in rest.get("resource") or []:
            if not isinstance(resource, dict):
                continue
            resource_type = _clean_text(resource.get("type"))
            if not resource_type:
                continue
            rest_resources.append(resource_type)
            names = [
                str(item.get("name"))
                for item in resource.get("searchParam") or []
                if isinstance(item, dict) and _clean_text(item.get("name"))
            ]
            search_params[resource_type] = names
    software = payload.get("software") if isinstance(payload.get("software"), dict) else {}
    implementation = payload.get("implementation") if isinstance(payload.get("implementation"), dict) else {}
    digest = hashlib.sha256(json.dumps(payload, sort_keys=True, default=str).encode("utf-8")).hexdigest()
    return {
        "source_id": source["source_id"],
        "api_base": source.get("api_base"),
        "metadata_url": probe.get("url"),
        "probe_status": probe["status"],
        "http_status": probe.get("http_status"),
        "response_time_ms": probe.get("response_time_ms"),
        "resource_type": _clean_text(payload.get("resourceType")),
        "fhir_version": _clean_text(payload.get("fhirVersion")),
        "software_name": _clean_text(software.get("name")),
        "software_version": _clean_text(software.get("version")),
        "implementation_url": _clean_text(implementation.get("url")),
        "formats": payload.get("format") or [],
        "supported_resources": sorted(set(rest_resources)),
        "search_params": search_params,
        "auth_required": probe["status"] == "auth_required",
        "error": probe.get("error"),
        "capability_hash": digest,
        "probed_at": _now(),
        "run_id": probe.get("run_id"),
        "metadata_json": {
            "publisher": _clean_text(payload.get("publisher")),
            "date": _clean_text(payload.get("date")),
            "kind": _clean_text(payload.get("kind")),
        },
    }


def _fhir_resource_base_fields(
    source_id: str,
    resource: dict[str, Any],
    resource_url: str | None,
    acquisition: FHIRAcquisitionContext | None,
    run_id: str | None,
) -> dict[str, Any]:
    observed_at = _now()
    return {
        "source_id": source_id,
        "resource_id": _resource_id(resource),
        "resource_url": _sanitized_fhir_url_identity(resource_url),
        **_fhir_acquisition_fields(resource, acquisition),
        "last_seen_run_id": run_id,
        "observed_at": observed_at,
        "updated_at": observed_at,
    }


def parse_fhir_resource(
    source_id: str,
    resource: dict[str, Any],
    *,
    resource_url: str | None = None,
    acquisition: FHIRAcquisitionContext | None = None,
    run_id: str | None = None,
    normalize_location_contacts: bool = True,
) -> tuple[type, dict[str, Any]] | None:
    """Parse fhir resource into normalized provider-directory records."""
    resource_type = resource.get("resourceType")
    base = _fhir_resource_base_fields(
        source_id,
        resource,
        resource_url,
        acquisition,
        run_id,
    )
    if resource_type == "InsurancePlan":
        period_start, period_end = _period(resource)
        plan = next((item for item in resource.get("plan") or [] if isinstance(item, dict)), {})
        identifier = _identifier_value(
            plan,
            "planid",
            "plan-id",
            "hios",
            allow_systemless=True,
        ) or _identifier_value(
            resource,
            "plan",
            "hios",
            "formulary_id",
            allow_systemless=True,
        )
        row = {
            **base,
            "plan_identifier": identifier,
            "product_identifiers": _normalized_identifiers(
                resource.get("identifier")
            ),
            "plan_backbones": _normalized_insurance_plan_backbones(resource),
            "coverage": _normalized_insurance_plan_coverage(resource),
            "status": _clean_text(resource.get("status")),
            "name": _clean_text(resource.get("name")),
            "aliases": resource.get("alias") or [],
            "type_codes": _codings(resource.get("type")),
            "owned_by_ref": _first_reference(resource.get("ownedBy")),
            "administered_by_ref": _first_reference(resource.get("administeredBy")),
            "network_refs": _insurance_plan_network_references(resource),
            "coverage_area_refs": _references(resource.get("coverageArea")),
            "plan_json": plan or None,
            "period_start": period_start,
            "period_end": period_end,
        }
        return ProviderDirectoryInsurancePlan, row
    if resource_type == "Practitioner":
        family, given, full_name = _name(resource)
        row = {
            **base,
            "npi": _resource_npi(resource),
            "active": resource.get("active") if isinstance(resource.get("active"), bool) else None,
            "identifiers": _normalized_identifiers(resource.get("identifier")),
            "names": _normalized_human_names(resource.get("name")),
            "family_name": family,
            "given_names": given,
            "full_name": full_name,
            "administrative_gender": _administrative_gender(resource),
            **_practitioner_derived_profile_fields(
                resource,
                as_of=base["observed_at"].date(),
            ),
            "telecom": _telecom(resource),
            "addresses": _normalized_fhir_addresses(resource.get("address")),
            "qualification_codes": _codings([item.get("code") for item in resource.get("qualification") or [] if isinstance(item, dict)]),
            "qualifications": _normalized_qualifications(
                resource.get("qualification")
            ),
            "communication_codes": _codings(resource.get("communication")),
            "communications": _normalized_communications(
                resource.get("communication")
            ),
            "photos": _normalized_photo_metadata(resource.get("photo")),
        }
        return ProviderDirectoryPractitioner, row
    if resource_type == "Organization":
        row = {
            **base,
            "npi": _resource_npi(resource),
            "tax_id": _tin(resource),
            "active": resource.get("active") if isinstance(resource.get("active"), bool) else None,
            "identifiers": _normalized_identifiers(resource.get("identifier")),
            "name": _clean_text(resource.get("name")),
            "aliases": resource.get("alias") or [],
            "type_codes": _codings(resource.get("type")),
            "telecom": _telecom(resource),
            "address_json": resource.get("address") or [],
            "contacts": _normalized_organization_contacts(resource.get("contact")),
            "part_of_ref": _first_reference(resource.get("partOf")),
            "endpoint_refs": _references(resource.get("endpoint")),
        }
        return ProviderDirectoryOrganization, row
    if resource_type == "Location":
        telecom = _telecom(resource)
        address = _address(resource)
        telephone_number = _phone(telecom)
        fax_number = _fax(telecom)
        row = {
            **base,
            "status": _clean_text(resource.get("status")),
            "name": _clean_text(resource.get("name")),
            "description": _profile_text(resource.get("description")),
            "mode": _clean_text(resource.get("mode")),
            "type_codes": _codings(resource.get("type")),
            "physical_type_codes": _codings(resource.get("physicalType")),
            "managing_organization_ref": _first_reference(
                resource.get("managingOrganization")
            ),
            "telephone_number": telephone_number,
            "fax_number": fax_number,
            "telecom": telecom,
            "addresses": _normalized_fhir_addresses(resource.get("address")),
            "hours_of_operation": [
                item
                for item in resource.get("hoursOfOperation") or []
                if isinstance(item, dict)
            ],
            "availability_exceptions": _profile_text(
                resource.get("availabilityExceptions")
            ),
            "photos": _normalized_photo_metadata(resource.get("photo")),
            **{key: value for key, value in address.items() if key != "address_json"},
        }
        if normalize_location_contacts:
            row.update(_location_contact_fields(telephone_number, fax_number, address.get("country_code")))
        return ProviderDirectoryLocation, row
    if resource_type == "PractitionerRole":
        period_start, period_end = _period(resource)
        row = {
            **base,
            "npi": _npi(resource),
            "active": resource.get("active") if isinstance(resource.get("active"), bool) else None,
            "identifiers": _normalized_identifiers(resource.get("identifier")),
            "practitioner_ref": _first_reference(resource.get("practitioner")),
            "organization_ref": _first_reference(resource.get("organization")),
            "location_refs": _references(resource.get("location")),
            "healthcare_service_refs": _references(resource.get("healthcareService")),
            "network_refs": _network_references(resource),
            "insurance_plan_refs": _references(resource.get("insurancePlan")),
            "endpoint_refs": _references(resource.get("endpoint")),
            "specialty_codes": _codings(resource.get("specialty")),
            "code_codes": _codings(resource.get("code")),
            "telecom": _telecom(resource),
            **_practitioner_role_completeness_fields(resource),
            "period_start": period_start,
            "period_end": period_end,
        }
        return ProviderDirectoryPractitionerRole, row
    if resource_type == "HealthcareService":
        row = {
            **base,
            "provided_by_ref": _first_reference(resource.get("providedBy")),
            "accepting_patients": _plan_net_accepting_patients(resource),
            "npi": _npi(resource),
            "active": resource.get("active") if isinstance(resource.get("active"), bool) else None,
            "identifiers": _normalized_identifiers(resource.get("identifier")),
            "name": _clean_text(resource.get("name")),
            "type_codes": _codings(resource.get("type")),
            "category_codes": _codings(resource.get("category")),
            "specialty_codes": _codings(resource.get("specialty")),
            "program_codes": _codings(resource.get("program")),
            "characteristic_codes": _codings(resource.get("characteristic")),
            "communication_codes": _codings(resource.get("communication")),
            "referral_method_codes": _codings(resource.get("referralMethod")),
            "service_provision_codes": _codings(
                resource.get("serviceProvisionCode")
            ),
            "eligibility": _normalized_service_eligibility(
                resource.get("eligibility")
            ),
            "appointment_required": resource.get("appointmentRequired")
            if isinstance(resource.get("appointmentRequired"), bool)
            else None,
            "location_refs": _references(resource.get("location")),
            "endpoint_refs": _references(resource.get("endpoint")),
            "telecom": _telecom(resource),
            "coverage_area_refs": _references(resource.get("coverageArea")),
            "available_time": [
                item
                for item in resource.get("availableTime") or []
                if isinstance(item, dict)
            ],
            "not_available": [
                item
                for item in resource.get("notAvailable") or []
                if isinstance(item, dict)
            ],
            "availability_exceptions": _profile_text(
                resource.get("availabilityExceptions")
            ),
            "extra_details": _profile_text(resource.get("extraDetails")),
            "comment": _profile_text(resource.get("comment")),
            "photos": _normalized_photo_metadata(resource.get("photo")),
        }
        return ProviderDirectoryHealthcareService, row
    if resource_type == "OrganizationAffiliation":
        period_start, period_end = _period(resource)
        row = {
            **base,
            "active": resource.get("active") if isinstance(resource.get("active"), bool) else None,
            "identifiers": _normalized_identifiers(resource.get("identifier")),
            "organization_ref": _first_reference(resource.get("organization")),
            "participating_organization_ref": _first_reference(resource.get("participatingOrganization")),
            "network_refs": _references(resource.get("network")),
            "location_refs": _references(resource.get("location")),
            "healthcare_service_refs": _references(resource.get("healthcareService")),
            "endpoint_refs": _references(resource.get("endpoint")),
            "specialty_codes": _codings(resource.get("specialty")),
            "code_codes": _codings(resource.get("code")),
            "telecom": _telecom(resource),
            "period_start": period_start,
            "period_end": period_end,
        }
        return ProviderDirectoryOrganizationAffiliation, row
    if resource_type == "Endpoint":
        period_start, period_end = _period(resource)
        connection_type = resource.get("connectionType") if isinstance(resource.get("connectionType"), dict) else {}
        contact = resource.get("contact") or []
        row = {
            **base,
            "status": _clean_text(resource.get("status")),
            "connection_type_system": _clean_text(connection_type.get("system")),
            "connection_type_code": _clean_text(connection_type.get("code")),
            "connection_type_display": _clean_text(connection_type.get("display")),
            "name": _clean_text(resource.get("name")),
            "managing_organization_ref": _first_reference(resource.get("managingOrganization")),
            "contact": [item for item in contact if isinstance(item, dict)] if isinstance(contact, list) else [],
            "period_start": period_start,
            "period_end": period_end,
            "payload_type_codes": _codings(resource.get("payloadType")),
            "payload_mime_types": _string_list(resource.get("payloadMimeType")),
            "address": _clean_text(resource.get("address")),
            "header": _string_list(resource.get("header")),
        }
        return ProviderDirectoryEndpoint, row
    return None


def _alohr_source_uses_graphql_connector(source: dict[str, Any]) -> bool:
    api_base = _canonical_base(source.get("api_base") or source.get("canonical_api_base"))
    if api_base in {ALOHR_PUBLIC_PROVIDER_DIRECTORY_BASE, ALOHR_FHIR_PROVIDER_DIRECTORY_BASE}:
        return True
    metadata = source.get("metadata_json") if isinstance(source.get("metadata_json"), dict) else {}
    return metadata.get("provider_directory_graphql_tenant_id") == ALOHR_TENANT_ID


def _alohr_resource_id(prefix: str, *parts: Any) -> str:
    cleaned = [_clean_text(part) or "" for part in parts]
    raw = "|".join(cleaned)
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()[:16]
    candidate = _clean_text(parts[0]) if parts else None
    if candidate and re.fullmatch(r"[A-Za-z0-9_.:-]{1,160}", candidate):
        return candidate if prefix == "" else f"{prefix}-{candidate}"
    return f"{prefix}-{digest}" if prefix else digest


def _alohr_npi(value: Any) -> int | None:
    text = _clean_text(value)
    if not text or not text.isdigit():
        return None
    try:
        return int(text)
    except Exception:
        return None


def _alohr_telecom(*items: Any) -> list[dict[str, Any]]:
    telecom: list[dict[str, Any]] = []
    for item in items:
        if not item:
            continue
        if isinstance(item, list):
            for nested in item:
                if isinstance(nested, dict):
                    system = _clean_text(nested.get("system"))
                    value = _clean_text(nested.get("value"))
                    if system and value:
                        telecom.append({"system": system, "value": value, "use": _clean_text(nested.get("use"))})
            continue
        if isinstance(item, dict):
            for nested in item.get("contacts") or []:
                if isinstance(nested, dict):
                    system = _clean_text(nested.get("system"))
                    value = _clean_text(nested.get("value"))
                    if system and value:
                        telecom.append({"system": system, "value": value, "use": _clean_text(nested.get("use"))})
            continue
        value = _clean_text(item)
        if value:
            system = "email" if "@" in value else "phone"
            telecom.append({"system": system, "value": value})
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[str | None, str | None, str | None]] = set()
    for item in telecom:
        key = (item.get("system"), item.get("value"), item.get("use"))
        if key in seen:
            continue
        seen.add(key)
        deduped.append({key: value for key, value in item.items() if value is not None})
    return deduped


def _alohr_specialty_codings(code: Any, display: Any) -> list[dict[str, Any]]:
    clean_code = _clean_text(code)
    clean_display = _clean_text(display)
    if not clean_code and not clean_display:
        return []
    coding: dict[str, Any] = {}
    if clean_code:
        coding.update({"system": "http://nucc.org/provider-taxonomy", "code": clean_code})
    if clean_display:
        coding["display"] = clean_display
    return [coding]


def _alohr_address_items(item: dict[str, Any]) -> list[dict[str, Any]]:
    raw_addresses = item.get("addresses") if isinstance(item.get("addresses"), list) else []
    if not raw_addresses and isinstance(item.get("address"), dict):
        raw_addresses = [item["address"]]
    addresses: list[dict[str, Any]] = []
    seen: set[tuple[str | None, ...]] = set()
    for raw in raw_addresses:
        if not isinstance(raw, dict):
            continue
        street1 = _clean_text(raw.get("street1"))
        street2 = _clean_text(raw.get("street2"))
        city = _clean_text(raw.get("city"))
        state = _clean_text(raw.get("state"))
        zip_code = _clean_text(raw.get("zip"))
        if not any((street1, city, state, zip_code)):
            continue
        key = (street1, street2, city, state, zip_code)
        if key in seen:
            continue
        seen.add(key)
        address: dict[str, Any] = {
            "use": _clean_text(raw.get("type")) or "work",
            "line": [value for value in (street1, street2) if value],
            "city": city,
            "state": state,
            "postalCode": zip_code,
            "country": "US",
        }
        if _clean_text(raw.get("county")):
            address["district"] = _clean_text(raw.get("county"))
        addresses.append(address)
    return addresses


def _alohr_location_resource(owner_id: str, owner_name: str | None, address: dict[str, Any], telecom: list[dict[str, Any]]) -> dict[str, Any]:
    address_key = json.dumps(address, sort_keys=True)
    resource_id = _alohr_resource_id("loc", owner_id, address_key)
    return {
        "resourceType": "Location",
        "id": resource_id,
        "status": "active",
        "name": owner_name,
        "address": address,
        "telecom": telecom,
    }


def _append_alohr_parsed_resource(
    rows_by_model: dict[type, list[dict[str, Any]]],
    source_id: str,
    resource: dict[str, Any],
    *,
    run_id: str | None,
) -> None:
    resource_type = _clean_text(resource.get("resourceType")) or "Resource"
    resource_id = _resource_id(resource)
    parsed = parse_fhir_resource(
        source_id,
        resource,
        resource_url=(
            "urn:healthporta:provider-directory:alohr:"
            f"{resource_type}:{resource_id}"
        ),
        acquisition=FHIRAcquisitionContext(
            fetch_url=ALOHR_GRAPHQL_URL,
            fetch_mode="graphql",
        ),
        run_id=run_id,
        normalize_location_contacts=resource.get("resourceType") != "Location",
    )
    if parsed:
        model, row = parsed
        rows_by_model.setdefault(model, []).append(row)


def _alohr_reviewed_boolean_extensions(
    provider: dict[str, Any],
) -> list[dict[str, Any]]:
    """Map only explicit ALOHR booleans into reviewed local extensions."""

    extensions = []
    for extension_url, value in (
        (
            "https://healthporta.com/fhir/provider-directory/telehealth",
            provider.get("telehealth"),
        ),
        (
            "https://healthporta.com/fhir/provider-directory/accepting-medicaid",
            provider.get("acceptingMedicaid"),
        ),
    ):
        if isinstance(value, bool):
            extensions.append(
                {"url": extension_url, "valueBoolean": value}
            )
    return extensions


def _alohr_provider_role_resource(
    provider: dict[str, Any],
    provider_id: str,
    location_refs: list[dict[str, str]],
    specialty: list[dict[str, Any]],
    telecom: list[dict[str, Any]],
) -> dict[str, Any]:
    """Build one role without requiring an address-backed Location."""

    return {
        "resourceType": "PractitionerRole",
        "id": _alohr_resource_id(
            "role",
            provider_id,
            ",".join(ref["reference"] for ref in location_refs),
        ),
        "active": True,
        "practitioner": {"reference": f"Practitioner/{provider_id}"},
        "location": location_refs,
        "specialty": [{"coding": specialty}] if specialty else [],
        "telecom": telecom,
        "extension": _alohr_reviewed_boolean_extensions(provider),
    }


def _append_alohr_provider_rows(
    rows_by_model: dict[type, list[dict[str, Any]]],
    source_id: str,
    provider: dict[str, Any],
    *,
    run_id: str | None,
) -> None:
    """Append normalized Practitioner, Location, and role rows for ALOHR."""

    provider_id = _clean_text(provider.get("providerId")) or _alohr_resource_id("prac", provider.get("npi"), provider.get("firstName"), provider.get("lastName"))
    full_name = " ".join(value for value in (_clean_text(provider.get("firstName")), _clean_text(provider.get("lastName"))) if value)
    telecom = _alohr_telecom(provider.get("phone"), provider.get("email"))
    specialty = _alohr_specialty_codings(provider.get("specialty"), provider.get("specialtyDescription"))
    identifiers = []
    if _clean_text(provider.get("npi")):
        identifiers.append({"system": "http://hl7.org/fhir/sid/us-npi", "value": _clean_text(provider.get("npi"))})
    practitioner = {
        "resourceType": "Practitioner",
        "id": provider_id,
        "active": True,
        "identifier": identifiers,
        "name": [
            {
                "family": _clean_text(provider.get("lastName")),
                "given": [_clean_text(provider.get("firstName"))] if _clean_text(provider.get("firstName")) else [],
                "text": full_name or None,
            }
        ],
        "telecom": telecom,
        "qualification": [{"code": {"coding": specialty}}] if specialty else [],
        "communication": [{"coding": [{"display": language}]} for language in provider.get("languages") or [] if _clean_text(language)],
    }
    _append_alohr_parsed_resource(rows_by_model, source_id, practitioner, run_id=run_id)
    location_refs: list[dict[str, str]] = []
    for address in _alohr_address_items(provider):
        location = _alohr_location_resource(provider_id, full_name or provider_id, address, telecom)
        _append_alohr_parsed_resource(rows_by_model, source_id, location, run_id=run_id)
        location_refs.append({"reference": f"Location/{location['id']}"})
    role = _alohr_provider_role_resource(
        provider,
        provider_id,
        location_refs,
        specialty,
        telecom,
    )
    _append_alohr_parsed_resource(rows_by_model, source_id, role, run_id=run_id)


def _append_alohr_organization_rows(
    rows_by_model: dict[type, list[dict[str, Any]]],
    source_id: str,
    organization: dict[str, Any],
    *,
    run_id: str | None,
) -> None:
    org_id = _clean_text(organization.get("orgId")) or _alohr_resource_id("org", organization.get("npi"), organization.get("name"))
    contacts = []
    for item in organization.get("contacts") or []:
        if isinstance(item, dict):
            contacts.extend(item.get("contacts") or [])
    contacts.extend(organization.get("organizationContact") or [])
    telecom = _alohr_telecom(contacts)
    specialty = _alohr_specialty_codings(organization.get("specialty"), organization.get("specialtyDescription"))
    identifiers = []
    if _clean_text(organization.get("npi")):
        identifiers.append({"system": "http://hl7.org/fhir/sid/us-npi", "value": _clean_text(organization.get("npi"))})
    org_resource = {
        "resourceType": "Organization",
        "id": org_id,
        "active": True,
        "identifier": identifiers,
        "name": _clean_text(organization.get("name")),
        "type": [{"coding": specialty}] if specialty else [],
        "telecom": telecom,
        "address": _alohr_address_items(organization),
    }
    _append_alohr_parsed_resource(rows_by_model, source_id, org_resource, run_id=run_id)
    for address in _alohr_address_items(organization):
        location = _alohr_location_resource(org_id, _clean_text(organization.get("name")) or org_id, address, telecom)
        _append_alohr_parsed_resource(rows_by_model, source_id, location, run_id=run_id)


def provider_directory_address_corroboration_sql(
    db_schema: str | None = None,
    *,
    view_name: str = PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW,
) -> str:
    """Build a view that corroborates role-bound Provider Directory addresses.

    The compact address overlay is the driving relation, scoped to role and
    affiliation rows that can carry network context. Direct Organization
    address evidence stays in provider_directory_address_overlay for provider
    APIs, but is intentionally excluded from this PTG corroboration artifact.
    """

    schema = db_schema or _schema()
    view_ref = _qt(schema, view_name)
    plan_ref_resource_id_expr = _sql_reference_resource_id("plan_ref.value", "InsurancePlan")
    network_ref_resource_id_expr = _sql_reference_resource_id("network_ref.value", "Organization")
    return f"""
    CREATE OR REPLACE VIEW {view_ref} AS
    WITH address_candidates AS (
        SELECT
            overlay.source_record_id::varchar AS source_record_id,
            overlay.source_id::varchar AS source_id,
            overlay.resource_type::varchar AS resource_type,
            overlay.resource_id::varchar AS resource_id,
            CASE
                WHEN overlay.resource_type IN ('PractitionerRole', 'OrganizationAffiliation')
                    THEN NULLIF(split_part(overlay.source_record_id, ':', 5), '')
                ELSE NULL::varchar
            END AS location_resource_id,
            overlay.npi::bigint AS npi,
            NULL::varchar AS location_key,
            overlay.address_key::uuid AS address_key,
            NULLIF(LEFT(regexp_replace(COALESCE(overlay.postal_code, ''), '\\D', '', 'g'), 5), '')::varchar AS zip5,
            overlay.state_code::varchar AS state_code,
            NULLIF(regexp_replace(upper(BTRIM(COALESCE(overlay.city_name, ''))), '[^A-Z0-9]+', '', 'g'), '')::varchar AS city_norm,
            overlay.telephone_number::varchar AS telephone_number,
            overlay.phone_number::varchar AS phone_number,
            overlay.fax_number::varchar AS fax_number,
            overlay.fax_number_digits::varchar AS fax_number_digits,
            overlay.source_updated_at AS source_updated_at
          FROM {_qt(schema, PROVIDER_DIRECTORY_ADDRESS_OVERLAY_TABLE)} overlay
         WHERE overlay.npi IS NOT NULL
           AND overlay.address_key IS NOT NULL
           AND overlay.resource_type IN ('PractitionerRole', 'OrganizationAffiliation')
    ),
    practitioner_matches AS (
        SELECT
            NULL::varchar AS source_key,
            NULL::varchar AS snapshot_id,
            NULL::varchar AS plan_id,
            NULL::varchar AS ptg_plan_id,
            e.npi,
            e.location_key,
            e.address_key,
            e.zip5,
            e.state_code,
            e.city_norm,
            src.source_id AS provider_directory_source_id,
            src.org_name AS provider_directory_org_name,
            src.plan_name AS provider_directory_plan_name,
            practitioner.resource_id AS provider_directory_provider_resource_id,
            practitioner.full_name AS provider_directory_provider_name,
            role.resource_id AS provider_directory_role_resource_id,
            COALESCE(loc.resource_id, e.location_resource_id) AS provider_directory_location_resource_id,
            loc.name AS provider_directory_location_name,
            COALESCE(loc.telephone_number, e.telephone_number) AS provider_directory_telephone_number,
            COALESCE(loc.phone_number, e.phone_number) AS provider_directory_phone_number,
            loc.phone_extension AS provider_directory_phone_extension,
            COALESCE(loc.fax_number, e.fax_number) AS provider_directory_fax_number,
            COALESCE(loc.fax_number_digits, e.fax_number_digits) AS provider_directory_fax_number_digits,
            loc.fax_extension AS provider_directory_fax_extension,
            COALESCE(role.network_refs::jsonb, '[]'::jsonb) AS provider_directory_network_refs,
            COALESCE(role.insurance_plan_refs::jsonb, '[]'::jsonb) AS provider_directory_insurance_plan_refs,
            COALESCE(network_context.provider_directory_network_names, ARRAY[]::varchar[])
                AS provider_directory_network_names,
            COALESCE(network_context.provider_directory_network_matches, '[]'::jsonb)
                AS provider_directory_network_matches,
            false AS provider_directory_plan_context_matched,
            COALESCE(network_context.provider_directory_network_context_present, false)
                AS provider_directory_network_context_present,
            COALESCE(plan_context.provider_directory_insurance_plan_matches, '[]'::jsonb)
                AS provider_directory_insurance_plan_matches,
            COALESCE(role.specialty_codes::jsonb, '[]'::jsonb) AS provider_directory_specialty_codes,
            COALESCE(role.code_codes::jsonb, '[]'::jsonb) AS provider_directory_role_codes,
            'practitioner_role'::varchar AS provider_directory_match_type,
            (role.active IS DISTINCT FROM false) AS provider_directory_active_role,
            (practitioner.active IS DISTINCT FROM false) AS provider_directory_active_provider,
            (loc.resource_id IS NULL OR loc.status IS NULL OR lower(loc.status) <> 'inactive') AS provider_directory_active_location,
            GREATEST(
                COALESCE(e.source_updated_at, TIMESTAMP 'epoch'),
                COALESCE(role.observed_at, TIMESTAMP 'epoch'),
                COALESCE(practitioner.observed_at, TIMESTAMP 'epoch'),
                COALESCE(loc.observed_at, TIMESTAMP 'epoch')
            ) AS provider_directory_observed_at
          FROM address_candidates e
          JOIN {_qt(schema, "provider_directory_practitioner_role")} role
            ON e.resource_type = 'PractitionerRole'
           AND role.source_id = e.source_id
           AND role.resource_id = e.resource_id
          JOIN {_qt(schema, "provider_directory_practitioner")} practitioner
            ON practitioner.source_id = role.source_id
           AND practitioner.resource_id = NULLIF(regexp_replace(COALESCE(role.practitioner_ref, ''), '^.*/', ''), '')
           AND COALESCE(practitioner.npi, role.npi) = e.npi
          LEFT JOIN {_qt(schema, "provider_directory_location")} loc
            ON loc.source_id = e.source_id
           AND loc.resource_id = e.location_resource_id
          LEFT JOIN LATERAL (
            SELECT
                COALESCE(
                    jsonb_agg(
                        DISTINCT jsonb_build_object(
                            'ref', plan_ref.value,
                            'resource_id', insurance_plan.resource_id,
                            'plan_identifier', insurance_plan.plan_identifier,
                            'name', insurance_plan.name
                        )
                    ) FILTER (WHERE plan_ref.value IS NOT NULL),
                    '[]'::jsonb
                ) AS provider_directory_insurance_plan_matches
              FROM jsonb_array_elements_text(
                  COALESCE(role.insurance_plan_refs::jsonb, '[]'::jsonb)
              ) AS plan_ref(value)
              LEFT JOIN {_qt(schema, "provider_directory_insurance_plan")} insurance_plan
                ON insurance_plan.source_id = role.source_id
               AND insurance_plan.resource_id = {plan_ref_resource_id_expr}
          ) plan_context ON TRUE
          LEFT JOIN LATERAL (
            WITH network_ref_values AS (
                SELECT network_ref.value
                  FROM jsonb_array_elements_text(
                      COALESCE(role.network_refs::jsonb, '[]'::jsonb)
                  ) AS network_ref(value)
                UNION
                SELECT plan_network_ref.value
                  FROM jsonb_array_elements_text(
                      COALESCE(role.insurance_plan_refs::jsonb, '[]'::jsonb)
                  ) AS plan_ref(value)
                  JOIN {_qt(schema, "provider_directory_insurance_plan")} insurance_plan
                    ON insurance_plan.source_id = role.source_id
                   AND insurance_plan.resource_id = {plan_ref_resource_id_expr}
                  CROSS JOIN LATERAL jsonb_array_elements_text(
                      COALESCE(insurance_plan.network_refs::jsonb, '[]'::jsonb)
                  ) AS plan_network_ref(value)
            )
            SELECT
                bool_or(network_ref.value IS NOT NULL) AS provider_directory_network_context_present,
                COALESCE(
                    array_agg(DISTINCT network_catalog.provider_directory_network_name)
                        FILTER (WHERE NULLIF(BTRIM(network_catalog.provider_directory_network_name), '') IS NOT NULL),
                    ARRAY[]::varchar[]
                ) AS provider_directory_network_names,
                COALESCE(
                    jsonb_agg(
                        DISTINCT jsonb_build_object(
                            'ref', network_ref.value,
                            'resource_id', network_catalog.network_resource_id,
                            'name', network_catalog.provider_directory_network_name,
                            'aliases', COALESCE(network_catalog.aliases::jsonb, '[]'::jsonb),
                            'provider_directory_network_key', network_catalog.provider_directory_network_key,
                            'provider_directory_source', 'provider_directory_fhir',
                            'provider_directory_source_id', role.source_id,
                            'provider_directory_org_name', network_catalog.source_org_name,
                            'provider_directory_plan_name', network_catalog.source_plan_name,
                            'provider_directory_issuer_key', network_catalog.provider_directory_issuer_key,
                            'provider_directory_issuer_network_match_key',
                                network_catalog.provider_directory_issuer_network_match_key
                        )
                    ) FILTER (WHERE network_catalog.network_resource_id IS NOT NULL),
                    '[]'::jsonb
                ) AS provider_directory_network_matches
              FROM network_ref_values network_ref
              LEFT JOIN {_qt(schema, PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)} network_catalog
                ON network_catalog.source_id = role.source_id
               AND network_catalog.network_resource_id = {network_ref_resource_id_expr}
          ) network_context ON TRUE
          JOIN {_qt(schema, "provider_directory_source")} src
            ON src.source_id = role.source_id
         WHERE e.npi IS NOT NULL
           AND e.address_key IS NOT NULL
    ),
    organization_affiliation_matches AS (
        SELECT
            NULL::varchar AS source_key,
            NULL::varchar AS snapshot_id,
            NULL::varchar AS plan_id,
            NULL::varchar AS ptg_plan_id,
            e.npi,
            e.location_key,
            e.address_key,
            e.zip5,
            e.state_code,
            e.city_norm,
            src.source_id AS provider_directory_source_id,
            src.org_name AS provider_directory_org_name,
            src.plan_name AS provider_directory_plan_name,
            organization.resource_id AS provider_directory_provider_resource_id,
            organization.name AS provider_directory_provider_name,
            affiliation.resource_id AS provider_directory_role_resource_id,
            COALESCE(loc.resource_id, e.location_resource_id) AS provider_directory_location_resource_id,
            loc.name AS provider_directory_location_name,
            COALESCE(loc.telephone_number, e.telephone_number) AS provider_directory_telephone_number,
            COALESCE(loc.phone_number, e.phone_number) AS provider_directory_phone_number,
            loc.phone_extension AS provider_directory_phone_extension,
            COALESCE(loc.fax_number, e.fax_number) AS provider_directory_fax_number,
            COALESCE(loc.fax_number_digits, e.fax_number_digits) AS provider_directory_fax_number_digits,
            loc.fax_extension AS provider_directory_fax_extension,
            COALESCE(affiliation.network_refs::jsonb, '[]'::jsonb) AS provider_directory_network_refs,
            '[]'::jsonb AS provider_directory_insurance_plan_refs,
            COALESCE(network_context.provider_directory_network_names, ARRAY[]::varchar[])
                AS provider_directory_network_names,
            COALESCE(network_context.provider_directory_network_matches, '[]'::jsonb)
                AS provider_directory_network_matches,
            false AS provider_directory_plan_context_matched,
            COALESCE(network_context.provider_directory_network_context_present, false)
                AS provider_directory_network_context_present,
            '[]'::jsonb AS provider_directory_insurance_plan_matches,
            COALESCE(affiliation.specialty_codes::jsonb, '[]'::jsonb) AS provider_directory_specialty_codes,
            COALESCE(affiliation.code_codes::jsonb, '[]'::jsonb) AS provider_directory_role_codes,
            'organization_affiliation'::varchar AS provider_directory_match_type,
            (affiliation.active IS DISTINCT FROM false) AS provider_directory_active_role,
            (organization.active IS DISTINCT FROM false) AS provider_directory_active_provider,
            (loc.resource_id IS NULL OR loc.status IS NULL OR lower(loc.status) <> 'inactive') AS provider_directory_active_location,
            GREATEST(
                COALESCE(e.source_updated_at, TIMESTAMP 'epoch'),
                COALESCE(affiliation.observed_at, TIMESTAMP 'epoch'),
                COALESCE(organization.observed_at, TIMESTAMP 'epoch'),
                COALESCE(loc.observed_at, TIMESTAMP 'epoch')
            ) AS provider_directory_observed_at
          FROM address_candidates e
          JOIN {_qt(schema, "provider_directory_organization_affiliation")} affiliation
            ON e.resource_type = 'OrganizationAffiliation'
           AND affiliation.source_id = e.source_id
           AND affiliation.resource_id = e.resource_id
          JOIN LATERAL (
              SELECT DISTINCT normalized_ref AS resource_id
                FROM (
                    VALUES
                        (NULLIF(regexp_replace(COALESCE(affiliation.organization_ref, ''), '^.*/', ''), '')),
                        (NULLIF(regexp_replace(COALESCE(affiliation.participating_organization_ref, ''), '^.*/', ''), ''))
                ) AS refs(normalized_ref)
               WHERE normalized_ref IS NOT NULL
          ) AS organization_ref ON TRUE
          JOIN {_qt(schema, "provider_directory_organization")} organization
            ON organization.source_id = affiliation.source_id
           AND organization.resource_id = organization_ref.resource_id
           AND organization.npi = e.npi
          LEFT JOIN {_qt(schema, "provider_directory_location")} loc
            ON loc.source_id = e.source_id
           AND loc.resource_id = e.location_resource_id
          LEFT JOIN LATERAL (
            SELECT
                bool_or(network_ref.value IS NOT NULL) AS provider_directory_network_context_present,
                COALESCE(
                    array_agg(DISTINCT network_catalog.provider_directory_network_name)
                        FILTER (WHERE NULLIF(BTRIM(network_catalog.provider_directory_network_name), '') IS NOT NULL),
                    ARRAY[]::varchar[]
                ) AS provider_directory_network_names,
                COALESCE(
                    jsonb_agg(
                        DISTINCT jsonb_build_object(
                            'ref', network_ref.value,
                            'resource_id', network_catalog.network_resource_id,
                            'name', network_catalog.provider_directory_network_name,
                            'aliases', COALESCE(network_catalog.aliases::jsonb, '[]'::jsonb),
                            'provider_directory_network_key', network_catalog.provider_directory_network_key,
                            'provider_directory_source', 'provider_directory_fhir',
                            'provider_directory_source_id', affiliation.source_id,
                            'provider_directory_org_name', network_catalog.source_org_name,
                            'provider_directory_plan_name', network_catalog.source_plan_name,
                            'provider_directory_issuer_key', network_catalog.provider_directory_issuer_key,
                            'provider_directory_issuer_network_match_key',
                                network_catalog.provider_directory_issuer_network_match_key
                        )
                    ) FILTER (WHERE network_catalog.network_resource_id IS NOT NULL),
                    '[]'::jsonb
                ) AS provider_directory_network_matches
              FROM jsonb_array_elements_text(
                  COALESCE(affiliation.network_refs::jsonb, '[]'::jsonb)
              ) AS network_ref(value)
              LEFT JOIN {_qt(schema, PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)} network_catalog
                ON network_catalog.source_id = affiliation.source_id
               AND network_catalog.network_resource_id = {network_ref_resource_id_expr}
          ) network_context ON TRUE
          JOIN {_qt(schema, "provider_directory_source")} src
            ON src.source_id = affiliation.source_id
         WHERE e.npi IS NOT NULL
           AND e.address_key IS NOT NULL
    ),
    matches AS (
        SELECT * FROM practitioner_matches
        UNION ALL
        SELECT * FROM organization_affiliation_matches
    )
    SELECT
        source_key,
        snapshot_id,
        plan_id,
        ptg_plan_id,
        npi,
        location_key,
        address_key,
        zip5,
        state_code,
        city_norm,
        provider_directory_source_id,
        provider_directory_org_name,
        provider_directory_plan_name,
        provider_directory_provider_resource_id,
        provider_directory_provider_name,
        provider_directory_role_resource_id,
        provider_directory_location_resource_id,
        provider_directory_location_name,
        provider_directory_telephone_number,
        provider_directory_phone_number,
        provider_directory_phone_extension,
        provider_directory_fax_number,
        provider_directory_fax_number_digits,
        provider_directory_fax_extension,
        provider_directory_network_refs,
        provider_directory_insurance_plan_refs,
        provider_directory_specialty_codes,
        provider_directory_role_codes,
        provider_directory_match_type,
        provider_directory_active_role,
        provider_directory_active_provider,
        provider_directory_active_location,
        provider_directory_observed_at,
        (
            provider_directory_active_role
            AND provider_directory_active_provider
            AND provider_directory_active_location
        ) AS provider_directory_active_match,
        CASE
            WHEN provider_directory_active_role
             AND provider_directory_active_provider
             AND provider_directory_active_location
             AND provider_directory_plan_context_matched
                THEN 'payer_directory_corroborated_location'
            WHEN provider_directory_active_role
             AND provider_directory_active_provider
             AND provider_directory_active_location
                THEN 'provider_directory_address'
            ELSE 'payer_directory_corroborated_location_inactive_or_unknown'
        END::varchar AS address_network_binding,
        jsonb_build_object(
            'source', 'provider_directory_fhir',
            'matched_on',
                CASE
                    WHEN provider_directory_plan_context_matched
                        THEN 'npi_address_key_role_location_plan'
                    ELSE 'npi_address_key_role_location'
                END,
            'source_id', provider_directory_source_id,
            'org_name', provider_directory_org_name,
            'plan_name', provider_directory_plan_name,
            'provider_directory_source_id', provider_directory_source_id,
            'provider_directory_org_name', provider_directory_org_name,
            'provider_directory_plan_name', provider_directory_plan_name,
            'provider_resource_id', provider_directory_provider_resource_id,
            'role_resource_id', provider_directory_role_resource_id,
            'location_resource_id', provider_directory_location_resource_id,
            'match_type', provider_directory_match_type,
            'plan_context_matched', provider_directory_plan_context_matched,
            'network_context_present', provider_directory_network_context_present,
            'network_names', provider_directory_network_names,
            'network_matches', provider_directory_network_matches,
            'insurance_plan_matches', provider_directory_insurance_plan_matches
        ) AS address_verification_evidence,
        provider_directory_plan_context_matched,
        provider_directory_network_context_present,
        provider_directory_insurance_plan_matches,
        provider_directory_network_names,
        provider_directory_network_matches
      FROM matches;
    """


async def publish_provider_directory_address_corroboration_view(db_schema: str | None = None) -> None:
    """Publish provider directory address corroboration view for provider-directory serving."""
    await db.status(provider_directory_address_corroboration_sql(db_schema))


def provider_directory_address_corroboration_select_sql(db_schema: str | None = None) -> str:
    """Build SQL for provider directory address corroboration select."""
    sql = provider_directory_address_corroboration_sql(db_schema)
    marker = " AS\n"
    if marker not in sql:
        raise ValueError("Provider Directory PTG corroboration SQL does not contain view AS marker")
    return sql.split(marker, 1)[1].strip().rstrip(";")


def _drop_provider_directory_address_corroboration_relation_sql(schema: str, relation: str) -> str:
    relation_ref = _qt(schema, relation)
    return f"""
    DO $$
    DECLARE relkind_value "char";
    BEGIN
        SELECT cls.relkind
          INTO relkind_value
          FROM pg_class cls
          JOIN pg_namespace ns ON ns.oid = cls.relnamespace
         WHERE ns.nspname = {_sql_string_literal(schema)}
           AND cls.relname = {_sql_string_literal(relation)};

        IF relkind_value = 'v' THEN
            EXECUTE 'DROP VIEW {relation_ref}';
        ELSIF relkind_value = 'm' THEN
            EXECUTE 'DROP MATERIALIZED VIEW {relation_ref}';
        ELSIF relkind_value IN ('r', 'p') THEN
            EXECUTE 'DROP TABLE {relation_ref}';
        END IF;
    END $$;
    """


async def _create_provider_directory_address_corroboration_indexes(
    schema: str,
    table_name: str = PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW,
) -> None:
    table_ref = _qt(schema, table_name)
    index_name = partial(_address_corroboration_index_name, table_name)
    statements = (
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_lookup_idx"))}
            ON {table_ref} (npi, address_key);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_active_lookup_idx"))}
            ON {table_ref} (npi, address_key, provider_directory_observed_at DESC NULLS LAST)
            WHERE provider_directory_active_match IS TRUE;
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_source_snapshot_idx"))}
            ON {table_ref} (source_key, snapshot_id);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_plan_pair_idx"))}
            ON {table_ref} (snapshot_id, plan_id, ptg_plan_id);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_pd_source_idx"))}
            ON {table_ref} (provider_directory_source_id);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name("pd_price_addr_corrob_network_names_gin"))}
            ON {table_ref} USING gin (provider_directory_network_names);
        """,
    )
    for statement in statements:
        await db.status(statement)


def _address_corroboration_index_name(table_name: str, target_index_name: str) -> str:
    if table_name == PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW:
        return target_index_name
    return _bounded_identifier(f"{table_name}_{target_index_name}")


async def _rename_address_corroboration_stage_indexes(schema: str, stage_table: str) -> None:
    for target_index_name in PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_INDEXES:
        stage_index_name = _address_corroboration_index_name(stage_table, target_index_name)
        if stage_index_name == target_index_name:
            continue
        await db.status(
            f"ALTER INDEX IF EXISTS {_qt(schema, stage_index_name)} RENAME TO {_q(target_index_name)};"
        )


class ProviderDirectoryArtifactCutoverConflict(RuntimeError):
    """Raised when a Provider Directory artifact cutover cannot acquire its lock."""


class ProviderDirectoryArtifactBuildStale(RuntimeError):
    """Raised when the live artifact changed after a stage copied from it."""


@dataclass(frozen=True)
class ProviderDirectoryArtifactBuildFence:
    """Identity of the live relation from which an artifact stage was built."""

    target_oid: int | None


@dataclass(frozen=True)
class ProviderDirectoryPreparedArtifactStage:
    """One logged stage ready for an atomic serving-relation cutover."""

    schema: str
    stage_table: str
    target_relation: str
    rename_stage_indexes: Callable[[str, str], Awaitable[None]]
    build_fence: ProviderDirectoryArtifactBuildFence | None = None


@dataclass(frozen=True)
class ProviderDirectoryArtifactPromotionIdentity:
    """Relation identity needed to resolve an ambiguous cutover timeout."""

    stage: ProviderDirectoryPreparedArtifactStage
    stage_oid: int


@dataclass
class ProviderDirectoryArtifactBundle:
    """Collect serving stages and promote or clean them as one unit."""

    stages: list[ProviderDirectoryPreparedArtifactStage] = field(
        default_factory=list
    )

    def add(
        self,
        stage: ProviderDirectoryPreparedArtifactStage | None,
    ) -> None:
        """Register a prepared stage when its target is available."""
        if stage is not None:
            self.stages.append(stage)

    @property
    def relation_overrides(self) -> dict[str, str]:
        """Map serving relations to their prepared dependency stages."""
        return {
            stage.target_relation: stage.stage_table
            for stage in self.stages
        }

    async def promote(self) -> int:
        """Atomically promote every registered serving stage."""
        if self.stages:
            await _retry_provider_directory_artifact_bundle_promotion(
                tuple(self.stages)
            )
        return len(self.stages)

    async def cleanup(self) -> None:
        """Remove every stage name that was not consumed by promotion."""
        for stage in reversed(self.stages):
            await _remove_provider_directory_artifact_stage(stage)


@contextlib.contextmanager
def _provider_directory_artifact_relation_scope(
    relation_overrides: dict[str, str],
) -> Iterator[None]:
    """Temporarily route artifact dependencies to prepared stage relations."""
    merged_overrides_by_relation = dict(
        _PROVIDER_DIRECTORY_ARTIFACT_RELATION_OVERRIDES.get()
    )
    merged_overrides_by_relation.update(relation_overrides)
    relation_token = _PROVIDER_DIRECTORY_ARTIFACT_RELATION_OVERRIDES.set(
        merged_overrides_by_relation
    )
    try:
        yield
    finally:
        _PROVIDER_DIRECTORY_ARTIFACT_RELATION_OVERRIDES.reset(relation_token)


@contextlib.asynccontextmanager
async def _provider_directory_artifact_bundle_scope(
) -> AsyncIterator[ProviderDirectoryArtifactBundle]:
    """Clean every prepared stage after bundle promotion or failure."""
    bundle = ProviderDirectoryArtifactBundle()
    bundle_token = _PROVIDER_DIRECTORY_ARTIFACT_BUNDLE.set(bundle)
    try:
        yield bundle
    finally:
        try:
            await bundle.cleanup()
        finally:
            _PROVIDER_DIRECTORY_ARTIFACT_BUNDLE.reset(bundle_token)


async def _try_provider_directory_artifact_build_lock(engine: Any, build_lock_key: str) -> Any | None:
    """Acquire one session advisory lock attempt on a dedicated connection."""

    connection = await engine.connect()
    try:
        lock_result = await connection.execute(
            sa_text("SELECT pg_try_advisory_lock(hashtextextended(:build_lock_key, 0));"),
            {"build_lock_key": build_lock_key},
        )
        acquired = bool(lock_result.scalar())
        await connection.commit()
    except Exception:
        await connection.close()
        raise
    if acquired:
        return connection
    await connection.close()
    return None


async def _acquire_provider_directory_artifact_build_lock(engine: Any, build_lock_key: str) -> Any | None:
    """Retry bounded acquisition of the artifact build guard."""

    for attempt_index in range(PROVIDER_DIRECTORY_ARTIFACT_BUILD_LOCK_ATTEMPTS):
        connection = await _try_provider_directory_artifact_build_lock(engine, build_lock_key)
        if connection is not None:
            return connection
        if attempt_index + 1 < PROVIDER_DIRECTORY_ARTIFACT_BUILD_LOCK_ATTEMPTS:
            await asyncio.sleep(PROVIDER_DIRECTORY_ARTIFACT_BUILD_LOCK_BACKOFF_SECONDS * (attempt_index + 1))
    return None


async def _release_provider_directory_artifact_build_lock(connection: Any, build_lock_key: str) -> None:
    """Release and close the dedicated artifact build-lock connection."""

    try:
        unlock_result = await connection.execute(
            sa_text("SELECT pg_advisory_unlock(hashtextextended(:build_lock_key, 0));"),
            {"build_lock_key": build_lock_key},
        )
        unlocked = bool(unlock_result.scalar())
        await connection.commit()
        if not unlocked:
            LOGGER.error("Provider Directory artifact build lock was lost: %s", build_lock_key)
    except Exception:
        LOGGER.exception("Failed to release Provider Directory artifact build lock: %s", build_lock_key)
        with contextlib.suppress(Exception):
            await connection.invalidate()
    finally:
        await connection.close()


@contextlib.asynccontextmanager
async def _provider_directory_artifact_build_guard(
    schema: str,
    target_relation: str,
) -> AsyncIterator[ProviderDirectoryArtifactBuildFence]:
    """Serialize the complete staged read-modify-write cycle without a long transaction."""

    if db.engine is None:
        await db.connect()
    assert db.engine is not None
    build_lock_key = f"provider-directory-artifact-build:{schema}.{target_relation}"
    connection = await _acquire_provider_directory_artifact_build_lock(db.engine, build_lock_key)
    if connection is None:
        raise ProviderDirectoryArtifactCutoverConflict(target_relation)
    try:
        target_oid = await _provider_directory_relation_oid(schema, target_relation)
        yield ProviderDirectoryArtifactBuildFence(target_oid=target_oid)
    finally:
        await _release_provider_directory_artifact_build_lock(connection, build_lock_key)


async def _provider_directory_relation_oid(schema: str, relation: str) -> int | None:
    """Return the PostgreSQL relation identity used to fence stale builds."""

    relation_oid = await db.scalar(
        """
        SELECT cls.oid::bigint
          FROM pg_class cls
          JOIN pg_namespace ns ON ns.oid = cls.relnamespace
         WHERE ns.nspname = :schema_name
           AND cls.relname = :relation_name;
        """,
        schema_name=schema,
        relation_name=relation,
    )
    return int(relation_oid) if relation_oid is not None else None


async def _capture_provider_directory_artifact_promotion_identities(
    stages: tuple[ProviderDirectoryPreparedArtifactStage, ...],
) -> tuple[ProviderDirectoryArtifactPromotionIdentity, ...]:
    """Capture exact stage OIDs before entering the bounded cutover."""

    identities: list[ProviderDirectoryArtifactPromotionIdentity] = []
    for stage in stages:
        stage_oid = await _provider_directory_relation_oid(
            stage.schema,
            stage.stage_table,
        )
        if stage_oid is None:
            return ()
        identities.append(
            ProviderDirectoryArtifactPromotionIdentity(
                stage=stage,
                stage_oid=stage_oid,
            )
        )
    return tuple(identities)


async def _is_provider_directory_artifact_promotion_committed(
    identities: tuple[ProviderDirectoryArtifactPromotionIdentity, ...],
    dataset_fence: ProviderDirectoryArtifactDatasetFence | None = None,
) -> bool:
    """Confirm exact relation identities and the matching dataset pointers."""

    if not identities:
        return False
    for identity in identities:
        stage = identity.stage
        target_oid = await _provider_directory_relation_oid(
            stage.schema,
            stage.target_relation,
        )
        stage_oid = await _provider_directory_relation_oid(
            stage.schema,
            stage.stage_table,
        )
        old_oid = await _provider_directory_relation_oid(
            stage.schema,
            f"{stage.target_relation}_old",
        )
        target_persistence = await _provider_directory_relation_attribute(
            stage.schema,
            stage.target_relation,
            "relpersistence",
        )
        if (
            target_oid != identity.stage_oid
            or stage_oid is not None
            or old_oid is not None
            or target_persistence != "p"
        ):
            return False
    if dataset_fence is None:
        return True
    return await _is_provider_directory_dataset_cutover_committed(
        dataset_fence
    )


async def _is_provider_directory_dataset_cutover_committed(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> bool:
    """Confirm that every selected pointer matches the committed cutover."""
    dataset_rows = await _artifact_fence_dataset_rows(
        fence,
        db,
        for_update=False,
    )
    dataset_rows_by_id = {
        dataset_id: dataset_row_map
        for dataset_row in dataset_rows
        if (
            dataset_row_map := _pagination_checkpoint_row_mapping(dataset_row)
        )
        and (dataset_id := _clean_text(dataset_row_map.get("dataset_id")))
    }
    for dataset in _unique_artifact_datasets(fence):
        selected_row = dataset_rows_by_id.get(dataset.dataset_id)
        if selected_row is None:
            return False
        expected_published_dataset = (
            replace(
                dataset,
                status=ENDPOINT_DATASET_PUBLISHED,
                is_current=True,
            )
            if dataset.promote_on_cutover
            else dataset
        )
        if not _is_artifact_fence_dataset_row_exact(
            expected_published_dataset,
            selected_row,
        ):
            return False
        current_dataset_ids = _current_published_artifact_dataset_ids(
            dataset_rows_by_id.values(),
            dataset.endpoint_id,
        )
        if current_dataset_ids != [dataset.dataset_id]:
            return False
        if not _is_artifact_incumbent_superseded(
            dataset,
            dataset_rows_by_id,
        ):
            return False
    return True


def _is_artifact_incumbent_superseded(
    dataset: ProviderDirectoryArtifactDataset,
    dataset_rows_by_id: dict[str, dict[str, Any]],
) -> bool:
    incumbent_dataset_id = dataset.expected_incumbent_dataset_id
    if not dataset.promote_on_cutover or not incumbent_dataset_id:
        return True
    incumbent_row = dataset_rows_by_id.get(incumbent_dataset_id)
    return bool(
        incumbent_row is not None
        and incumbent_row.get("is_current") is not True
        and _clean_text(incumbent_row.get("status"))
        == ENDPOINT_DATASET_SUPERSEDED
        and incumbent_row.get("superseded_at") is not None
    )


async def _provider_directory_relation_attribute(
    schema: str,
    relation: str,
    attribute: str,
) -> str | None:
    if attribute not in {"relkind", "relpersistence"}:
        raise ValueError(f"unsupported PostgreSQL relation attribute: {attribute}")
    value = await db.scalar(
        f"""
        SELECT cls.{attribute}::text
          FROM pg_class cls
          JOIN pg_namespace ns ON ns.oid = cls.relnamespace
         WHERE ns.nspname = :schema_name
           AND cls.relname = :relation_name;
        """,
        schema_name=schema,
        relation_name=relation,
    )
    return str(value) if value is not None else None


async def _assert_provider_directory_logged_relation(schema: str, relation: str) -> None:
    persistence = await _provider_directory_relation_attribute(schema, relation, "relpersistence")
    if persistence != "p":
        raise RuntimeError(
            f"Provider Directory artifact relation {schema}.{relation} is not LOGGED: {persistence!r}"
        )


def _is_provider_directory_artifact_cutover_retryable(exc: Exception) -> bool:
    if isinstance(exc, ProviderDirectoryArtifactCutoverConflict):
        return True
    error_values = (exc, getattr(exc, "orig", None), getattr(exc, "__cause__", None))
    return any(
        getattr(error, "pgcode", None) == "55P03" or getattr(error, "sqlstate", None) == "55P03"
        for error in error_values
        if error is not None
    )


async def _lock_provider_directory_artifact_tables(
    schema: str,
    relations: tuple[str, ...],
) -> None:
    for relation in relations:
        if await _provider_directory_relation_attribute(schema, relation, "relkind") in {"r", "p"}:
            await db.status(f"LOCK TABLE {_qt(schema, relation)} IN ACCESS EXCLUSIVE MODE NOWAIT;")


async def _prepare_provider_directory_artifact_stage(schema: str, stage_table: str) -> None:
    await db.status(f"ALTER TABLE {_qt(schema, stage_table)} SET LOGGED;")
    await _assert_provider_directory_logged_relation(schema, stage_table)


async def _acquire_provider_directory_artifact_cutover_lock(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> None:
    acquired = await db.scalar(
        "SELECT pg_try_advisory_xact_lock(hashtextextended(:target_lock_key, 0));",
        target_lock_key=(
            "provider-directory-artifact-cutover:"
            f"{stage.schema}.{stage.target_relation}"
        ),
    )
    if not acquired:
        raise ProviderDirectoryArtifactCutoverConflict(stage.target_relation)


async def _assert_provider_directory_artifact_build_fence(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> None:
    if stage.build_fence is None:
        return
    current_target_oid = await _provider_directory_relation_oid(
        stage.schema,
        stage.target_relation,
    )
    if current_target_oid != stage.build_fence.target_oid:
        raise ProviderDirectoryArtifactBuildStale(stage.target_relation)


def _provider_directory_prepared_stage_relations(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> tuple[str, str, str]:
    return (
        stage.stage_table,
        stage.target_relation,
        f"{stage.target_relation}_old",
    )


async def _install_provider_directory_prepared_stage(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> None:
    schema = stage.schema
    stage_ref = _qt(schema, stage.stage_table)
    target_ref = _qt(schema, stage.target_relation)
    old_relation = f"{stage.target_relation}_old"
    target_kind = await _provider_directory_relation_attribute(
        schema,
        stage.target_relation,
        "relkind",
    )
    await db.status(
        _drop_provider_directory_address_corroboration_relation_sql(
            schema,
            old_relation,
        )
    )
    if target_kind in {"r", "p"}:
        await db.status(
            f"ALTER TABLE {target_ref} RENAME TO {_q(old_relation)};"
        )
    elif target_kind in {"v", "m"}:
        await db.status(
            _drop_provider_directory_address_corroboration_relation_sql(
                schema,
                stage.target_relation,
            )
        )
    elif target_kind is not None:
        raise RuntimeError(
            "Unsupported Provider Directory artifact target relation kind: "
            f"{target_kind!r}"
        )
    await db.status(
        f"ALTER TABLE {stage_ref} RENAME TO {_q(stage.target_relation)};"
    )


async def _finish_provider_directory_prepared_stage(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> None:
    await db.status(
        _drop_provider_directory_address_corroboration_relation_sql(
            stage.schema,
            f"{stage.target_relation}_old",
        )
    )
    await stage.rename_stage_indexes(stage.schema, stage.stage_table)
    await _assert_provider_directory_logged_relation(
        stage.schema,
        stage.target_relation,
    )


async def _promote_provider_directory_artifact_datasets(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> None:
    """Flip validated candidates only after every serving relation is installed."""
    for dataset in fence.promotion_datasets:
        await _supersede_artifact_dataset_incumbent(dataset)
        await _publish_validated_artifact_dataset(dataset)


async def _supersede_artifact_dataset_incumbent(
    dataset: ProviderDirectoryArtifactDataset,
) -> None:
    incumbent_dataset_id = dataset.expected_incumbent_dataset_id
    if not incumbent_dataset_id:
        return
    superseded_count = await db.status(
        f"""
        UPDATE {_qt(_schema(), ProviderDirectoryEndpointDataset.__tablename__)}
           SET status = :superseded_status,
               is_current = false,
               superseded_at = now()
         WHERE dataset_id = :incumbent_dataset_id
           AND endpoint_id = :endpoint_id
           AND status = :published_status
           AND is_current = true
           AND superseded_at IS NULL;
        """,
        incumbent_dataset_id=incumbent_dataset_id,
        endpoint_id=dataset.endpoint_id,
        published_status=ENDPOINT_DATASET_PUBLISHED,
        superseded_status=ENDPOINT_DATASET_SUPERSEDED,
    )
    if _coerce_rowcount(superseded_count) != 1:
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_endpoint_dataset_current_changed"
        )


async def _publish_validated_artifact_dataset(
    dataset: ProviderDirectoryArtifactDataset,
) -> None:
    promoted_count = await db.status(
        f"""
            UPDATE {_qt(_schema(), ProviderDirectoryEndpointDataset.__tablename__)}
               SET status = :published_status,
                   is_current = true,
                   published_at = now(),
                   superseded_at = NULL
             WHERE dataset_id = :dataset_id
               AND endpoint_id = :endpoint_id
               AND COALESCE(acquisition_root_run_id, import_run_id)
                   IS NOT DISTINCT FROM :evidence_run_id
               AND previous_dataset_id IS NOT DISTINCT FROM :incumbent_dataset_id
               AND dataset_hash IS NOT DISTINCT FROM :dataset_hash
               AND status = :validated_status
               AND is_current = false
               AND validated_at IS NOT NULL
               AND superseded_at IS NULL;
        """,
        dataset_id=dataset.dataset_id,
        endpoint_id=dataset.endpoint_id,
        evidence_run_id=dataset.evidence_run_id,
        incumbent_dataset_id=dataset.expected_incumbent_dataset_id,
        dataset_hash=dataset.dataset_hash,
        validated_status=ENDPOINT_DATASET_VALIDATED,
        published_status=ENDPOINT_DATASET_PUBLISHED,
    )
    if _coerce_rowcount(promoted_count) != 1:
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_endpoint_dataset_candidate_changed"
        )


async def _promote_provider_directory_artifact_stage_transaction(
    schema: str,
    stage_table: str,
    target_relation: str,
    rename_stage_indexes: Callable[[str, str], Awaitable[None]],
    build_fence: ProviderDirectoryArtifactBuildFence | None,
) -> None:
    """Run only the bounded metadata swap inside one database transaction."""
    prepared_stage = ProviderDirectoryPreparedArtifactStage(
        schema=schema,
        stage_table=stage_table,
        target_relation=target_relation,
        rename_stage_indexes=rename_stage_indexes,
        build_fence=build_fence,
    )
    async with db.transaction():
        await db.status(f"SET LOCAL lock_timeout = '{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_LOCK_TIMEOUT}';")
        await db.status(f"SET LOCAL statement_timeout = '{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_STATEMENT_TIMEOUT}';")
        await _acquire_provider_directory_artifact_cutover_lock(prepared_stage)
        active_fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
        if active_fence is not None:
            await _lock_and_verify_artifact_dataset_fence(active_fence)
        await _assert_provider_directory_artifact_build_fence(prepared_stage)
        await _lock_provider_directory_artifact_tables(
            schema,
            _provider_directory_prepared_stage_relations(prepared_stage),
        )
        await _install_provider_directory_prepared_stage(prepared_stage)
        await _finish_provider_directory_prepared_stage(prepared_stage)
        if active_fence is not None:
            await _promote_provider_directory_artifact_datasets(active_fence)


def _ordered_provider_directory_artifact_bundle(
    stages: tuple[ProviderDirectoryPreparedArtifactStage, ...],
) -> tuple[ProviderDirectoryPreparedArtifactStage, ...]:
    """Validate and deterministically order one serving artifact bundle."""
    ordered_stages = tuple(
        sorted(stages, key=lambda stage: stage.target_relation)
    )
    schemas = {stage.schema for stage in ordered_stages}
    targets = [stage.target_relation for stage in ordered_stages]
    if len(schemas) > 1:
        raise ValueError("provider_directory_artifact_bundle_schema_mismatch")
    if len(targets) != len(set(targets)):
        raise ValueError("provider_directory_artifact_bundle_target_duplicate")
    return ordered_stages


async def _promote_provider_directory_artifact_bundle_transaction(
    stages: tuple[ProviderDirectoryPreparedArtifactStage, ...],
) -> None:
    """Swap every prepared serving relation in one bounded transaction."""
    ordered_stages = _ordered_provider_directory_artifact_bundle(stages)
    if not ordered_stages:
        return
    schema = ordered_stages[0].schema
    relation_names = tuple(
        sorted(
            {
                relation_name
                for stage in ordered_stages
                for relation_name in _provider_directory_prepared_stage_relations(
                    stage
                )
            }
        )
    )
    async with db.transaction():
        await db.status(
            "SET LOCAL lock_timeout = "
            f"'{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_LOCK_TIMEOUT}';"
        )
        await db.status(
            "SET LOCAL statement_timeout = "
            f"'{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_STATEMENT_TIMEOUT}';"
        )
        for stage in ordered_stages:
            await _acquire_provider_directory_artifact_cutover_lock(stage)
        active_fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
        if active_fence is not None:
            await _lock_and_verify_artifact_dataset_fence(active_fence)
        for stage in ordered_stages:
            await _assert_provider_directory_artifact_build_fence(stage)
        await _lock_provider_directory_artifact_tables(schema, relation_names)
        for stage in ordered_stages:
            await _install_provider_directory_prepared_stage(stage)
        for stage in ordered_stages:
            await _finish_provider_directory_prepared_stage(stage)
        if active_fence is not None:
            await _promote_provider_directory_artifact_datasets(active_fence)


async def _promote_provider_directory_artifact_bundle(
    stages: tuple[ProviderDirectoryPreparedArtifactStage, ...],
) -> None:
    """Apply a hard wall-clock limit to one atomic artifact bundle cutover."""

    promotion_identities = (
        await _capture_provider_directory_artifact_promotion_identities(stages)
    )
    dataset_fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
    try:
        async with asyncio.timeout(
            PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_TRANSACTION_TIMEOUT_SECONDS
        ):
            await _promote_provider_directory_artifact_bundle_transaction(stages)
    except TimeoutError:
        if await _is_provider_directory_artifact_promotion_committed(
            promotion_identities,
            dataset_fence,
        ):
            LOGGER.warning(
                "Provider Directory artifact cutover timed out after commit; "
                "verified promoted targets by relation identity: %s",
                ",".join(stage.target_relation for stage in stages),
            )
            return
        raise


async def _retry_provider_directory_artifact_bundle_promotion(
    stages: tuple[ProviderDirectoryPreparedArtifactStage, ...],
) -> None:
    """Retry transient lock conflicts without rebuilding immutable stages."""
    for attempt_index in range(PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_ATTEMPTS):
        try:
            await _promote_provider_directory_artifact_bundle(stages)
            return
        except Exception as exc:
            if not _is_provider_directory_artifact_cutover_retryable(exc):
                raise
            if attempt_index + 1 >= PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_ATTEMPTS:
                raise
            await asyncio.sleep(
                PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_BACKOFF_SECONDS
                * (attempt_index + 1)
            )


async def _remove_provider_directory_artifact_stage(
    stage: ProviderDirectoryPreparedArtifactStage,
) -> None:
    """Drop an unpromoted stage without masking the publication result."""
    stage_ref = _qt(stage.schema, stage.stage_table)
    try:
        await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
    except Exception:  # pragma: no cover - cleanup best effort
        LOGGER.warning(
            "Failed to clean Provider Directory artifact stage %s",
            stage_ref,
            exc_info=True,
        )


async def _promote_provider_directory_artifact_stage(
    schema: str,
    stage_table: str,
    target_relation: str,
    rename_stage_indexes: Callable[[str, str], Awaitable[None]],
    build_fence: ProviderDirectoryArtifactBuildFence | None = None,
) -> None:
    """Apply a hard wall-clock deadline to the live artifact cutover."""

    stage = ProviderDirectoryPreparedArtifactStage(
        schema=schema,
        stage_table=stage_table,
        target_relation=target_relation,
        rename_stage_indexes=rename_stage_indexes,
        build_fence=build_fence,
    )
    promotion_identities = (
        await _capture_provider_directory_artifact_promotion_identities((stage,))
    )
    dataset_fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
    try:
        async with asyncio.timeout(
            PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_TRANSACTION_TIMEOUT_SECONDS
        ):
            await _promote_provider_directory_artifact_stage_transaction(
                schema,
                stage_table,
                target_relation,
                rename_stage_indexes,
                build_fence,
            )
    except TimeoutError:
        if await _is_provider_directory_artifact_promotion_committed(
            promotion_identities,
            dataset_fence,
        ):
            LOGGER.warning(
                "Provider Directory artifact cutover timed out after commit; "
                "verified promoted target by relation identity: %s",
                target_relation,
            )
            return
        raise


async def _retry_provider_directory_artifact_promotion(
    schema: str,
    stage_table: str,
    target_relation: str,
    rename_stage_indexes: Callable[[str, str], Awaitable[None]],
    build_fence: ProviderDirectoryArtifactBuildFence | None,
) -> None:
    for attempt_index in range(PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_ATTEMPTS):
        try:
            await _promote_provider_directory_artifact_stage(
                schema,
                stage_table,
                target_relation,
                rename_stage_indexes,
                build_fence,
            )
            return
        except Exception as exc:
            if not _is_provider_directory_artifact_cutover_retryable(exc):
                raise
            if attempt_index + 1 >= PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_ATTEMPTS:
                raise
            await asyncio.sleep(PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_BACKOFF_SECONDS * (attempt_index + 1))


async def _cutover_provider_directory_artifact_stage(
    *,
    schema: str,
    stage_table: str,
    target_relation: str,
    rename_stage_indexes: Callable[[str, str], Awaitable[None]],
    build_fence: ProviderDirectoryArtifactBuildFence | None = None,
) -> None:
    """Promote a prepared stage without ever changing a live table's persistence."""

    stage_ref = _qt(schema, stage_table)
    try:
        await _prepare_provider_directory_artifact_stage(schema, stage_table)
        await _retry_provider_directory_artifact_promotion(
            schema,
            stage_table,
            target_relation,
            rename_stage_indexes,
            build_fence,
        )
        await _assert_provider_directory_logged_relation(schema, target_relation)
    except Exception:
        try:
            await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
        except Exception:  # pragma: no cover - cleanup best effort
            LOGGER.warning("Failed to clean Provider Directory artifact stage %s", stage_ref, exc_info=True)
        raise


async def _swap_address_corroboration_stage(
    schema: str,
    stage_table: str,
    stage_ref: str,
    target_relation: str,
    build_fence: ProviderDirectoryArtifactBuildFence | None = None,
) -> None:
    del stage_ref
    await _cutover_provider_directory_artifact_stage(
        schema=schema,
        stage_table=stage_table,
        target_relation=target_relation,
        rename_stage_indexes=_rename_address_corroboration_stage_indexes,
        build_fence=build_fence,
    )


async def _populate_address_corroboration_stage(
    schema: str,
    stage_ref: str,
    target_ref: str,
    select_sql: str,
    source_ids: list[str],
) -> int:
    """Create a stage while retaining corroboration outside a source scope."""
    target_kind = await _provider_directory_relation_attribute(
        schema,
        PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW,
        "relkind",
    )
    if source_ids and target_kind is not None:
        await db.status(
            f"""
            CREATE UNLOGGED TABLE {stage_ref} AS
            SELECT *
              FROM {target_ref}
             WHERE NOT (
                 provider_directory_source_id = ANY(
                     CAST(:source_ids AS varchar[])
                 )
             );
            """,
            source_ids=source_ids,
        )
        copied_existing = int(
            await db.scalar(f"SELECT COUNT(*) FROM {stage_ref};") or 0
        )
        await db.status(f"INSERT INTO {stage_ref}\n{select_sql};")
        return copied_existing
    await db.status(f"CREATE UNLOGGED TABLE {stage_ref} AS\n{select_sql};")
    return 0


def _address_corroboration_publication_metrics(
    target_ref: str,
    row_count: int,
    network_catalog_metrics: dict[str, Any],
    source_ids: list[str],
    copied_existing: int,
) -> dict[str, Any]:
    metrics_by_field = {
        "published": True,
        "relation": target_ref,
        "rows": row_count,
        "storage": "table",
        "network_catalog": network_catalog_metrics,
    }
    if source_ids:
        metrics_by_field["copied_existing"] = copied_existing
        metrics_by_field["source_ids"] = source_ids
    return metrics_by_field


async def _address_corroboration_network_metrics(
    schema: str,
    source_ids: list[str],
    *,
    refresh_network_catalog: bool,
    metrics_override: dict[str, Any] | None,
) -> dict[str, Any]:
    """Return network metrics without rebuilding a prepared bundle stage."""
    if metrics_override is not None:
        return metrics_override
    if refresh_network_catalog:
        return await publish_provider_directory_network_catalog(
            schema,
            **({"source_ids": source_ids} if source_ids else {}),
        )
    return await _ensure_provider_directory_network_catalog_populated(schema)


async def _prepared_address_corroboration_result(
    schema: str,
    stage_table: str,
    publish_metrics: dict[str, Any],
    build_fence: ProviderDirectoryArtifactBuildFence,
) -> tuple[dict[str, Any], ProviderDirectoryPreparedArtifactStage]:
    """Mark a corroboration stage logged and package it for bundle cutover."""
    await _prepare_provider_directory_artifact_stage(schema, stage_table)
    return (
        publish_metrics,
        ProviderDirectoryPreparedArtifactStage(
            schema=schema,
            stage_table=stage_table,
            target_relation=PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW,
            rename_stage_indexes=_rename_address_corroboration_stage_indexes,
            build_fence=build_fence,
        ),
    )


async def _best_effort_drop_address_corroboration_stage(stage_ref: str) -> None:
    """Clean a failed corroboration stage without masking its build error."""
    try:
        await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
    except Exception:  # pragma: no cover - cleanup best effort
        LOGGER.warning(
            "Failed to clean provider directory address stage table %s",
            stage_ref,
            exc_info=True,
        )


async def publish_provider_directory_address_corroboration_table(
    db_schema: str | None = None,
    *,
    refresh_network_catalog: bool = True,
    source_ids: list[str] | tuple[str, ...] | None = None,
    defer_cutover: bool = False,
    network_catalog_metrics_override: dict[str, Any] | None = None,
) -> Any:
    """Publish provider directory address corroboration table for provider-directory serving."""
    schema = db_schema or _schema()
    relation = PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW
    effective_source_ids = _clean_source_id_list(source_ids)
    network_catalog_metrics = await _address_corroboration_network_metrics(
        schema, effective_source_ids,
        refresh_network_catalog=refresh_network_catalog,
        metrics_override=network_catalog_metrics_override,
    )
    async with _provider_directory_artifact_build_guard(schema, relation) as build_fence:
        stage_table = _stage_table_name()
        stage_ref = _qt(schema, stage_table)
        target_ref = _qt(schema, relation)
        select_sql = provider_directory_address_corroboration_select_sql(schema)
        try:
            await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
            copied_existing = await _populate_address_corroboration_stage(
                schema,
                stage_ref,
                target_ref,
                select_sql,
                effective_source_ids,
            )
            row_count = int(await db.scalar(f"SELECT COUNT(*) FROM {stage_ref};") or 0)
            await _create_provider_directory_address_corroboration_indexes(schema, stage_table)
            await db.status(f"ANALYZE {stage_ref};")
            publish_result = _address_corroboration_publication_metrics(
                target_ref,
                row_count,
                network_catalog_metrics,
                effective_source_ids,
                copied_existing,
            )
            if defer_cutover:
                return await _prepared_address_corroboration_result(
                    schema,
                    stage_table,
                    publish_result,
                    build_fence,
                )
            await _swap_address_corroboration_stage(
                schema,
                stage_table,
                stage_ref,
                relation,
                build_fence,
            )
            await db.status(f"ANALYZE {_qt(schema, relation)};")
            return publish_result
        except Exception:
            await _best_effort_drop_address_corroboration_stage(stage_ref)
            raise


def _provider_directory_location_coordinate_sql_map(source_alias: str) -> dict[str, str]:
    location_country_expr = _country_restore_default_us_sql(f"{source_alias}.country_code")
    raw_lat = f"({source_alias}.latitude)::numeric"
    raw_long = f"({source_alias}.longitude)::numeric"
    numeric_re = r"^-?[0-9]+(\.[0-9]+)?$"
    numeric_guard = (
        f"{source_alias}.latitude ~ '{numeric_re}' "
        f"AND {source_alias}.longitude ~ '{numeric_re}'"
    )
    normalized_lat_expr = _coordinate_from_location_sql(
        f"{source_alias}.latitude",
        f"{source_alias}.longitude",
        location_country_expr,
        axis="lat",
    )
    normalized_long_expr = _coordinate_from_location_sql(
        f"{source_alias}.latitude",
        f"{source_alias}.longitude",
        location_country_expr,
        axis="long",
    )
    return {
        "location_country_expr": location_country_expr,
        "raw_lat": raw_lat,
        "raw_long": raw_long,
        "numeric_guard": numeric_guard,
        "normalized_lat_expr": normalized_lat_expr,
        "normalized_long_expr": normalized_long_expr,
    }


def _provider_directory_location_coordinate_scopes(
    source_alias: str,
    *,
    db_schema: str,
    run_id: str | None,
    source_ids: list[str] | tuple[str, ...] | None,
    seen_table: str | None,
) -> list[str]:
    scope_clause_list: list[str] = []
    if run_id is not None and not seen_table:
        scope_clause_list.append(f"{source_alias}.last_seen_run_id = CAST(:run_id AS varchar)")
    if source_ids:
        scope_clause_list.append(f"{source_alias}.source_id = ANY(CAST(:source_ids AS varchar[]))")
    if seen_table:
        seen_ref = _qt(db_schema, seen_table)
        seen_run_filter = "AND seen.run_id = CAST(:run_id AS varchar)" if run_id is not None else ""
        scope_clause_list.append(
            f"""EXISTS (
                SELECT 1
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = 'Location'
                   {seen_run_filter}
                   AND seen.source_id = {source_alias}.source_id
                   AND seen.resource_id = {source_alias}.resource_id
            )"""
        )
    scope_clause_list.append(
        f"""(
            CAST(:after_source_id AS varchar) IS NULL
            OR ({source_alias}.source_id, {source_alias}.resource_id)
                > (CAST(:after_source_id AS varchar), CAST(:after_resource_id AS varchar))
        )"""
    )
    return scope_clause_list


def _provider_directory_location_coordinate_where_sql(
    source_alias: str,
    coordinate_expr_map: dict[str, str],
    scope_clause_list: list[str],
) -> str:
    where_clause_list = [
        f"NULLIF(BTRIM(COALESCE({source_alias}.latitude, '')), '') IS NOT NULL",
        f"NULLIF(BTRIM(COALESCE({source_alias}.longitude, '')), '') IS NOT NULL",
        coordinate_expr_map["numeric_guard"],
        "NOT ("
        + _coordinate_pair_plausible_sql(
            coordinate_expr_map["raw_lat"],
            coordinate_expr_map["raw_long"],
            coordinate_expr_map["location_country_expr"],
        )
        + ")",
        f"({coordinate_expr_map['normalized_lat_expr']}) IS NOT NULL",
        f"({coordinate_expr_map['normalized_long_expr']}) IS NOT NULL",
        *scope_clause_list,
    ]
    return " AND ".join(f"({clause})" for clause in where_clause_list)


def _provider_directory_location_coordinate_batch_body(
    source_alias: str,
    location_ref: str,
    coordinate_expr_map: dict[str, str],
    where_sql: str,
) -> str:
    normalized_latitude_sql = _coordinate_text_sql(coordinate_expr_map["normalized_lat_expr"])
    normalized_longitude_sql = _coordinate_text_sql(coordinate_expr_map["normalized_long_expr"])
    return f"""
    WITH candidates AS MATERIALIZED (
        SELECT
            {source_alias}.source_id,
            {source_alias}.resource_id,
            {normalized_latitude_sql} AS normalized_latitude,
            {normalized_longitude_sql} AS normalized_longitude
          FROM {location_ref} AS {source_alias}
         WHERE {where_sql}
         ORDER BY {source_alias}.source_id,
                  {source_alias}.resource_id
         LIMIT CAST(:batch_size AS integer)
    ),
    updated AS (
        UPDATE {location_ref} AS loc
           SET latitude = candidates.normalized_latitude,
               longitude = candidates.normalized_longitude,
               updated_at = now()
          FROM candidates
         WHERE loc.source_id = candidates.source_id
           AND loc.resource_id = candidates.resource_id
           AND candidates.normalized_latitude IS NOT NULL
           AND candidates.normalized_longitude IS NOT NULL
           AND (
                loc.latitude IS DISTINCT FROM candidates.normalized_latitude
             OR loc.longitude IS DISTINCT FROM candidates.normalized_longitude
           )
         RETURNING loc.source_id,
                   loc.resource_id
    )
    SELECT
        (SELECT COUNT(*) FROM candidates)::bigint AS candidate_rows,
        (SELECT COUNT(*) FROM updated)::bigint AS updated_rows,
        (SELECT source_id FROM candidates ORDER BY source_id DESC, resource_id DESC LIMIT 1)::varchar
            AS last_source_id,
        (SELECT resource_id FROM candidates ORDER BY source_id DESC, resource_id DESC LIMIT 1)::varchar
            AS last_resource_id;
    """


def provider_directory_location_coordinate_batch_sql(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
) -> str:
    """Normalize stored FHIR Location coordinates in bounded keyset batches."""

    schema = db_schema or _schema()
    source_alias = "loc_src"
    location_ref = _qt(schema, "provider_directory_location")
    coordinate_expr_map = _provider_directory_location_coordinate_sql_map(source_alias)
    scope_clause_list = _provider_directory_location_coordinate_scopes(
        source_alias,
        db_schema=schema,
        run_id=run_id,
        source_ids=source_ids,
        seen_table=seen_table,
    )
    where_sql = _provider_directory_location_coordinate_where_sql(
        source_alias,
        coordinate_expr_map,
        scope_clause_list,
    )
    return _provider_directory_location_coordinate_batch_body(
        source_alias,
        location_ref,
        coordinate_expr_map,
        where_sql,
    )


async def backfill_provider_directory_location_coordinates(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
    batch_size: int | None = None,
) -> int:
    """Repair stored Provider Directory coordinates that can be normalized safely."""

    schema = db_schema or _schema()
    if not await _table_exists(schema, "provider_directory_location"):
        return 0
    query_param_dict: dict[str, Any] = {}
    if run_id is not None:
        query_param_dict["run_id"] = run_id
    if source_ids:
        query_param_dict["source_ids"] = list(source_ids)
    total_updated = 0
    after_source_id: str | None = None
    after_resource_id: str | None = None
    bounded_batch_size = max(int(batch_size or _location_coordinate_batch_size()), 1)
    coordinate_batch_sql = provider_directory_location_coordinate_batch_sql(
        schema,
        run_id=run_id,
        source_ids=source_ids,
        seen_table=seen_table,
    )
    while True:
        coordinate_batch_result = await db.first(
            coordinate_batch_sql,
            **query_param_dict,
            after_source_id=after_source_id,
            after_resource_id=after_resource_id,
            batch_size=bounded_batch_size,
        )
        batch_result_mapping = (
            coordinate_batch_result._mapping
            if hasattr(coordinate_batch_result, "_mapping")
            else dict(coordinate_batch_result or {})
        )
        candidate_rows = int(batch_result_mapping.get("candidate_rows") or 0)
        updated_rows = int(batch_result_mapping.get("updated_rows") or 0)
        total_updated += updated_rows
        next_source_id = _clean_text(batch_result_mapping.get("last_source_id"))
        next_resource_id = _clean_text(batch_result_mapping.get("last_resource_id"))
        if candidate_rows <= 0 or not next_source_id or not next_resource_id:
            break
        if next_source_id == after_source_id and next_resource_id == after_resource_id:
            break
        after_source_id = next_source_id
        after_resource_id = next_resource_id
    return total_updated


def provider_directory_location_address_key_sql(
    db_schema: str | None = None,
    *,
    restore_state_from_zip: bool = True,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
) -> str:
    """Stamp imported FHIR Location rows with the shared canonical address key."""

    schema = db_schema or _schema()
    qschema = _q(schema)
    location_ref = _qt(schema, "provider_directory_location")
    source_alias = "loc_src"
    raw_state_expr = f"COALESCE(NULLIF({source_alias}.state_name, ''), {source_alias}.state_code)"
    normalized_state_expr = _state_fips_restore_sql(raw_state_expr)
    normalized_country_expr = _country_restore_sql(f"{source_alias}.country_code")
    needs_country_normalization_expr = (
        f"(NULLIF({normalized_country_expr}, '') IS NOT NULL "
        f"AND {source_alias}.country_code IS DISTINCT FROM {normalized_country_expr})"
    )
    zip_state_select = "geo.state::varchar" if restore_state_from_zip else "NULL::varchar"
    zip_city_select = "geo.city::varchar" if restore_state_from_zip else "NULL::varchar"
    zip_state_join = (
        f"""
          LEFT JOIN {_qt(schema, "geo_zip_lookup")} AS geo
            ON geo.zip_code = normalized.source_zip5
        """
        if restore_state_from_zip
        else ""
    )
    needs_work_clauses = [
        f"{source_alias}.address_key IS NULL",
        f"{source_alias}.zip5 IS NULL",
        f"{source_alias}.city_name IS NULL",
        f"{source_alias}.state_code IS NULL",
        f"{source_alias}.city_norm IS NULL",
        f"{raw_state_expr} ~ '^[0-9]{{1,2}}$'",
        needs_country_normalization_expr,
    ]
    scope_clauses: list[str] = []
    from_sql = f"FROM {location_ref} AS {source_alias}"
    if run_id is not None and not seen_table:
        scope_clauses.append(f"{source_alias}.last_seen_run_id = CAST(:run_id AS varchar)")
    if source_ids:
        scope_clauses.append(f"{source_alias}.source_id = ANY(CAST(:source_ids AS varchar[]))")
    if seen_table:
        seen_ref = _qt(schema, seen_table)
        seen_run_filter = "AND seen.run_id = CAST(:run_id AS varchar)" if run_id is not None else ""
        from_sql = f"""
          FROM (
                SELECT DISTINCT seen.source_id,
                       seen.resource_id
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = 'Location'
                   {seen_run_filter}
               ) AS seen_scope
          JOIN {location_ref} AS {source_alias}
            ON {source_alias}.source_id = seen_scope.source_id
           AND {source_alias}.resource_id = seen_scope.resource_id
        """
    where_clauses = [f"({' OR '.join(needs_work_clauses)})", *scope_clauses]
    where_sql = " AND ".join(where_clauses)
    return f"""
    WITH normalized AS (
        SELECT
            {source_alias}.source_id,
            {source_alias}.resource_id,
            {source_alias}.first_line,
            {source_alias}.second_line,
            {source_alias}.city_name,
            {source_alias}.postal_code,
            {source_alias}.country_code,
            {qschema}.addr_zip5_norm_v1({source_alias}.postal_code)::varchar AS source_zip5,
            {normalized_country_expr} AS normalized_country,
            {raw_state_expr} AS raw_state,
            {normalized_state_expr} AS normalized_state
          {from_sql}
         WHERE {where_sql}
    ),
    resolved AS (
        SELECT
            normalized.*,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(normalized.normalized_state::varchar, '')), '') IS NULL
                    THEN {zip_state_select}
                ELSE NULL::varchar
            END AS zip_restored_state,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(normalized.city_name::varchar, '')), '') IS NULL
                    THEN {zip_city_select}
                ELSE NULL::varchar
            END AS zip_restored_city,
            COALESCE(NULLIF(BTRIM(normalized.normalized_state::varchar), ''), {zip_state_select}) AS resolved_state,
            COALESCE(NULLIF(BTRIM(normalized.city_name::varchar), ''), {zip_city_select}) AS resolved_city
          FROM normalized
          {zip_state_join}
    ),
    keyed AS (
        SELECT
            source_id,
            resource_id,
            {qschema}.addr_key_v1(
                first_line,
                second_line,
                resolved_city,
                resolved_state,
                postal_code,
                COALESCE(NULLIF(normalized_country, ''), 'US')
            ) AS computed_address_key,
            source_zip5 AS computed_zip5,
            {qschema}.addr_state_code_v1(resolved_state)::varchar AS computed_state_code,
            {qschema}.addr_city_norm_v1(resolved_city)::varchar AS computed_city_norm,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(city_name::varchar, '')), '') IS NULL
                 AND zip_restored_city IS NOT NULL
                    THEN zip_restored_city::varchar
                ELSE NULL::varchar
            END AS restored_city_name,
            CASE
                WHEN raw_state ~ '^[0-9]{{1,2}}$'
                    THEN {qschema}.addr_state_code_v1(resolved_state)::varchar
                WHEN NULLIF(BTRIM(COALESCE(raw_state::varchar, '')), '') IS NULL
                 AND zip_restored_state IS NOT NULL
                    THEN {qschema}.addr_state_code_v1(zip_restored_state)::varchar
                ELSE NULL::varchar
            END AS restored_state_name,
            normalized_country
          FROM resolved
    )
    UPDATE {location_ref} AS loc
       SET address_key = keyed.computed_address_key::text,
           zip5 = COALESCE(keyed.computed_zip5, loc.zip5),
           city_name = COALESCE(keyed.restored_city_name, loc.city_name),
           state_name = COALESCE(keyed.restored_state_name, loc.state_name),
           state_code = COALESCE(keyed.computed_state_code, loc.state_code),
           city_norm = COALESCE(keyed.computed_city_norm, loc.city_norm),
           country_code = COALESCE(keyed.normalized_country, loc.country_code),
           updated_at = now()
      FROM keyed
     WHERE loc.source_id = keyed.source_id
       AND loc.resource_id = keyed.resource_id
       AND keyed.computed_address_key IS NOT NULL
       AND (
            loc.address_key IS DISTINCT FROM keyed.computed_address_key::text
         OR loc.zip5 IS DISTINCT FROM COALESCE(keyed.computed_zip5, loc.zip5)
         OR loc.city_name IS DISTINCT FROM COALESCE(keyed.restored_city_name, loc.city_name)
         OR loc.state_name IS DISTINCT FROM COALESCE(keyed.restored_state_name, loc.state_name)
         OR loc.state_code IS DISTINCT FROM COALESCE(keyed.computed_state_code, loc.state_code)
         OR loc.city_norm IS DISTINCT FROM COALESCE(keyed.computed_city_norm, loc.city_norm)
         OR loc.country_code IS DISTINCT FROM COALESCE(keyed.normalized_country, loc.country_code)
       );
    """


def provider_directory_location_address_key_batch_sql(
    db_schema: str | None = None,
    *,
    restore_state_from_zip: bool = True,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
) -> str:
    """Stamp a bounded keyset batch of FHIR Location rows with address keys."""

    schema = db_schema or _schema()
    qschema = _q(schema)
    location_ref = _qt(schema, "provider_directory_location")
    source_alias = "loc_src"
    raw_state_expr = f"COALESCE(NULLIF({source_alias}.state_name, ''), {source_alias}.state_code)"
    normalized_state_expr = _state_fips_restore_sql(raw_state_expr)
    normalized_country_expr = _country_restore_sql(f"{source_alias}.country_code")
    needs_country_normalization_expr = (
        f"(NULLIF({normalized_country_expr}, '') IS NOT NULL "
        f"AND {source_alias}.country_code IS DISTINCT FROM {normalized_country_expr})"
    )
    zip_state_select = "geo.state::varchar" if restore_state_from_zip else "NULL::varchar"
    zip_city_select = "geo.city::varchar" if restore_state_from_zip else "NULL::varchar"
    zip_state_join = (
        f"""
          LEFT JOIN {_qt(schema, "geo_zip_lookup")} AS geo
            ON geo.zip_code = normalized.source_zip5
        """
        if restore_state_from_zip
        else ""
    )
    needs_work_clauses = [
        f"{source_alias}.address_key IS NULL",
        f"{source_alias}.zip5 IS NULL",
        f"{source_alias}.city_name IS NULL",
        f"{source_alias}.state_code IS NULL",
        f"{source_alias}.city_norm IS NULL",
        f"{raw_state_expr} ~ '^[0-9]{{1,2}}$'",
        needs_country_normalization_expr,
    ]
    scope_clauses: list[str] = []
    if run_id is not None and not seen_table:
        scope_clauses.append(f"{source_alias}.last_seen_run_id = CAST(:run_id AS varchar)")
    if source_ids:
        scope_clauses.append(f"{source_alias}.source_id = ANY(CAST(:source_ids AS varchar[]))")
    if seen_table:
        seen_ref = _qt(schema, seen_table)
        seen_run_filter = "AND seen.run_id = CAST(:run_id AS varchar)" if run_id is not None else ""
        scope_clauses.append(
            f"""EXISTS (
                SELECT 1
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = 'Location'
                   {seen_run_filter}
                   AND seen.source_id = {source_alias}.source_id
                   AND seen.resource_id = {source_alias}.resource_id
            )"""
        )
    scope_clauses.append(
        f"""(
            CAST(:after_source_id AS varchar) IS NULL
            OR ({source_alias}.source_id, {source_alias}.resource_id)
                > (CAST(:after_source_id AS varchar), CAST(:after_resource_id AS varchar))
        )"""
    )
    where_clauses = [f"({' OR '.join(needs_work_clauses)})", *scope_clauses]
    where_sql = " AND ".join(where_clauses)
    return f"""
    WITH candidates AS MATERIALIZED (
        SELECT
            {source_alias}.source_id,
            {source_alias}.resource_id,
            {source_alias}.first_line,
            {source_alias}.second_line,
            {source_alias}.city_name,
            {source_alias}.postal_code,
            {source_alias}.country_code,
            {qschema}.addr_zip5_norm_v1({source_alias}.postal_code)::varchar AS source_zip5,
            {normalized_country_expr} AS normalized_country,
            {raw_state_expr} AS raw_state,
            {normalized_state_expr} AS normalized_state
          FROM {location_ref} AS {source_alias}
         WHERE {where_sql}
         ORDER BY {source_alias}.source_id,
                  {source_alias}.resource_id
         LIMIT CAST(:batch_size AS integer)
    ),
    normalized AS (
        SELECT * FROM candidates
    ),
    resolved AS (
        SELECT
            normalized.*,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(normalized.normalized_state::varchar, '')), '') IS NULL
                    THEN {zip_state_select}
                ELSE NULL::varchar
            END AS zip_restored_state,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(normalized.city_name::varchar, '')), '') IS NULL
                    THEN {zip_city_select}
                ELSE NULL::varchar
            END AS zip_restored_city,
            COALESCE(NULLIF(BTRIM(normalized.normalized_state::varchar), ''), {zip_state_select}) AS resolved_state,
            COALESCE(NULLIF(BTRIM(normalized.city_name::varchar), ''), {zip_city_select}) AS resolved_city
          FROM normalized
          {zip_state_join}
    ),
    keyed AS (
        SELECT
            source_id,
            resource_id,
            {qschema}.addr_key_v1(
                first_line,
                second_line,
                resolved_city,
                resolved_state,
                postal_code,
                COALESCE(NULLIF(normalized_country, ''), 'US')
            ) AS computed_address_key,
            source_zip5 AS computed_zip5,
            {qschema}.addr_state_code_v1(resolved_state)::varchar AS computed_state_code,
            {qschema}.addr_city_norm_v1(resolved_city)::varchar AS computed_city_norm,
            CASE
                WHEN NULLIF(BTRIM(COALESCE(city_name::varchar, '')), '') IS NULL
                 AND zip_restored_city IS NOT NULL
                    THEN zip_restored_city::varchar
                ELSE NULL::varchar
            END AS restored_city_name,
            CASE
                WHEN raw_state ~ '^[0-9]{{1,2}}$'
                    THEN {qschema}.addr_state_code_v1(resolved_state)::varchar
                WHEN NULLIF(BTRIM(COALESCE(raw_state::varchar, '')), '') IS NULL
                 AND zip_restored_state IS NOT NULL
                    THEN {qschema}.addr_state_code_v1(zip_restored_state)::varchar
                ELSE NULL::varchar
            END AS restored_state_name,
            normalized_country
          FROM resolved
    ),
    updated AS (
        UPDATE {location_ref} AS loc
           SET address_key = keyed.computed_address_key::text,
               zip5 = COALESCE(keyed.computed_zip5, loc.zip5),
               city_name = COALESCE(keyed.restored_city_name, loc.city_name),
               state_name = COALESCE(keyed.restored_state_name, loc.state_name),
               state_code = COALESCE(keyed.computed_state_code, loc.state_code),
               city_norm = COALESCE(keyed.computed_city_norm, loc.city_norm),
               country_code = COALESCE(keyed.normalized_country, loc.country_code),
               updated_at = now()
          FROM keyed
         WHERE loc.source_id = keyed.source_id
           AND loc.resource_id = keyed.resource_id
           AND keyed.computed_address_key IS NOT NULL
           AND (
                loc.address_key IS DISTINCT FROM keyed.computed_address_key::text
             OR loc.zip5 IS DISTINCT FROM COALESCE(keyed.computed_zip5, loc.zip5)
             OR loc.city_name IS DISTINCT FROM COALESCE(keyed.restored_city_name, loc.city_name)
             OR loc.state_name IS DISTINCT FROM COALESCE(keyed.restored_state_name, loc.state_name)
             OR loc.state_code IS DISTINCT FROM COALESCE(keyed.computed_state_code, loc.state_code)
             OR loc.city_norm IS DISTINCT FROM COALESCE(keyed.computed_city_norm, loc.city_norm)
             OR loc.country_code IS DISTINCT FROM COALESCE(keyed.normalized_country, loc.country_code)
           )
         RETURNING loc.source_id,
                   loc.resource_id
    )
    SELECT
        (SELECT COUNT(*) FROM candidates)::bigint AS candidate_rows,
        (SELECT COUNT(*) FROM updated)::bigint AS updated_rows,
        (SELECT source_id FROM candidates ORDER BY source_id DESC, resource_id DESC LIMIT 1)::varchar
            AS last_source_id,
        (SELECT resource_id FROM candidates ORDER BY source_id DESC, resource_id DESC LIMIT 1)::varchar
            AS last_resource_id;
    """


async def _address_canon_functions_available(db_schema: str) -> bool:
    value = await db.scalar(
        "SELECT to_regprocedure(:signature);",
        signature=f"{db_schema}.addr_key_v1(text,text,text,text,text,text)",
    )
    return isinstance(value, str) and bool(value)


async def _table_exists(db_schema: str, table_name: str) -> bool:
    return bool(
        await db.scalar(
            "SELECT to_regclass(:qualified_name) IS NOT NULL;",
            qualified_name=f"{db_schema}.{table_name}",
        )
    )


@dataclass(frozen=True)
class ProviderDirectoryArtifactDataset:
    source_id: str
    endpoint_id: str
    dataset_id: str
    evidence_run_id: str
    selected_resources: tuple[str, ...] = ()
    expected_resources: tuple[str, ...] = ()
    recorded_expected_resources: tuple[str, ...] | None = None
    status: str = ENDPOINT_DATASET_PUBLISHED
    is_current: bool = True
    previous_dataset_id: str | None = None
    expected_incumbent_dataset_id: str | None = None
    promote_on_cutover: bool = False
    dataset_hash: str | None = None
    resource_count: int | None = None
    validated_at: str | None = None
    publication_metadata_hash: str | None = None


@dataclass(frozen=True)
class ProviderDirectoryArtifactDatasetFence:
    datasets: tuple[ProviderDirectoryArtifactDataset, ...]
    should_select_validated_candidates: bool = False

    @property
    def dataset_id_by_endpoint_id(self) -> dict[str, str]:
        """Return the immutable dataset selected for each endpoint."""
        return {
            dataset.endpoint_id: dataset.dataset_id
            for dataset in self.datasets
        }

    @property
    def incumbent_dataset_ids(
        self,
    ) -> dict[str, str | None]:
        """Return the current pointer expected before each cutover."""
        return {
            dataset.endpoint_id: (
                dataset.expected_incumbent_dataset_id
                if dataset.promote_on_cutover
                else dataset.dataset_id
            )
            for dataset in self.datasets
        }

    @property
    def promotion_datasets(self) -> list[ProviderDirectoryArtifactDataset]:
        """Return one promotion candidate per endpoint in lock order."""
        candidates_by_endpoint_id = {
            dataset.endpoint_id: dataset
            for dataset in self.datasets
            if dataset.promote_on_cutover
        }
        return [
            candidates_by_endpoint_id[endpoint_id]
            for endpoint_id in sorted(candidates_by_endpoint_id)
        ]

    @property
    def source_endpoint_dataset_tuples(self) -> tuple[tuple[str, str, str], ...]:
        """Return the source alias mapping that must still hold at cutover."""
        return tuple(
            sorted(
                (
                    dataset.source_id,
                    dataset.endpoint_id,
                    dataset.dataset_id,
                )
                for dataset in self.datasets
            )
        )

    @property
    def source_endpoint_tuples(self) -> tuple[tuple[str, str], ...]:
        """Return the complete alias mapping selected for publication."""
        return tuple(
            sorted(
                (dataset.source_id, dataset.endpoint_id)
                for dataset in self.datasets
            )
        )

    @property
    def endpoint_ids(self) -> list[str]:
        """Return the endpoint rows that serialize artifact cutover."""
        return sorted({dataset.endpoint_id for dataset in self.datasets})

    @property
    def source_ids(self) -> list[str]:
        """Return the source alias rows protected by this fence."""
        return sorted({dataset.source_id for dataset in self.datasets})


def _provider_directory_artifact_dataset_selection_sql(
    source_ids: list[str] | tuple[str, ...] | None,
    *,
    should_select_validated_candidates: bool = False,
) -> str:
    """Select one immutable dataset per endpoint with explicit fallback rules."""
    source_ref = _qt(_schema(), ProviderDirectorySource.__tablename__)
    dataset_ref = _qt(_schema(), ProviderDirectoryEndpointDataset.__tablename__)
    selection_sql = (
        _artifact_dataset_explicit_selection_sql(source_ref)
        if source_ids
        else _artifact_dataset_all_source_selection_sql(source_ref)
    )
    options_sql = _artifact_dataset_options_cte(dataset_ref)
    ranking_sql = _artifact_dataset_ranking_cte()
    projection_sql = _artifact_dataset_projection_sql()
    return f"""
        WITH {options_sql}, {ranking_sql}, {selection_sql}
        {projection_sql}
    """


def _artifact_dataset_options_cte(dataset_ref: str) -> str:
    return f"""
        dataset_options AS MATERIALIZED (
        SELECT dataset.*,
               count(*) FILTER (
                   WHERE dataset.is_current = true
                     AND dataset.status = :published_status
                     AND dataset.superseded_at IS NULL
               ) OVER (PARTITION BY dataset.endpoint_id)
                   AS current_dataset_count,
               max(dataset.dataset_id) FILTER (
                   WHERE dataset.is_current = true
                     AND dataset.status = :published_status
                     AND dataset.superseded_at IS NULL
               ) OVER (PARTITION BY dataset.endpoint_id)
                   AS current_dataset_id,
               count(*) FILTER (
                   WHERE dataset.is_current = false
                     AND dataset.status = :validated_status
                     AND dataset.superseded_at IS NULL
               ) OVER (PARTITION BY dataset.endpoint_id)
                   AS validated_candidate_count
          FROM {dataset_ref} AS dataset
         WHERE (
                dataset.is_current = true
            AND dataset.status = :published_status
            AND dataset.superseded_at IS NULL
         ) OR (
                dataset.is_current = false
            AND dataset.status = :validated_status
            AND dataset.superseded_at IS NULL
         )
        )
    """


def _artifact_dataset_ranking_cte() -> str:
    return """
        ranked_datasets AS MATERIALIZED (
        SELECT dataset_options.*,
               row_number() OVER (
                   PARTITION BY dataset_options.endpoint_id
                   ORDER BY
                       CASE
                           WHEN CAST(:select_validated_candidates AS boolean)
                            AND dataset_options.is_current = false
                            AND dataset_options.status = :validated_status
                           THEN 0
                           ELSE 1
                       END,
                       dataset_options.dataset_id
               ) AS selection_rank
          FROM dataset_options
         WHERE (
                dataset_options.is_current = true
            AND dataset_options.status = :published_status
            AND dataset_options.superseded_at IS NULL
         ) OR (
                CAST(:select_validated_candidates AS boolean)
            AND dataset_options.is_current = false
            AND dataset_options.status = :validated_status
            AND dataset_options.superseded_at IS NULL
         )
        )
    """


def _artifact_dataset_projection_sql() -> str:
    return """
        SELECT selected.source_id,
               selected.endpoint_id,
               selected.source_record_json,
               dataset.dataset_id,
               COALESCE(
                   dataset.acquisition_root_run_id,
                   dataset.import_run_id
               ) AS evidence_run_id,
               COALESCE(
                   dataset.publication_metadata_json::jsonb -> 'selected_resources',
                   '[]'::jsonb
               ) AS selected_resources,
               dataset.publication_metadata_json::jsonb -> 'expected_resources'
                   AS recorded_expected_resources,
               dataset.status,
               dataset.is_current,
               dataset.previous_dataset_id,
               dataset.dataset_hash,
               dataset.resource_count,
               dataset.validated_at,
               dataset.publication_metadata_json,
               dataset.current_dataset_count,
               dataset.current_dataset_id,
               dataset.validated_candidate_count,
               (
                   CAST(:select_validated_candidates AS boolean)
                   AND dataset.is_current = false
                   AND dataset.status = :validated_status
               ) AS promote_on_cutover
          FROM selected_sources AS selected
          LEFT JOIN ranked_datasets AS dataset
            ON dataset.endpoint_id = selected.endpoint_id
           AND dataset.selection_rank = 1
         ORDER BY selected.source_id, dataset.dataset_id;
    """


def _artifact_dataset_explicit_selection_sql(source_ref: str) -> str:
    return f"""
        requested_sources AS MATERIALIZED (
            SELECT source_id, endpoint_id, to_jsonb(source) AS source_record_json
              FROM {source_ref} AS source
             WHERE source_id = ANY(CAST(:source_ids AS varchar[]))
        ), selected_sources AS MATERIALIZED (
            SELECT source_id, endpoint_id, source_record_json
              FROM requested_sources
            UNION
            SELECT sibling.source_id,
                   sibling.endpoint_id,
                   to_jsonb(sibling) AS source_record_json
              FROM {source_ref} AS sibling
              JOIN requested_sources AS requested
                ON requested.endpoint_id IS NOT NULL
               AND sibling.endpoint_id = requested.endpoint_id
        )
    """


def _artifact_dataset_all_source_selection_sql(
    source_ref: str,
) -> str:
    return f"""
        selected_endpoints AS MATERIALIZED (
            SELECT dataset.endpoint_id
              FROM ranked_datasets AS dataset
             WHERE dataset.selection_rank = 1
        ), selected_sources AS MATERIALIZED (
            SELECT source.source_id,
                   source.endpoint_id,
                   to_jsonb(source) AS source_record_json
              FROM {source_ref} AS source
              JOIN selected_endpoints AS endpoint
                ON endpoint.endpoint_id = source.endpoint_id
        )
    """


def _artifact_dataset_resource_profile(
    raw_profile: Any,
    *,
    dataset_id: str,
    field_name: str,
) -> tuple[str, ...]:
    decoded_profile = raw_profile
    if isinstance(decoded_profile, str):
        try:
            decoded_profile = json.loads(decoded_profile)
        except json.JSONDecodeError as exc:
            raise RuntimeError(
                f"provider_directory_artifact_dataset_profile_invalid:{dataset_id}:{field_name}"
            ) from exc
    if not isinstance(decoded_profile, list):
        raise RuntimeError(
            f"provider_directory_artifact_dataset_profile_invalid:{dataset_id}:{field_name}"
        )
    resource_types = [_clean_text(entry) for entry in decoded_profile]
    if (
        any(resource_type not in DEFAULT_RESOURCES for resource_type in resource_types)
        or len(set(resource_types)) != len(resource_types)
    ):
        raise RuntimeError(
            f"provider_directory_artifact_dataset_profile_invalid:{dataset_id}:{field_name}"
        )
    return tuple(sorted(resource_types))


def _provider_directory_artifact_dataset_from_row(
    dataset_row: Any,
) -> ProviderDirectoryArtifactDataset | None:
    """Build one immutable artifact selection from a query result."""
    dataset_row_map = _pagination_checkpoint_row_mapping(dataset_row)
    value_by_name = {
        key: _clean_text(dataset_row_map.get(key))
        for key in ("source_id", "endpoint_id", "dataset_id", "evidence_run_id")
    }
    if not all(value_by_name.values()):
        return None
    dataset_id = value_by_name["dataset_id"] or ""
    selected_resources, expected_resources, recorded_expected_resources = (
        _artifact_dataset_profiles_from_row(dataset_row_map, dataset_id)
    )
    selection_state = _artifact_dataset_state_from_row(
        dataset_row_map,
        dataset_id,
        value_by_name["endpoint_id"] or "",
    )
    return ProviderDirectoryArtifactDataset(
        source_id=value_by_name["source_id"] or "",
        endpoint_id=value_by_name["endpoint_id"] or "",
        dataset_id=dataset_id,
        evidence_run_id=value_by_name["evidence_run_id"] or "",
        selected_resources=selected_resources,
        expected_resources=expected_resources,
        recorded_expected_resources=recorded_expected_resources,
        **selection_state,
    )


def _artifact_dataset_profiles_from_row(
    dataset_row_map: dict[str, Any],
    dataset_id: str,
) -> tuple[tuple[str, ...], tuple[str, ...], tuple[str, ...] | None]:
    selected_resources = _artifact_dataset_resource_profile(
        dataset_row_map.get("selected_resources"),
        dataset_id=dataset_id,
        field_name="selected_resources",
    )
    raw_recorded_expected_resources = dataset_row_map.get(
        "recorded_expected_resources"
    )
    if raw_recorded_expected_resources is None:
        source_record = _json_object(dataset_row_map.get("source_record_json"))
        expected_resources = _endpoint_dataset_expected_resources([source_record])
        recorded_expected_resources = None
    else:
        recorded_expected_resources = _artifact_dataset_resource_profile(
            raw_recorded_expected_resources,
            dataset_id=dataset_id,
            field_name="expected_resources",
        )
        expected_resources = recorded_expected_resources
    return (
        selected_resources,
        expected_resources,
        recorded_expected_resources,
    )


def _artifact_dataset_state_from_row(
    dataset_row_map: dict[str, Any],
    dataset_id: str,
    endpoint_id: str,
) -> dict[str, Any]:
    selection_state = _artifact_dataset_selection_from_row(
        dataset_row_map,
        dataset_id,
        endpoint_id,
    )
    should_promote_on_cutover = selection_state[
        "should_promote_on_cutover"
    ]
    publication_metadata = _json_object(
        dataset_row_map.get("publication_metadata_json")
    )
    dataset_hash = _clean_text(dataset_row_map.get("dataset_hash"))
    validated_at_value = dataset_row_map.get("validated_at")
    validated_at = (
        str(validated_at_value) if validated_at_value is not None else None
    )
    if should_promote_on_cutover and (
        not dataset_hash
        or validated_at is None
        or not publication_metadata
    ):
        raise RuntimeError(
            "provider_directory_artifact_validated_candidate_proof_invalid:"
            + dataset_id
        )
    return {
        "status": selection_state["status"],
        "is_current": selection_state["is_current"],
        "previous_dataset_id": selection_state["previous_dataset_id"],
        "expected_incumbent_dataset_id": (
            selection_state["current_dataset_id"]
            if should_promote_on_cutover
            else None
        ),
        "promote_on_cutover": should_promote_on_cutover,
        "dataset_hash": dataset_hash,
        "resource_count": (
            int(dataset_row_map.get("resource_count"))
            if dataset_row_map.get("resource_count") is not None
            else None
        ),
        "validated_at": validated_at,
        "publication_metadata_hash": _identity_hash(publication_metadata),
    }


def _artifact_dataset_selection_from_row(
    dataset_row_map: dict[str, Any],
    dataset_id: str,
    endpoint_id: str,
) -> dict[str, Any]:
    status = (
        _clean_text(dataset_row_map.get("status"))
        or ENDPOINT_DATASET_PUBLISHED
    )
    is_current = dataset_row_map.get("is_current")
    if not isinstance(is_current, bool):
        is_current = status == ENDPOINT_DATASET_PUBLISHED
    should_promote_on_cutover = bool(
        dataset_row_map.get("promote_on_cutover")
    )
    current_dataset_count = int(
        dataset_row_map.get("current_dataset_count")
        if dataset_row_map.get("current_dataset_count") is not None
        else (1 if is_current else 0)
    )
    current_dataset_id = _clean_text(
        dataset_row_map.get("current_dataset_id")
    )
    if current_dataset_id is None and is_current:
        current_dataset_id = dataset_id
    validated_candidate_count = int(
        dataset_row_map.get("validated_candidate_count")
        if dataset_row_map.get("validated_candidate_count") is not None
        else (1 if should_promote_on_cutover else 0)
    )
    previous_dataset_id = _clean_text(
        dataset_row_map.get("previous_dataset_id")
    )
    selection_state_map = {
        "status": status,
        "is_current": is_current,
        "should_promote_on_cutover": should_promote_on_cutover,
        "current_dataset_count": current_dataset_count,
        "current_dataset_id": current_dataset_id,
        "validated_candidate_count": validated_candidate_count,
        "previous_dataset_id": previous_dataset_id,
    }
    _assert_artifact_dataset_selection_state(
        selection_state_map,
        dataset_id,
        endpoint_id,
    )
    return selection_state_map


def _assert_artifact_dataset_selection_state(
    selection_state: dict[str, Any],
    dataset_id: str,
    endpoint_id: str,
) -> None:
    if selection_state["should_promote_on_cutover"]:
        if selection_state["validated_candidate_count"] != 1:
            raise RuntimeError(
                "provider_directory_artifact_validated_candidate_ambiguous:"
                + endpoint_id
            )
        if (
            selection_state["status"] != ENDPOINT_DATASET_VALIDATED
            or selection_state["is_current"]
        ):
            raise RuntimeError(
                "provider_directory_artifact_validated_candidate_invalid:"
                + dataset_id
            )
        if (
            selection_state["current_dataset_count"] > 1
            or selection_state["previous_dataset_id"]
            != selection_state["current_dataset_id"]
        ):
            raise RuntimeError(
                "provider_directory_artifact_expected_incumbent_mismatch:"
                + dataset_id
            )
        return
    if (
        selection_state["status"] != ENDPOINT_DATASET_PUBLISHED
        or not selection_state["is_current"]
        or selection_state["current_dataset_count"] != 1
        or selection_state["current_dataset_id"] != dataset_id
    ):
        raise RuntimeError(
            "provider_directory_artifact_current_dataset_invalid:" + dataset_id
        )


def _validate_provider_directory_artifact_datasets(
    dataset_rows: list[Any],
    requested_source_ids: list[str],
    *,
    should_select_validated_candidates: bool = False,
) -> ProviderDirectoryArtifactDatasetFence:
    """Turn a current-dataset query result into one exact alias fence."""
    rows_by_source_id = _artifact_dataset_rows_by_source(dataset_rows)
    selected_source_ids = _artifact_dataset_source_ids(
        rows_by_source_id,
        requested_source_ids,
    )
    selected_datasets = [
        _artifact_dataset_for_source(source_id, rows_by_source_id[source_id])
        for source_id in selected_source_ids
    ]
    _assert_artifact_endpoint_consistency(selected_datasets)
    return ProviderDirectoryArtifactDatasetFence(
        tuple(selected_datasets),
        should_select_validated_candidates=(
            should_select_validated_candidates
        ),
    )


def _artifact_dataset_rows_by_source(
    dataset_rows: list[Any],
) -> dict[str, list[Any]]:
    rows_by_source_id: dict[str, list[Any]] = {}
    for dataset_row in dataset_rows:
        source_id = _clean_text(
            _pagination_checkpoint_row_mapping(dataset_row).get("source_id")
        )
        if source_id:
            rows_by_source_id.setdefault(source_id, []).append(dataset_row)
    return rows_by_source_id


def _artifact_dataset_source_ids(
    rows_by_source_id: dict[str, list[Any]],
    requested_source_ids: list[str],
) -> list[str]:
    missing_requested_aliases = [
        source_id
        for source_id in requested_source_ids
        if source_id not in rows_by_source_id
    ]
    if missing_requested_aliases:
        raise RuntimeError(
            "provider_directory_artifact_source_alias_missing:"
            + ",".join(missing_requested_aliases)
        )
    selected_source_ids = list(requested_source_ids)
    selected_source_ids.extend(
        source_id
        for source_id in sorted(rows_by_source_id)
        if source_id not in requested_source_ids
    )
    if not selected_source_ids:
        raise RuntimeError("provider_directory_artifact_source_aliases_empty")
    return selected_source_ids


def _artifact_dataset_for_source(
    source_id: str,
    dataset_rows: list[Any],
) -> ProviderDirectoryArtifactDataset:
    candidates = [
        dataset
        for dataset_row in dataset_rows
        if (dataset := _provider_directory_artifact_dataset_from_row(dataset_row))
        is not None
    ]
    if not candidates:
        raise RuntimeError(
            f"provider_directory_artifact_current_dataset_missing:{source_id}"
        )
    if len({candidate.dataset_id for candidate in candidates}) != 1 or len(candidates) != 1:
        raise RuntimeError(
            f"provider_directory_artifact_current_dataset_ambiguous:{source_id}"
        )
    return candidates[0]


def _assert_artifact_endpoint_consistency(
    selected_datasets: list[ProviderDirectoryArtifactDataset],
) -> None:
    """Require every alias of an endpoint to carry one exact selection."""
    identity_by_endpoint_id: dict[str, tuple[Any, ...]] = {}
    for dataset in selected_datasets:
        selection_identity = _artifact_endpoint_selection_identity(dataset)
        incumbent_identity = identity_by_endpoint_id.setdefault(
            dataset.endpoint_id,
            selection_identity,
        )
        if incumbent_identity == selection_identity:
            continue
        if incumbent_identity[0] != dataset.dataset_id:
            raise RuntimeError(
                "provider_directory_artifact_endpoint_dataset_ambiguous:"
                + dataset.endpoint_id
            )
        raise RuntimeError(
            "provider_directory_artifact_endpoint_metadata_ambiguous:"
            + dataset.endpoint_id
        )


def _artifact_endpoint_selection_identity(
    dataset: ProviderDirectoryArtifactDataset,
) -> tuple[Any, ...]:
    return (
        dataset.dataset_id,
        dataset.selected_resources,
        dataset.expected_resources,
        dataset.recorded_expected_resources,
        dataset.status,
        dataset.is_current,
        dataset.previous_dataset_id,
        dataset.expected_incumbent_dataset_id,
        dataset.promote_on_cutover,
        dataset.dataset_hash,
        dataset.resource_count,
        dataset.validated_at,
        dataset.publication_metadata_hash,
    )


async def _resolve_provider_directory_artifact_datasets(
    source_ids: list[str] | tuple[str, ...] | None,
    *,
    should_select_validated_candidates: bool = False,
) -> ProviderDirectoryArtifactDatasetFence:
    cleaned_source_ids = _clean_source_id_list(source_ids)
    dataset_rows = await db.all(
        _provider_directory_artifact_dataset_selection_sql(
            cleaned_source_ids,
            should_select_validated_candidates=(
                should_select_validated_candidates
            ),
        ),
        published_status=ENDPOINT_DATASET_PUBLISHED,
        validated_status=ENDPOINT_DATASET_VALIDATED,
        select_validated_candidates=should_select_validated_candidates,
        **({"source_ids": cleaned_source_ids} if cleaned_source_ids else {}),
    )
    return _validate_provider_directory_artifact_datasets(
        dataset_rows,
        cleaned_source_ids,
        should_select_validated_candidates=should_select_validated_candidates,
    )


def _should_select_validated_artifacts(
    publish_artifacts_targets: set[str] | None,
) -> bool:
    """Return whether an artifact run may atomically publish validated data."""
    if publish_artifacts_targets is None:
        return True
    base_targets = set(PROVIDER_DIRECTORY_PUBLISH_ARTIFACT_TARGETS) - {
        "corroboration"
    }
    return base_targets.issubset(publish_artifacts_targets)


def _provider_directory_dataset_artifact_targets(
    publish_artifacts_targets: set[str] | None,
    *,
    publish_corroboration: bool,
) -> tuple[str, ...]:
    targets = [
        target
        for target in PROVIDER_DIRECTORY_PUBLISH_ARTIFACT_TARGETS
        if is_provider_directory_publish_target_enabled(publish_artifacts_targets, target)
        and (target != "corroboration" or publish_corroboration)
    ]
    return tuple(targets)


def _assert_provider_directory_artifact_target_dependencies(
    fence: ProviderDirectoryArtifactDatasetFence,
    *,
    publish_artifacts_targets: set[str] | None,
    publish_corroboration: bool,
) -> None:
    """Reject a target before scoped rows could omit its required evidence."""
    enabled_targets = _provider_directory_dataset_artifact_targets(
        publish_artifacts_targets,
        publish_corroboration=publish_corroboration,
    )
    if "corroboration" in enabled_targets:
        missing_prerequisites = [
            prerequisite_target
            for prerequisite_target in ("address_overlay", "network_catalog")
            if prerequisite_target not in enabled_targets
        ]
        if missing_prerequisites:
            raise RuntimeError(
                "provider_directory_artifact_corroboration_prerequisites_missing:"
                + ",".join(missing_prerequisites)
            )
    violations = _artifact_dataset_profile_violations(fence)
    violations.extend(
        _artifact_target_dependency_violations(fence, enabled_targets)
    )
    if violations:
        raise RuntimeError(
            "provider_directory_artifact_target_dependencies_missing:"
            + ";".join(violations)
        )


def _artifact_dataset_profile_violations(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> list[str]:
    """Return current datasets that cover less than their source profile."""
    violations: list[str] = []
    for dataset in fence.datasets:
        if dataset.selected_resources != dataset.expected_resources:
            violations.append(
                ":".join(
                    (
                        "dataset_profile",
                        dataset.source_id,
                        dataset.endpoint_id,
                        dataset.dataset_id,
                        ",".join(dataset.selected_resources),
                        ",".join(dataset.expected_resources),
                    )
                )
            )
        if (
            dataset.recorded_expected_resources is not None
            and dataset.recorded_expected_resources != dataset.expected_resources
        ):
            violations.append(
                ":".join(
                    (
                        "dataset_recorded_profile",
                        dataset.source_id,
                        dataset.endpoint_id,
                        dataset.dataset_id,
                        ",".join(dataset.recorded_expected_resources),
                        ",".join(dataset.expected_resources),
                    )
                )
            )
    return violations


def _provider_directory_artifact_resource_types(
    publish_artifacts_targets: set[str] | None,
    *,
    publish_corroboration: bool,
) -> frozenset[str]:
    """Return the immutable resource types read by enabled artifact targets."""
    enabled_targets = _provider_directory_dataset_artifact_targets(
        publish_artifacts_targets,
        publish_corroboration=publish_corroboration,
    )
    return frozenset().union(
        *(
            PROVIDER_DIRECTORY_ARTIFACT_TARGET_RESOURCE_TYPES[target]
            for target in enabled_targets
        )
    )


def _artifact_target_dependency_violations(
    fence: ProviderDirectoryArtifactDatasetFence,
    enabled_targets: tuple[str, ...],
) -> list[str]:
    """Return source-specific artifact paths missing a complete alternative."""
    violations: list[str] = []
    sorted_datasets = sorted(
        fence.datasets,
        key=lambda dataset: (
            dataset.source_id,
            dataset.endpoint_id,
            dataset.dataset_id,
        ),
    )
    for artifact_target in enabled_targets:
        for dataset in sorted_datasets:
            violation = _artifact_target_dependency_violation(
                artifact_target,
                dataset,
            )
            if violation:
                violations.append(violation)
    return violations


def _artifact_target_dependency_violation(
    artifact_target: str,
    dataset: ProviderDirectoryArtifactDataset,
) -> str | None:
    """Return one missing artifact dependency or None when not applicable."""
    alternatives = PROVIDER_DIRECTORY_ARTIFACT_TARGET_RESOURCE_ALTERNATIVES[
        artifact_target
    ]
    selected_resources = set(dataset.selected_resources)
    if artifact_target == "corroboration" and "InsurancePlan" not in selected_resources:
        return None
    if not selected_resources.intersection(set().union(*alternatives)):
        return None
    if any(alternative.issubset(selected_resources) for alternative in alternatives):
        return None
    required_alternatives = "|".join(
        ",".join(sorted(alternative)) for alternative in alternatives
    )
    return ":".join(
        (
            artifact_target,
            dataset.source_id,
            dataset.endpoint_id,
            dataset.dataset_id,
            required_alternatives,
        )
    )


def _provider_directory_artifact_scope_row_limit() -> int:
    configured = _positive_int(
        os.getenv("HLTHPRT_PROVIDER_DIRECTORY_ARTIFACT_SCOPE_MAX_PROJECTED_ROWS")
    )
    return configured or DEFAULT_PROVIDER_DIRECTORY_ARTIFACT_SCOPE_MAX_PROJECTED_ROWS


def _artifact_scope_alias_counts(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> dict[str, int]:
    """Count source aliases represented by each immutable dataset."""
    alias_count_by_dataset_id: dict[str, int] = {}
    for dataset in fence.datasets:
        alias_count_by_dataset_id[dataset.dataset_id] = (
            alias_count_by_dataset_id.get(dataset.dataset_id, 0) + 1
        )
    return alias_count_by_dataset_id


def _artifact_scope_resource_pairs(
    fence: ProviderDirectoryArtifactDatasetFence,
    resource_types: frozenset[str],
) -> list[tuple[str, str]]:
    """Return validated dataset and resource pairs needed by this publish."""
    return sorted(
        {
            (dataset.dataset_id, resource_type)
            for dataset in fence.datasets
            for resource_type in dataset.selected_resources
            if resource_type in resource_types
        }
    )


async def _artifact_scope_resource_rows(
    dataset_resource_pairs: list[tuple[str, str]],
) -> list[Any]:
    """Count immutable rows for the exact validated dataset profile."""
    if not dataset_resource_pairs:
        return []
    return await db.all(
        f"""
        WITH selected(dataset_id, resource_type) AS (
            SELECT *
              FROM unnest(
                    CAST(:dataset_ids AS varchar[]),
                    CAST(:resource_types AS varchar[])
              )
        )
        SELECT resource.dataset_id,
               resource.resource_type,
               COUNT(*)::bigint AS resource_rows
          FROM {_qt(_schema(), ProviderDirectoryDatasetResource.__tablename__)}
               AS resource
          JOIN selected
            ON selected.dataset_id = resource.dataset_id
           AND selected.resource_type = resource.resource_type
         GROUP BY resource.dataset_id, resource.resource_type
         ORDER BY resource.dataset_id, resource.resource_type;
        """,
        dataset_ids=[pair[0] for pair in dataset_resource_pairs],
        resource_types=[pair[1] for pair in dataset_resource_pairs],
    )


def _artifact_scope_projection_summary(
    fence: ProviderDirectoryArtifactDatasetFence,
    resource_types: frozenset[str],
    alias_count_by_dataset_id: dict[str, int],
    resource_rows: list[Any],
) -> dict[str, Any]:
    """Summarize row and alias amplification before materialization."""
    dataset_rows = 0
    projected_rows = 0
    projected_rows_by_resource: dict[str, int] = {}
    for resource_row in resource_rows:
        resource_row_map = _pagination_checkpoint_row_mapping(resource_row)
        dataset_id = _clean_text(resource_row_map.get("dataset_id"))
        resource_type = _clean_text(resource_row_map.get("resource_type"))
        resource_count = int(resource_row_map.get("resource_rows") or 0)
        if not dataset_id or not resource_type:
            continue
        dataset_rows += resource_count
        projected_count = resource_count * alias_count_by_dataset_id.get(dataset_id, 0)
        projected_rows += projected_count
        projected_rows_by_resource[resource_type] = (
            projected_rows_by_resource.get(resource_type, 0) + projected_count
        )
    return {
        "dataset_count": len(alias_count_by_dataset_id),
        "alias_count": len(fence.datasets),
        "dataset_rows": dataset_rows,
        "projected_rows": projected_rows,
        "resource_types": sorted(resource_types),
        "alias_amplification": (
            projected_rows / dataset_rows if dataset_rows else 0.0
        ),
        "aliases_by_dataset": dict(sorted(alias_count_by_dataset_id.items())),
        "projected_rows_by_resource": dict(
            sorted(projected_rows_by_resource.items())
        ),
    }


async def _provider_directory_artifact_scope_projection(
    fence: ProviderDirectoryArtifactDatasetFence,
    resource_types: frozenset[str] | None = None,
) -> dict[str, Any]:
    """Project bounded immutable scope size for selected artifact targets."""
    scoped_resource_types = (
        resource_types
        if resource_types is not None
        else PROVIDER_DIRECTORY_ARTIFACT_RESOURCE_TYPES
    )
    alias_count_by_dataset_id = _artifact_scope_alias_counts(fence)
    resource_rows = await _artifact_scope_resource_rows(
        _artifact_scope_resource_pairs(fence, scoped_resource_types)
    )
    return _artifact_scope_projection_summary(
        fence,
        scoped_resource_types,
        alias_count_by_dataset_id,
        resource_rows,
    )


def _assert_provider_directory_artifact_scope_capacity(
    projection: dict[str, Any],
) -> None:
    projected_rows = int(projection["projected_rows"])
    capacity = _provider_directory_artifact_scope_row_limit()
    if projected_rows > capacity:
        raise RuntimeError(
            "provider_directory_artifact_scope_projected_rows_exceeded:"
            f"projected={projected_rows}:capacity={capacity}"
        )


async def _reap_provider_directory_artifact_scope_tables(schema: str) -> list[str]:
    prefixes = tuple(
        sorted(
            {
                f"{model.__tablename__}_artifact_scope_"
                for model in (ProviderDirectorySource, *RESOURCE_MODELS)
            }
        )
    )
    table_rows = await db.all(
        """
        SELECT tablename
          FROM pg_tables
         WHERE schemaname = :schema_name
           AND tablename LIKE ANY(CAST(:scope_patterns AS text[]))
         ORDER BY tablename;
        """,
        schema_name=schema,
        scope_patterns=[f"{prefix}%" for prefix in prefixes],
    )
    table_names = sorted(
        table_name
        for table_row in table_rows
        if (table_name := _clean_text(
            _pagination_checkpoint_row_mapping(table_row).get("tablename")
        ))
        and any(table_name.startswith(prefix) for prefix in prefixes)
    )
    for table_name in table_names:
        await db.status(f"DROP TABLE IF EXISTS {_qt(schema, table_name)};")
    return table_names


@contextlib.asynccontextmanager
async def _provider_directory_artifact_scope_guard(schema: str) -> AsyncIterator[None]:
    """Serialize scoped table ownership so prefix cleanup cannot reap live work."""
    async with _provider_directory_artifact_build_guard(
        schema,
        "provider_directory_artifact_scope",
    ):
        yield


def _provider_directory_artifact_scope_table_name(
    table_name: str,
    run_id: str | None,
) -> str:
    identity = (
        f"{table_name}:{run_id or 'artifact'}:{os.getpid()}:"
        f"{time.time_ns()}:{os.urandom(8).hex()}"
    )
    digest = hashlib.sha1(identity.encode("utf-8")).hexdigest()[:16]
    return _bounded_identifier(f"{table_name}_artifact_scope_{digest}")


def _provider_directory_artifact_scope_table_sql(
    model: Any,
    schema: str,
    table_name: str,
) -> str:
    dialect = postgresql.dialect()
    column_definitions = [
        str(CreateColumn(column).compile(dialect=dialect)).strip()
        for column in model.__table__.columns
    ]
    primary_key_columns = [
        _q(column.name) for column in model.__table__.primary_key.columns
    ]
    if primary_key_columns:
        column_definitions.append(
            f"PRIMARY KEY ({', '.join(primary_key_columns)})"
        )
    return (
        f"CREATE UNLOGGED TABLE {_qt(schema, table_name)} (\n    "
        + ",\n    ".join(column_definitions)
        + "\n);"
    )


def _provider_directory_artifact_payload_column_sql(column: Any) -> str:
    column_name = column.name
    if column_name == "source_id":
        return "selected.source_id"
    if column_name == "resource_id":
        return "resource.resource_id"
    if column_name == "last_seen_run_id":
        return "selected.evidence_run_id"
    if column_name in {"observed_at", "updated_at"}:
        return (
            "COALESCE(dataset.published_at, dataset.validated_at, "
            "dataset.created_at)"
        )
    json_key = _sql_string_literal(column_name)
    payload_expr = f"resource.payload_json::jsonb -> {json_key}"
    if isinstance(column.type, SQLAlchemyJSON):
        return f"CAST({payload_expr} AS json)"
    column_type = column.type.compile(dialect=postgresql.dialect())
    return (
        f"CAST(resource.payload_json::jsonb ->> {json_key} AS {column_type})"
    )


def _provider_directory_artifact_resource_insert_sql(
    model: Any,
    schema: str,
    table_name: str,
) -> str:
    columns = list(model.__table__.columns)
    column_names = ", ".join(_q(column.name) for column in columns)
    selected_columns = ",\n            ".join(
        _provider_directory_artifact_payload_column_sql(column)
        for column in columns
    )
    return f"""
        INSERT INTO {_qt(schema, table_name)} ({column_names})
        WITH selected(source_id, dataset_id, evidence_run_id) AS (
            SELECT *
              FROM unnest(
                    CAST(:source_ids AS varchar[]),
                    CAST(:dataset_ids AS varchar[]),
                    CAST(:evidence_run_ids AS varchar[])
              )
        )
        SELECT {selected_columns}
          FROM selected
          JOIN {_qt(schema, ProviderDirectoryEndpointDataset.__tablename__)} AS dataset
            ON dataset.dataset_id = selected.dataset_id
          JOIN {_qt(schema, ProviderDirectoryDatasetResource.__tablename__)} AS resource
            ON resource.dataset_id = selected.dataset_id
           AND resource.resource_type = :resource_type;
    """


async def _materialize_provider_directory_artifact_source_scope(
    schema: str,
    table_name: str,
    source_ids: list[str],
) -> None:
    model = ProviderDirectorySource
    await db.status(
        _provider_directory_artifact_scope_table_sql(model, schema, table_name)
    )
    columns = ", ".join(_q(column.name) for column in model.__table__.columns)
    await db.status(
        f"""
        INSERT INTO {_qt(schema, table_name)} ({columns})
        SELECT {columns}
          FROM {_qt(schema, model.__tablename__)}
         WHERE source_id = ANY(CAST(:source_ids AS varchar[]));
        """,
        source_ids=source_ids,
    )
    await db.status(f"ANALYZE {_qt(schema, table_name)};")


async def _materialize_provider_directory_artifact_resource_scope(
    schema: str,
    table_name: str,
    model: Any,
    fence: ProviderDirectoryArtifactDatasetFence,
    resource_types: frozenset[str],
) -> None:
    await db.status(
        _provider_directory_artifact_scope_table_sql(model, schema, table_name)
    )
    resource_type = RESOURCE_TYPES_BY_MODEL[model]
    selected_datasets = [
        dataset
        for dataset in fence.datasets
        if resource_type in resource_types
        and resource_type in dataset.selected_resources
    ]
    if selected_datasets:
        await db.status(
            _provider_directory_artifact_resource_insert_sql(
                model,
                schema,
                table_name,
            ),
            source_ids=[dataset.source_id for dataset in selected_datasets],
            dataset_ids=[dataset.dataset_id for dataset in selected_datasets],
            evidence_run_ids=[
                dataset.evidence_run_id for dataset in selected_datasets
            ],
            resource_type=resource_type,
        )
    await db.status(f"ANALYZE {_qt(schema, table_name)};")


async def _verify_provider_directory_artifact_dataset_fence(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> None:
    dataset_rows = await _artifact_fence_dataset_rows(
        fence,
        db,
        for_update=False,
    )
    _assert_locked_artifact_fence_datasets(fence, dataset_rows)


async def _lock_and_verify_artifact_dataset_fence(
    fence: ProviderDirectoryArtifactDatasetFence,
    executor: Any | None = None,
) -> None:
    """Fence alias and dataset identity while an artifact becomes live."""
    if not fence.datasets:
        return
    query_executor = executor or db
    await _lock_artifact_fence_endpoints(fence, query_executor)
    locked_alias_rows = await _lock_artifact_fence_aliases(
        fence,
        query_executor,
    )
    _assert_locked_artifact_fence_aliases(fence, locked_alias_rows)
    locked_dataset_rows = await _artifact_fence_dataset_rows(
        fence,
        query_executor,
        for_update=True,
    )
    _assert_locked_artifact_fence_datasets(fence, locked_dataset_rows)


async def _lock_artifact_fence_endpoints(
    fence: ProviderDirectoryArtifactDatasetFence,
    executor: Any,
) -> None:
    """Serialize cutover with endpoint dataset promotion."""
    endpoint_ref = _unscoped_qt(
        _schema(),
        ProviderDirectoryAPIEndpoint.__tablename__,
    )
    endpoint_rows = await executor.all(
        f"""
        SELECT endpoint_id
          FROM {endpoint_ref}
         WHERE endpoint_id = ANY(CAST(:endpoint_ids AS varchar[]))
         ORDER BY endpoint_id
         FOR UPDATE;
        """,
        endpoint_ids=fence.endpoint_ids,
    )
    locked_endpoint_ids = sorted(
        endpoint_id
        for endpoint_row in endpoint_rows
        if (endpoint_id := _clean_text(
            _pagination_checkpoint_row_mapping(endpoint_row).get("endpoint_id")
        ))
    )
    if locked_endpoint_ids != fence.endpoint_ids:
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_api_endpoint_changed"
        )


async def _lock_artifact_fence_aliases(
    fence: ProviderDirectoryArtifactDatasetFence,
    executor: Any,
) -> list[Any]:
    """Lock and return every alias currently attached to selected endpoints."""
    source_ref = _unscoped_qt(_schema(), ProviderDirectorySource.__tablename__)
    await executor.status(f"LOCK TABLE {source_ref} IN SHARE MODE;")
    return await executor.all(
        f"""
        SELECT source.source_id,
               source.endpoint_id,
               to_jsonb(source) AS source_record_json
          FROM {source_ref} AS source
         WHERE source.endpoint_id = ANY(CAST(:endpoint_ids AS varchar[]))
         ORDER BY source.source_id, source.endpoint_id
         FOR SHARE OF source;
        """,
        endpoint_ids=fence.endpoint_ids,
    )


def _assert_locked_artifact_fence_aliases(
    fence: ProviderDirectoryArtifactDatasetFence,
    locked_alias_rows: list[Any],
) -> None:
    """Ensure the complete held alias family remains exact."""
    alias_rows_by_source_id = {
        source_id: alias_row_map
        for alias_row in locked_alias_rows
        if (
            alias_row_map := _pagination_checkpoint_row_mapping(alias_row)
        )
        and (source_id := _clean_text(alias_row_map.get("source_id")))
    }
    actual_source_endpoint_tuples = tuple(
        sorted(
            (
                source_id,
                _clean_text(alias_row_map.get("endpoint_id")) or "",
            )
            for source_id, alias_row_map in alias_rows_by_source_id.items()
        )
    )
    if actual_source_endpoint_tuples != fence.source_endpoint_tuples:
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_source_endpoint_dataset_changed"
        )
    for dataset in fence.datasets:
        if dataset.recorded_expected_resources is not None:
            continue
        alias_row_map = alias_rows_by_source_id[dataset.source_id]
        source_record = _json_object(alias_row_map.get("source_record_json"))
        if (
            _endpoint_dataset_expected_resources([source_record])
            != dataset.expected_resources
        ):
            raise ProviderDirectoryArtifactBuildStale(
                "provider_directory_endpoint_dataset_expected_metadata_changed"
            )


def _artifact_fence_dataset_rows_sql(*, for_update: bool) -> str:
    lock_sql = "FOR UPDATE" if for_update else ""
    return f"""
        SELECT dataset_id,
               endpoint_id,
               import_run_id,
               acquisition_root_run_id,
               previous_dataset_id,
               dataset_hash,
               status,
               is_current,
               resource_count,
               validated_at,
               published_at,
               superseded_at,
               publication_metadata_json
          FROM {_unscoped_qt(_schema(), ProviderDirectoryEndpointDataset.__tablename__)}
         WHERE endpoint_id = ANY(CAST(:endpoint_ids AS varchar[]))
         ORDER BY dataset_id
         {lock_sql};
    """


async def _artifact_fence_dataset_rows(
    fence: ProviderDirectoryArtifactDatasetFence,
    executor: Any,
    *,
    for_update: bool,
) -> list[Any]:
    return await executor.all(
        _artifact_fence_dataset_rows_sql(for_update=for_update),
        endpoint_ids=fence.endpoint_ids,
    )


def _artifact_fence_dataset_row_identity(
    dataset_row_map: dict[str, Any],
) -> tuple[Any, ...]:
    validated_at = dataset_row_map.get("validated_at")
    return (
        _clean_text(dataset_row_map.get("endpoint_id")),
        _clean_text(dataset_row_map.get("acquisition_root_run_id"))
        or _clean_text(dataset_row_map.get("import_run_id")),
        _clean_text(dataset_row_map.get("status")),
        dataset_row_map.get("is_current") is True,
        _clean_text(dataset_row_map.get("previous_dataset_id")),
        _clean_text(dataset_row_map.get("dataset_hash")),
        (
            int(dataset_row_map.get("resource_count"))
            if dataset_row_map.get("resource_count") is not None
            else None
        ),
        str(validated_at) if validated_at is not None else None,
        _identity_hash(
            _json_object(dataset_row_map.get("publication_metadata_json"))
        ),
    )


def _expected_artifact_fence_dataset_identity(
    dataset: ProviderDirectoryArtifactDataset,
) -> tuple[Any, ...]:
    return (
        dataset.endpoint_id,
        dataset.evidence_run_id,
        dataset.status,
        dataset.is_current,
        dataset.previous_dataset_id,
        dataset.dataset_hash,
        dataset.resource_count,
        dataset.validated_at,
        dataset.publication_metadata_hash,
    )


def _is_artifact_fence_dataset_row_exact(
    dataset: ProviderDirectoryArtifactDataset,
    dataset_row_map: dict[str, Any],
) -> bool:
    actual_identity = _artifact_fence_dataset_row_identity(dataset_row_map)
    expected_identity = _expected_artifact_fence_dataset_identity(dataset)
    for field_index, (actual_value, expected_value) in enumerate(
        zip(actual_identity, expected_identity)
    ):
        if field_index >= 5 and expected_value is None:
            continue
        if actual_value != expected_value:
            return False
    return True


def _current_published_artifact_dataset_ids(
    dataset_row_maps: Iterable[dict[str, Any]],
    endpoint_id: str,
) -> list[str]:
    return sorted(
        _clean_text(dataset_row_map.get("dataset_id")) or ""
        for dataset_row_map in dataset_row_maps
        if _clean_text(dataset_row_map.get("endpoint_id")) == endpoint_id
        and dataset_row_map.get("is_current") is True
        and _clean_text(dataset_row_map.get("status"))
        == ENDPOINT_DATASET_PUBLISHED
        and dataset_row_map.get("superseded_at") is None
    )


def _validated_artifact_dataset_ids(
    dataset_row_maps: Iterable[dict[str, Any]],
) -> list[str]:
    return sorted(
        _clean_text(dataset_row_map.get("dataset_id")) or ""
        for dataset_row_map in dataset_row_maps
        if dataset_row_map.get("is_current") is not True
        and _clean_text(dataset_row_map.get("status"))
        == ENDPOINT_DATASET_VALIDATED
        and dataset_row_map.get("superseded_at") is None
    )


def _assert_locked_artifact_fence_datasets(
    fence: ProviderDirectoryArtifactDatasetFence,
    locked_dataset_rows: list[Any],
) -> None:
    """Reverify selected datasets, candidates, and expected incumbents."""
    dataset_rows_by_id = {
        dataset_id: dataset_row_map
        for dataset_row in locked_dataset_rows
        if (
            dataset_row_map := _pagination_checkpoint_row_mapping(dataset_row)
        )
        and (dataset_id := _clean_text(dataset_row_map.get("dataset_id")))
    }
    rows_by_endpoint_id: dict[str, list[dict[str, Any]]] = {}
    for dataset_row_map in dataset_rows_by_id.values():
        endpoint_id = _clean_text(dataset_row_map.get("endpoint_id"))
        if endpoint_id:
            rows_by_endpoint_id.setdefault(endpoint_id, []).append(
                dataset_row_map
            )
    for dataset in _unique_artifact_datasets(fence):
        endpoint_dataset_rows = rows_by_endpoint_id.get(
            dataset.endpoint_id,
            [],
        )
        actual_current_ids = _current_published_artifact_dataset_ids(
            endpoint_dataset_rows,
            dataset.endpoint_id,
        )
        expected_incumbent_id = (
            dataset.expected_incumbent_dataset_id
            if dataset.promote_on_cutover
            else dataset.dataset_id
        )
        expected_current_ids = (
            [expected_incumbent_id] if expected_incumbent_id else []
        )
        if actual_current_ids != expected_current_ids:
            raise ProviderDirectoryArtifactBuildStale(
                "provider_directory_endpoint_dataset_current_changed"
            )
        if fence.should_select_validated_candidates:
            actual_validated_ids = _validated_artifact_dataset_ids(
                endpoint_dataset_rows
            )
            expected_validated_ids = (
                [dataset.dataset_id] if dataset.promote_on_cutover else []
            )
            if actual_validated_ids != expected_validated_ids:
                raise ProviderDirectoryArtifactBuildStale(
                    "provider_directory_endpoint_dataset_candidate_changed"
                )
        selected_row = dataset_rows_by_id.get(dataset.dataset_id)
        if selected_row is None or not _is_artifact_fence_dataset_row_exact(
            dataset,
            selected_row,
        ):
            raise ProviderDirectoryArtifactBuildStale(
                "provider_directory_endpoint_dataset_metadata_changed"
            )


@contextlib.asynccontextmanager
async def _provider_directory_active_artifact_dataset_transaction() -> AsyncIterator[None]:
    """Keep endpoint dataset identity stable during additive archive mutation."""
    fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
    if fence is None:
        yield
        return
    async with db.transaction():
        await _lock_and_verify_artifact_dataset_fence(fence, db)
        yield


@contextlib.asynccontextmanager
async def _provider_directory_artifact_dataset_scope(
    *,
    run_id: str | None,
    source_ids: list[str] | tuple[str, ...] | None,
    fence: ProviderDirectoryArtifactDatasetFence | None = None,
    metrics: dict[str, Any] | None = None,
    resource_types: frozenset[str] | None = None,
) -> AsyncIterator[ProviderDirectoryArtifactDatasetFence]:
    """Materialize and clean one bounded alias-aware artifact source scope."""
    schema = _schema()
    fence = fence or await _resolve_provider_directory_artifact_datasets(source_ids)
    async with _provider_directory_artifact_scope_guard(schema):
        reaped_tables = await _reap_provider_directory_artifact_scope_tables(schema)
        scoped_resource_types = (
            resource_types
            if resource_types is not None
            else PROVIDER_DIRECTORY_ARTIFACT_RESOURCE_TYPES
        )
        projection = await _provider_directory_artifact_scope_projection(
            fence,
            scoped_resource_types,
        )
        _assert_provider_directory_artifact_scope_capacity(projection)
        _record_artifact_scope_metrics(metrics, projection, reaped_tables)
        relation_overrides, created_tables = await _materialize_artifact_scope_tables(
            schema,
            run_id,
            fence,
            scoped_resource_types,
        )
        try:
            relation_token = _PROVIDER_DIRECTORY_ARTIFACT_RELATION_OVERRIDES.set(
                relation_overrides
            )
            fence_token = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.set(fence)
            try:
                yield fence
            finally:
                _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.reset(fence_token)
                _PROVIDER_DIRECTORY_ARTIFACT_RELATION_OVERRIDES.reset(relation_token)
        finally:
            await _drop_artifact_scope_tables(schema, created_tables)


def _record_artifact_scope_metrics(
    metrics: dict[str, Any] | None,
    projection: dict[str, Any],
    reaped_tables: list[str],
) -> None:
    if metrics is None:
        return
    metrics["artifact_scope_dataset_count"] = projection["dataset_count"]
    metrics["artifact_scope_alias_count"] = projection["alias_count"]
    metrics["artifact_scope_dataset_rows"] = projection["dataset_rows"]
    metrics["artifact_scope_projected_rows"] = projection["projected_rows"]
    metrics["artifact_scope_resource_types"] = projection["resource_types"]
    metrics["artifact_scope_alias_amplification"] = projection[
        "alias_amplification"
    ]
    metrics["artifact_scope_projected_rows_by_resource"] = projection[
        "projected_rows_by_resource"
    ]
    metrics["artifact_scope_aliases_by_dataset"] = projection[
        "aliases_by_dataset"
    ]
    metrics["artifact_scope_reaped_table_count"] = len(reaped_tables)


async def _materialize_artifact_scope_tables(
    schema: str,
    run_id: str | None,
    fence: ProviderDirectoryArtifactDatasetFence,
    resource_types: frozenset[str],
) -> tuple[dict[str, str], list[str]]:
    source_table = _provider_directory_artifact_scope_table_name(
        ProviderDirectorySource.__tablename__,
        run_id,
    )
    created_tables = [source_table]
    relation_by_table = {ProviderDirectorySource.__tablename__: source_table}
    try:
        await _materialize_provider_directory_artifact_source_scope(
            schema,
            source_table,
            [dataset.source_id for dataset in fence.datasets],
        )
        for model in RESOURCE_MODELS:
            scope_table = _provider_directory_artifact_scope_table_name(
                model.__tablename__,
                run_id,
            )
            created_tables.append(scope_table)
            await _materialize_provider_directory_artifact_resource_scope(
                schema,
                scope_table,
                model,
                fence,
                resource_types,
            )
            relation_by_table[model.__tablename__] = scope_table
    except BaseException:
        await _drop_artifact_scope_tables(schema, created_tables)
        raise
    return relation_by_table, created_tables


async def _drop_artifact_scope_tables(
    schema: str,
    table_names: list[str],
) -> None:
    for table_name in reversed(table_names):
        try:
            await db.status(f"DROP TABLE IF EXISTS {_qt(schema, table_name)};")
        except Exception:  # pragma: no cover - cleanup best effort
            LOGGER.warning(
                "Failed to clean Provider Directory artifact scope %s",
                table_name,
                exc_info=True,
            )


async def publish_provider_directory_location_address_keys(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
    batch_size: int | None = None,
) -> int:
    """Publish provider directory location address keys for provider-directory serving."""
    schema = db_schema or _schema()
    if not await _address_canon_functions_available(schema):
        return 0
    restore_state_from_zip = await _table_exists(schema, "geo_zip_lookup")
    params: dict[str, Any] = {}
    if run_id is not None:
        params["run_id"] = run_id
    if source_ids:
        params["source_ids"] = list(source_ids)
    total_updated = 0
    after_source_id: str | None = None
    after_resource_id: str | None = None
    bounded_batch_size = max(int(batch_size or _location_address_key_batch_size()), 1)
    sql = provider_directory_location_address_key_batch_sql(
        schema,
        restore_state_from_zip=restore_state_from_zip,
        run_id=run_id,
        source_ids=source_ids,
        seen_table=seen_table,
    )
    while True:
        row = await db.first(
            sql,
            **params,
            after_source_id=after_source_id,
            after_resource_id=after_resource_id,
            batch_size=bounded_batch_size,
        )
        payload = row._mapping if hasattr(row, "_mapping") else dict(row or {})
        candidate_rows = int(payload.get("candidate_rows") or 0)
        updated_rows = int(payload.get("updated_rows") or 0)
        total_updated += updated_rows
        next_source_id = _clean_text(payload.get("last_source_id"))
        next_resource_id = _clean_text(payload.get("last_resource_id"))
        if candidate_rows <= 0 or not next_source_id or not next_resource_id:
            break
        if next_source_id == after_source_id and next_resource_id == after_resource_id:
            break
        after_source_id = next_source_id
        after_resource_id = next_resource_id
    return total_updated


async def backfill_provider_directory_resource_id_npis(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
) -> dict[str, int]:
    """Backfill payer rows that use the FHIR resource id as the NPI."""
    schema = db_schema or _schema()
    cleaned_source_ids = _clean_source_id_list(source_ids)
    query_params_by_name: dict[str, Any] = {}
    scope_clauses: list[str] = []
    if cleaned_source_ids:
        scope_clauses.append("resource.source_id = ANY(CAST(:source_ids AS varchar[]))")
        query_params_by_name["source_ids"] = cleaned_source_ids
    if seen_table:
        seen_run_filter = "AND seen.run_id = CAST(:run_id AS varchar)" if run_id else ""
        if run_id:
            query_params_by_name["run_id"] = run_id
        seen_ref = _qt(schema, seen_table)
        scope_clauses.append(
            f"""EXISTS (
                SELECT 1
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = :resource_type
                   {seen_run_filter}
                   AND seen.source_id = resource.source_id
                   AND seen.resource_id = resource.resource_id
            )"""
        )
    elif run_id:
        scope_clauses.append("resource.last_seen_run_id = CAST(:run_id AS varchar)")
        query_params_by_name["run_id"] = run_id
    scope_sql = "".join(f"\n               AND {clause}" for clause in scope_clauses)
    updated_counts_by_resource: dict[str, int] = {}
    for resource_type, table_name in (
        ("Practitioner", "provider_directory_practitioner"),
        ("Organization", "provider_directory_organization"),
    ):
        updated_counts_by_resource[resource_type] = _coerce_rowcount(
            await db.status(
                f"""
                UPDATE {_qt(schema, table_name)} AS resource
                   SET npi = resource.resource_id::bigint,
                       updated_at = now()
                 WHERE resource.npi IS NULL
                   AND resource.resource_id ~ '^[0-9]{{10}}$'
                   {scope_sql};
                """,
                **query_params_by_name,
                resource_type=resource_type,
            )
        )
    return updated_counts_by_resource


def _unique_artifact_datasets(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> list[ProviderDirectoryArtifactDataset]:
    datasets_by_id: dict[str, ProviderDirectoryArtifactDataset] = {}
    for dataset in fence.datasets:
        incumbent = datasets_by_id.setdefault(dataset.dataset_id, dataset)
        if incumbent.endpoint_id != dataset.endpoint_id:
            raise RuntimeError(
                "provider_directory_artifact_dataset_endpoint_ambiguous:"
                + dataset.dataset_id
            )
    return [datasets_by_id[dataset_id] for dataset_id in sorted(datasets_by_id)]


def _artifact_fence_for_dataset(
    fence: ProviderDirectoryArtifactDatasetFence,
    dataset_id: str,
) -> ProviderDirectoryArtifactDatasetFence:
    return ProviderDirectoryArtifactDatasetFence(
        datasets=tuple(
            dataset
            for dataset in fence.datasets
            if dataset.dataset_id == dataset_id
        ),
        should_select_validated_candidates=(
            fence.should_select_validated_candidates
        ),
    )


async def _lock_dataset_serving_relation_build(
    executor: Any,
    dataset_id: str,
) -> None:
    await executor.scalar(
        "SELECT pg_advisory_xact_lock(hashtextextended(:lock_key, 0));",
        lock_key=f"provider-directory-dataset-serving-relations:{dataset_id}",
    )


async def _record_current_dataset_serving_relation_proof(
    dataset: ProviderDirectoryArtifactDataset,
    metadata_key: str,
    proof: dict[str, Any],
) -> None:
    dataset_ref = _qt(
        _schema(),
        ProviderDirectoryEndpointDataset.__tablename__,
    )
    updated = await db.status(
        f"""
        UPDATE {dataset_ref}
           SET publication_metadata_json = jsonb_set(
               COALESCE(publication_metadata_json::jsonb, '{{}}'::jsonb),
               '{{{metadata_key}}}',
               CAST(:proof_json AS jsonb),
               true
           )
         WHERE dataset_id = :dataset_id
           AND endpoint_id = :endpoint_id
           AND COALESCE(acquisition_root_run_id, import_run_id)
               IS NOT DISTINCT FROM :evidence_run_id
           AND previous_dataset_id IS NOT DISTINCT FROM :previous_dataset_id
           AND dataset_hash IS NOT DISTINCT FROM :dataset_hash
           AND is_current = :is_current
           AND status = :expected_status
           AND superseded_at IS NULL;
        """,
        proof_json=json.dumps(proof, sort_keys=True, default=_json_default),
        dataset_id=dataset.dataset_id,
        endpoint_id=dataset.endpoint_id,
        evidence_run_id=dataset.evidence_run_id,
        previous_dataset_id=dataset.previous_dataset_id,
        dataset_hash=dataset.dataset_hash,
        is_current=dataset.is_current,
        expected_status=dataset.status,
    )
    if _coerce_rowcount(updated) != 1:
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_endpoint_dataset_metadata_changed"
        )


def _dataset_network_plan_aggregate_proof(
    dataset_proofs: list[dict[str, Any]],
    *,
    build_run_id: str | None,
) -> dict[str, Any]:
    count_fields = (
        "insurance_plan_resource_count",
        "insurance_plan_with_network_refs_count",
        "zero_network_reference_plan_count",
        "malformed_network_refs_payload_count",
        "network_reference_value_count",
        "valid_network_reference_count",
        "invalid_network_reference_count",
        "expected_edge_count",
        "edge_count",
        "duplicate_network_reference_count",
        "replaced_edge_count",
        "plan_projection_count",
        "replaced_plan_projection_count",
        "inserted_plan_projection_count",
    )
    return {
        "complete": True,
        "version": PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_VERSION,
        "build_run_id": build_run_id,
        "dataset_count": len(dataset_proofs),
        "dataset_ids": [proof["dataset_id"] for proof in dataset_proofs],
        **{
            field_name: sum(int(proof[field_name]) for proof in dataset_proofs)
            for field_name in count_fields
        },
        "datasets": dataset_proofs,
    }


def _dataset_affiliation_organization_aggregate_proof(
    dataset_proofs: list[dict[str, Any]],
    *,
    build_run_id: str | None,
) -> dict[str, Any]:
    count_fields = (
        "affiliation_resource_count",
        "affiliation_with_participating_organization_count",
        "empty_participating_organization_reference_count",
        "malformed_reference_payload_count",
        "valid_reference_count",
        "invalid_reference_count",
        "expected_edge_count",
        "edge_count",
        "replaced_edge_count",
    )
    return {
        "complete": True,
        "version": (
            PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_VERSION
        ),
        "build_run_id": build_run_id,
        "dataset_count": len(dataset_proofs),
        "dataset_ids": [proof["dataset_id"] for proof in dataset_proofs],
        **{
            field_name: sum(int(proof[field_name]) for proof in dataset_proofs)
            for field_name in count_fields
        },
        "datasets": dataset_proofs,
    }


async def _rebuild_one_current_dataset_relation_set(
    dataset: ProviderDirectoryArtifactDataset,
    *,
    build_run_id: str | None,
    should_rebuild_network_plan: bool,
    should_rebuild_affiliation_organization: bool,
) -> dict[str, dict[str, Any]]:
    proof_by_relation: dict[str, dict[str, Any]] = {}
    if should_rebuild_network_plan:
        network_proof = await _build_provider_directory_dataset_network_plan(
            db,
            dataset.dataset_id,
            build_run_id=build_run_id,
            expected_acquisition_root_run_id=dataset.evidence_run_id,
        )
        proof_by_relation[
            PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_METADATA_KEY
        ] = network_proof
    if should_rebuild_affiliation_organization:
        affiliation_proof = (
            await _build_provider_directory_dataset_affiliation_organization(
                db,
                dataset.dataset_id,
                build_run_id=build_run_id,
                expected_acquisition_root_run_id=dataset.evidence_run_id,
            )
        )
        proof_by_relation[
            PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_METADATA_KEY
        ] = affiliation_proof
    for metadata_key, relation_proof in proof_by_relation.items():
        await _record_current_dataset_serving_relation_proof(
            dataset,
            metadata_key,
            relation_proof,
        )
    return proof_by_relation


def _aggregate_dataset_serving_relation_proofs(
    proof_list_by_relation: dict[str, list[dict[str, Any]]],
    *,
    build_run_id: str | None,
) -> dict[str, dict[str, Any]]:
    aggregate_by_relation: dict[str, dict[str, Any]] = {}
    network_key = PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_METADATA_KEY
    affiliation_key = (
        PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_METADATA_KEY
    )
    if network_key in proof_list_by_relation:
        aggregate_by_relation[network_key] = (
            _dataset_network_plan_aggregate_proof(
                proof_list_by_relation[network_key],
                build_run_id=build_run_id,
            )
        )
    if affiliation_key in proof_list_by_relation:
        aggregate_by_relation[affiliation_key] = (
            _dataset_affiliation_organization_aggregate_proof(
                proof_list_by_relation[affiliation_key],
                build_run_id=build_run_id,
            )
        )
    return aggregate_by_relation


async def _rebuild_current_dataset_serving_relations(
    fence: ProviderDirectoryArtifactDatasetFence,
    *,
    build_run_id: str | None,
    should_rebuild_network_plan: bool,
    should_rebuild_affiliation_organization: bool,
) -> dict[str, dict[str, Any]]:
    """Refresh selected dataset relations without global-table cutover."""
    selected_datasets = _unique_artifact_datasets(fence)
    proof_list_by_relation: dict[str, list[dict[str, Any]]] = {}
    for dataset in selected_datasets:
        dataset_fence = _artifact_fence_for_dataset(fence, dataset.dataset_id)
        async with db.transaction():
            await _lock_and_verify_artifact_dataset_fence(dataset_fence, db)
            await _lock_dataset_serving_relation_build(db, dataset.dataset_id)
            proof_by_relation = (
                await _rebuild_one_current_dataset_relation_set(
                    dataset,
                    build_run_id=build_run_id,
                    should_rebuild_network_plan=should_rebuild_network_plan,
                    should_rebuild_affiliation_organization=(
                        should_rebuild_affiliation_organization
                    ),
                )
            )
            for relation_name, relation_proof in proof_by_relation.items():
                proof_list_by_relation.setdefault(
                    relation_name,
                    [],
                ).append(relation_proof)
    for relation_name, should_rebuild in (
        (
            PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_METADATA_KEY,
            should_rebuild_network_plan,
        ),
        (
            PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_METADATA_KEY,
            should_rebuild_affiliation_organization,
        ),
    ):
        if should_rebuild:
            proof_list_by_relation.setdefault(relation_name, [])
    return _aggregate_dataset_serving_relation_proofs(
        proof_list_by_relation,
        build_run_id=build_run_id,
    )


async def _publish_current_dataset_relation_artifacts(
    fence: ProviderDirectoryArtifactDatasetFence,
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    publish_artifacts_targets: set[str] | None,
) -> None:
    should_rebuild_network_plan = is_provider_directory_publish_target_enabled(
        publish_artifacts_targets,
        "dataset_network_plan",
    )
    should_rebuild_affiliation_organization = (
        is_provider_directory_publish_target_enabled(
            publish_artifacts_targets,
            "dataset_affiliation_organization",
        )
    )
    relation_proof_by_name: dict[str, dict[str, Any]] = {}
    if should_rebuild_network_plan or should_rebuild_affiliation_organization:
        relation_proof_by_name = (
            await _rebuild_current_dataset_serving_relations(
                fence,
                build_run_id=run_id,
                should_rebuild_network_plan=should_rebuild_network_plan,
                should_rebuild_affiliation_organization=(
                    should_rebuild_affiliation_organization
                ),
            )
        )
    metrics.update(relation_proof_by_name)
    if not should_rebuild_network_plan:
        metrics[PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_METADATA_KEY] = (
            _provider_directory_publish_target_skipped()
        )
    if not should_rebuild_affiliation_organization:
        metrics[
            PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_METADATA_KEY
        ] = _provider_directory_publish_target_skipped()


def _is_dataset_relation_only_artifact_target(
    publish_artifacts_targets: set[str] | None,
) -> bool:
    dataset_relation_targets = {
        "dataset_network_plan",
        "dataset_affiliation_organization",
    }
    return (
        publish_artifacts_targets is not None
        and publish_artifacts_targets.issubset(dataset_relation_targets)
    )


def _artifact_fence_selection_identity(
    fence: ProviderDirectoryArtifactDatasetFence,
) -> tuple[Any, ...]:
    """Return immutable selection fields that relation-proof refresh may not alter."""
    return (
        fence.should_select_validated_candidates,
        tuple(
            sorted(
                (
                    dataset.source_id,
                    dataset.endpoint_id,
                    dataset.dataset_id,
                    dataset.evidence_run_id,
                    dataset.selected_resources,
                    dataset.expected_resources,
                    dataset.recorded_expected_resources,
                    dataset.status,
                    dataset.is_current,
                    dataset.previous_dataset_id,
                    dataset.expected_incumbent_dataset_id,
                    dataset.promote_on_cutover,
                    dataset.dataset_hash,
                    dataset.resource_count,
                    dataset.validated_at,
                )
                for dataset in fence.datasets
            )
        ),
    )


def _assert_artifact_fence_selection_unchanged(
    expected_fence: ProviderDirectoryArtifactDatasetFence,
    refreshed_fence: ProviderDirectoryArtifactDatasetFence,
) -> None:
    if (
        _artifact_fence_selection_identity(expected_fence)
        != _artifact_fence_selection_identity(refreshed_fence)
    ):
        raise ProviderDirectoryArtifactBuildStale(
            "provider_directory_artifact_dataset_selection_changed"
        )


async def _publish_provider_directory_dataset_artifacts(
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    source_ids: list[str] | tuple[str, ...] | None,
    publish_corroboration: bool,
    publish_artifacts_targets: set[str] | None,
) -> dict[str, Any]:
    """Build one selected dataset bundle and atomically publish its pointers."""
    should_select_validated_candidates = (
        _should_select_validated_artifacts(publish_artifacts_targets)
    )
    fence = await _prepare_artifact_publication_fence(
        source_ids,
        run_id=run_id,
        metrics=metrics,
        publish_artifacts_targets=publish_artifacts_targets,
        publish_corroboration=publish_corroboration,
        should_select_validated_candidates=should_select_validated_candidates,
    )
    if _is_dataset_relation_only_artifact_target(publish_artifacts_targets):
        metrics["publish_artifacts_targets"] = sorted(
            publish_artifacts_targets or ()
        )
        return metrics
    artifact_resource_types = _provider_directory_artifact_resource_types(
        publish_artifacts_targets,
        publish_corroboration=publish_corroboration,
    )
    return await _publish_artifact_bundle_from_fence(
        fence,
        run_id=run_id,
        metrics=metrics,
        source_ids=source_ids,
        publish_corroboration=publish_corroboration,
        publish_artifacts_targets=publish_artifacts_targets,
        artifact_resource_types=artifact_resource_types,
    )


async def _prepare_artifact_publication_fence(
    source_ids: list[str] | tuple[str, ...] | None,
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    publish_artifacts_targets: set[str] | None,
    publish_corroboration: bool,
    should_select_validated_candidates: bool,
) -> ProviderDirectoryArtifactDatasetFence:
    fence = await _resolve_provider_directory_artifact_datasets(
        source_ids,
        should_select_validated_candidates=should_select_validated_candidates,
    )
    _assert_provider_directory_artifact_target_dependencies(
        fence,
        publish_artifacts_targets=publish_artifacts_targets,
        publish_corroboration=publish_corroboration,
    )
    await _publish_current_dataset_relation_artifacts(
        fence,
        run_id=run_id,
        metrics=metrics,
        publish_artifacts_targets=publish_artifacts_targets,
    )
    refreshed_fence = await _resolve_provider_directory_artifact_datasets(
        source_ids,
        should_select_validated_candidates=should_select_validated_candidates,
    )
    _assert_artifact_fence_selection_unchanged(fence, refreshed_fence)
    return refreshed_fence


_CANDIDATE_ARTIFACT_METRIC_BY_TARGET = {
    "dataset_network_plan": PROVIDER_DIRECTORY_DATASET_NETWORK_PLAN_METADATA_KEY,
    "dataset_affiliation_organization": (
        PROVIDER_DIRECTORY_DATASET_AFFILIATION_ORGANIZATION_METADATA_KEY
    ),
    "location_contacts": "location_contacts_backfilled",
    "location_coordinates": "location_coordinates_backfilled",
    "resource_id_npis": "resource_id_npis_backfilled",
    "location_address_keys": "location_address_keys_stamped",
    "location_archive": "location_archive",
    "address_overlay": "address_overlay",
    "profile": "profile",
    "network_catalog": "network_catalog",
}


def _candidate_artifact_skip_reason(value: Any) -> str | None:
    if not isinstance(value, dict) or value.get("skipped") is not True:
        return None
    return _clean_text(value.get("reason")) or "unspecified"


def _candidate_artifact_deferred_relations(
    enabled_targets: set[str],
    publish_metrics_by_name: dict[str, Any],
) -> set[str]:
    relations: set[str] = set()
    if "address_overlay" in enabled_targets:
        relations.add(PROVIDER_DIRECTORY_ADDRESS_OVERLAY_TABLE)
    if (
        "profile" in enabled_targets
        and _candidate_artifact_skip_reason(
            publish_metrics_by_name.get("profile")
        )
        is None
    ):
        relations.update(
            {
                profile_artifact.PROFILE_EVIDENCE_TABLE,
                profile_artifact.PROFILE_TABLE,
            }
        )
    if "network_catalog" in enabled_targets:
        relations.add(PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)
    if "corroboration" in enabled_targets:
        relations.add(PROVIDER_DIRECTORY_ADDRESS_CORROBORATION_VIEW)
    return relations


def _assert_candidate_artifact_metrics_complete(
    enabled_targets: set[str],
    publish_metrics_by_name: dict[str, Any],
) -> None:
    for artifact_target_name in sorted(enabled_targets - {"corroboration"}):
        metric_name = _CANDIDATE_ARTIFACT_METRIC_BY_TARGET.get(
            artifact_target_name
        )
        if metric_name is None or metric_name not in publish_metrics_by_name:
            raise RuntimeError(
                "provider_directory_candidate_artifact_metric_missing:"
                + artifact_target_name
            )
        skip_reason = _candidate_artifact_skip_reason(
            publish_metrics_by_name[metric_name]
        )
        if skip_reason is None:
            continue
        if (
            artifact_target_name == "profile"
            and skip_reason == "no_profile_enabled_sources_in_scope"
        ):
            continue
        raise RuntimeError(
            "provider_directory_candidate_artifact_skipped:"
            f"{artifact_target_name}:{skip_reason}"
        )
    if "corroboration" in enabled_targets and publish_metrics_by_name.get(
        "ptg_corroboration_view_published"
    ) is not True:
        raise RuntimeError(
            "provider_directory_candidate_artifact_skipped:corroboration"
        )


def _assert_candidate_artifact_stage_relations_complete(
    enabled_targets: set[str],
    publish_metrics_by_name: dict[str, Any],
    artifact_bundle: ProviderDirectoryArtifactBundle,
) -> None:
    expected_relations = _candidate_artifact_deferred_relations(
        enabled_targets,
        publish_metrics_by_name,
    )
    actual_relations = {
        stage.target_relation for stage in artifact_bundle.stages
    }
    if actual_relations != expected_relations:
        missing_relations = sorted(expected_relations - actual_relations)
        unexpected_relations = sorted(actual_relations - expected_relations)
        raise RuntimeError(
            "provider_directory_candidate_artifact_bundle_incomplete:"
            f"missing={','.join(missing_relations) or '-'}:"
            f"unexpected={','.join(unexpected_relations) or '-'}"
        )


def _assert_candidate_artifact_bundle_complete(
    fence: ProviderDirectoryArtifactDatasetFence,
    publish_metrics_by_name: dict[str, Any],
    artifact_bundle: ProviderDirectoryArtifactBundle,
    *,
    publish_corroboration: bool,
    publish_artifacts_targets: set[str] | None,
) -> None:
    """Fail closed before a validated dataset can outpace its serving bundle."""
    if not fence.promotion_datasets:
        return
    enabled_targets = set(
        _provider_directory_dataset_artifact_targets(
            publish_artifacts_targets,
            publish_corroboration=publish_corroboration,
        )
    )
    _assert_candidate_artifact_metrics_complete(
        enabled_targets,
        publish_metrics_by_name,
    )
    _assert_candidate_artifact_stage_relations_complete(
        enabled_targets,
        publish_metrics_by_name,
        artifact_bundle,
    )


async def _record_artifact_promotion_metrics(
    fence: ProviderDirectoryArtifactDatasetFence,
    publish_metrics_by_name: dict[str, Any],
    promoted_stage_count: int,
) -> dict[str, Any]:
    """Record pointer promotion and best-effort retry-state cleanup."""
    promoted_dataset_ids = (
        sorted({dataset.dataset_id for dataset in fence.promotion_datasets})
        if promoted_stage_count > 0
        else []
    )
    publish_metrics_by_name["artifact_promoted_dataset_ids"] = promoted_dataset_ids
    retry_cleanup_expected_ids = (
        promoted_dataset_ids
        if fence.should_select_validated_candidates
        else []
    )
    retry_cleanup_cleared_ids = (
        await _clear_promoted_endpoint_dataset_retry_state(
            retry_cleanup_expected_ids
        )
        if retry_cleanup_expected_ids
        else []
    )
    publish_metrics_by_name["artifact_retry_state_cleared_dataset_ids"] = (
        retry_cleanup_cleared_ids
    )
    publish_metrics_by_name["artifact_retry_state_pending_dataset_ids"] = (
        sorted(
            set(retry_cleanup_expected_ids)
            - set(retry_cleanup_cleared_ids)
        )
    )
    return publish_metrics_by_name


async def _publish_artifact_bundle_from_fence(
    fence: ProviderDirectoryArtifactDatasetFence,
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    source_ids: list[str] | tuple[str, ...] | None,
    publish_corroboration: bool,
    publish_artifacts_targets: set[str] | None,
    artifact_resource_types: frozenset[str],
) -> dict[str, Any]:
    """Build one immutable serving bundle and publish it behind its fence."""
    async with _provider_directory_artifact_dataset_scope(
        run_id=run_id,
        source_ids=source_ids,
        fence=fence,
        metrics=metrics,
        resource_types=artifact_resource_types,
    ):
        async with _provider_directory_artifact_bundle_scope() as artifact_bundle:
            metrics["artifact_dataset_ids"] = sorted(
                {dataset.dataset_id for dataset in fence.datasets}
            )
            metrics["artifact_dataset_evidence_run_ids"] = sorted(
                {dataset.evidence_run_id for dataset in fence.datasets}
            )
            publish_metrics = await _publish_provider_directory_artifacts(
                run_id=run_id,
                metrics=metrics,
                address_key_run_id=None,
                publish_scope_run_id=None,
                source_ids=[dataset.source_id for dataset in fence.datasets],
                publish_corroboration=publish_corroboration,
                publish_artifacts_targets=publish_artifacts_targets,
            )
            _assert_candidate_artifact_bundle_complete(
                fence,
                publish_metrics,
                artifact_bundle,
                publish_corroboration=publish_corroboration,
                publish_artifacts_targets=publish_artifacts_targets,
            )
            promoted_stage_count = await artifact_bundle.promote()
            return await _record_artifact_promotion_metrics(
                fence,
                publish_metrics,
                promoted_stage_count,
            )


async def _publish_selected_provider_directory_artifacts(
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    source_ids: list[str],
    seen_table: str | None,
    publish_after_acquisition: bool,
    publish_corroboration: bool,
    publish_artifacts_targets: set[str] | None,
) -> dict[str, Any]:
    if publish_after_acquisition:
        return await _publish_provider_directory_dataset_artifacts(
            run_id=run_id,
            metrics=metrics,
            source_ids=source_ids,
            publish_corroboration=publish_corroboration,
            publish_artifacts_targets=publish_artifacts_targets,
        )
    return await _publish_provider_directory_artifacts(
        run_id=run_id,
        metrics=metrics,
        seen_table=seen_table,
        address_key_run_id=run_id,
        publish_scope_run_id=run_id,
        source_ids=source_ids,
        publish_corroboration=publish_corroboration,
        publish_artifacts_targets=publish_artifacts_targets,
    )


def _collect_provider_directory_artifact_stages(
    raw_stages: Any,
) -> tuple[ProviderDirectoryPreparedArtifactStage, ...] | None:
    stages = (
        (raw_stages,)
        if isinstance(raw_stages, ProviderDirectoryPreparedArtifactStage)
        else raw_stages
    )
    if (
        isinstance(stages, (list, tuple))
        and stages
        and all(
            isinstance(stage, ProviderDirectoryPreparedArtifactStage)
            for stage in stages
        )
    ):
        return tuple(stages)
    return None


def _collect_provider_directory_artifact_stage(
    publish_result: Any,
    artifact_bundle: ProviderDirectoryArtifactBundle | None,
) -> dict[str, Any]:
    """Register a deferred stage and return its serializable metrics."""
    if isinstance(publish_result, dict):
        return publish_result
    if (
        artifact_bundle is not None
        and isinstance(publish_result, tuple)
        and len(publish_result) == 2
    ):
        metrics, raw_stages = publish_result
        stages = _collect_provider_directory_artifact_stages(raw_stages)
        if isinstance(metrics, dict) and stages is not None:
            for stage in stages:
                artifact_bundle.add(stage)
            return metrics
    raise RuntimeError("provider_directory_artifact_stage_result_invalid")


async def _locked_finalized_retry_cleanup_dataset_ids(
    selected_dataset_ids: list[str],
) -> list[str]:
    finalized_rows = await db.all(
        f"""
        SELECT dataset_id
          FROM {_qt(_schema(), ProviderDirectoryEndpointDataset.__tablename__)}
         WHERE dataset_id = ANY(CAST(:dataset_ids AS varchar[]))
           AND status = ANY(CAST(:finalized_statuses AS varchar[]))
         ORDER BY dataset_id
         FOR UPDATE;
        """,
        dataset_ids=selected_dataset_ids,
        finalized_statuses=[
            ENDPOINT_DATASET_PUBLISHED,
            ENDPOINT_DATASET_SUPERSEDED,
        ],
    )
    return sorted(
        dataset_id
        for finalized_row in finalized_rows
        if (
            dataset_id := _clean_text(
                _pagination_checkpoint_row_mapping(finalized_row).get(
                    "dataset_id"
                )
            )
        )
    )


async def _delete_endpoint_dataset_retry_state(
    selected_dataset_ids: list[str],
) -> None:
    await db.status(
        f"""
        DELETE FROM {_qt(_schema(), ProviderDirectoryDatasetResource.__tablename__)}
         WHERE dataset_id = ANY(CAST(:dataset_ids AS varchar[]))
           AND resource_type LIKE 'LU:%:pass:%';
        """,
        dataset_ids=selected_dataset_ids,
    )
    await db.status(
        f"""
        DELETE FROM {_pagination_checkpoint_table_ref()}
         WHERE dataset_id = ANY(CAST(:dataset_ids AS varchar[]));
        """,
        dataset_ids=selected_dataset_ids,
    )


async def _clear_promoted_endpoint_dataset_retry_state(
    dataset_ids: Iterable[str],
) -> list[str]:
    """Atomically clear retry state for exact promoted datasets once finalized."""
    selected_dataset_ids = sorted(
        {
            cleaned_dataset_id
            for dataset_id in dataset_ids
            if (cleaned_dataset_id := _clean_text(dataset_id))
        }
    )
    if not selected_dataset_ids:
        return []
    try:
        async with asyncio.timeout(
            PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_TRANSACTION_TIMEOUT_SECONDS
        ):
            async with db.transaction():
                await db.status(
                    "SET LOCAL lock_timeout = "
                    f"'{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_LOCK_TIMEOUT}';"
                )
                await db.status(
                    "SET LOCAL statement_timeout = "
                    f"'{PROVIDER_DIRECTORY_ARTIFACT_CUTOVER_STATEMENT_TIMEOUT}';"
                )
                finalized_dataset_ids = (
                    await _locked_finalized_retry_cleanup_dataset_ids(
                        selected_dataset_ids
                    )
                )
                if finalized_dataset_ids != selected_dataset_ids:
                    return []
                await _delete_endpoint_dataset_retry_state(selected_dataset_ids)
    except Exception:
        LOGGER.warning(
            "Provider Directory retry-state cleanup remains pending for %s",
            ",".join(selected_dataset_ids),
            exc_info=True,
        )
        return []
    return selected_dataset_ids


async def _is_provider_directory_corroboration_artifact_published(
    *,
    source_ids: list[str] | tuple[str, ...] | None,
    network_catalog_metrics: dict[str, Any],
    artifact_bundle: ProviderDirectoryArtifactBundle | None,
) -> bool:
    """Build corroboration from either live artifacts or prepared bundle stages."""
    if artifact_bundle is None:
        return await publish_provider_directory_address_corroboration_if_available(
            refresh_network_catalog=False,
            source_ids=source_ids,
        )
    schema = _schema()
    if not await _table_exists(schema, "entity_address_unified"):
        return False
    cleaned_source_ids = _clean_source_id_list(source_ids)
    with _provider_directory_artifact_relation_scope(
        artifact_bundle.relation_overrides
    ):
        publish_result = (
            await publish_provider_directory_address_corroboration_table(
                schema,
                refresh_network_catalog=False,
                source_ids=cleaned_source_ids,
                defer_cutover=True,
                network_catalog_metrics_override=network_catalog_metrics,
            )
        )
    _collect_provider_directory_artifact_stage(
        publish_result,
        artifact_bundle,
    )
    return True


async def _provider_directory_profile_scope_source_ids(
    schema: str,
    allowed_source_ids: set[str],
) -> list[str]:
    configured_source_ids = list(
        profile_artifact.configured_profile_source_ids()
    )
    source_rows = await db.all(
        profile_artifact.profile_scope_source_ids_sql(
            _qt(schema, ProviderDirectorySource.__tablename__)
        ),
        configured_source_ids=configured_source_ids,
    )
    return sorted(
        {
            source_id
            for source_row in source_rows
            if (
                source_id := _clean_text(
                    _pagination_checkpoint_row_mapping(source_row).get(
                        "source_id"
                    )
                )
            )
            and source_id in allowed_source_ids
        }
    )


async def _create_provider_directory_profile_indexes(
    schema: str,
    table_name: str,
    *,
    evidence: bool,
) -> None:
    for statement in profile_artifact.profile_index_statements(
        schema,
        table_name,
        evidence=evidence,
    ):
        await db.status(statement)


async def _rename_provider_directory_profile_indexes(
    schema: str,
    stage_table: str,
    *,
    target_table: str,
    evidence: bool,
) -> None:
    suffixes = (
        profile_artifact.PROFILE_EVIDENCE_INDEX_SUFFIXES
        if evidence
        else profile_artifact.PROFILE_INDEX_SUFFIXES
    )
    for suffix in suffixes:
        stage_index = profile_artifact.profile_index_name(
            stage_table,
            suffix,
        )
        target_index = profile_artifact.profile_index_name(
            target_table,
            suffix,
        )
        await db.status(
            f"ALTER INDEX {_unscoped_qt(schema, stage_index)} "
            f"RENAME TO {_q(target_index)};"
        )


async def _rename_provider_directory_profile_table_indexes(
    schema: str,
    stage_table: str,
) -> None:
    await _rename_provider_directory_profile_indexes(
        schema,
        stage_table,
        target_table=profile_artifact.PROFILE_TABLE,
        evidence=False,
    )


async def _rename_provider_directory_profile_evidence_indexes(
    schema: str,
    stage_table: str,
) -> None:
    await _rename_provider_directory_profile_indexes(
        schema,
        stage_table,
        target_table=profile_artifact.PROFILE_EVIDENCE_TABLE,
        evidence=True,
    )


async def _provider_directory_profile_stage_metrics(
    schema: str,
    evidence_stage: str,
    profile_stage: str,
    source_ids: list[str],
) -> dict[str, Any]:
    evidence_ref = _unscoped_qt(schema, evidence_stage)
    profile_ref = _unscoped_qt(schema, profile_stage)
    return {
        "enabled_source_ids": source_ids,
        "evidence_rows": int(
            await db.scalar(f"SELECT count(*) FROM {evidence_ref};") or 0
        ),
        "selected_evidence_rows": int(
            await db.scalar(
                f"""
                SELECT count(*)
                  FROM {evidence_ref}
                 WHERE source_id = ANY(CAST(:source_ids AS varchar[]));
                """,
                source_ids=source_ids,
            )
            or 0
        ),
        "profile_rows": int(
            await db.scalar(f"SELECT count(*) FROM {profile_ref};") or 0
        ),
    }


async def _remove_provider_directory_profile_stage_table(
    schema: str,
    stage_table: str,
) -> None:
    stage_ref = _unscoped_qt(schema, stage_table)
    try:
        await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
    except Exception:  # pragma: no cover - cleanup best effort
        LOGGER.warning(
            "Failed to clean Provider Directory profile stage %s",
            stage_ref,
            exc_info=True,
        )


@dataclass(frozen=True)
class _ProviderDirectoryProfileBuild:
    schema: str
    generation_id: str
    source_ids: tuple[str, ...]
    dataset_ids: tuple[str, ...]
    evidence_stage: str
    profile_stage: str


def _provider_directory_profile_build_ref(
    build: _ProviderDirectoryProfileBuild,
    table_name: str,
) -> str:
    return _unscoped_qt(build.schema, table_name)


def _logged_provider_directory_profile_stage_sql(stage_sql: str) -> str:
    """Render one profile stage as LOGGED from its initial creation."""
    unlogged_clause = "CREATE UNLOGGED TABLE"
    if stage_sql.count(unlogged_clause) != 1:
        raise RuntimeError("provider_directory_profile_stage_ddl_invalid")
    return stage_sql.replace(unlogged_clause, "CREATE TABLE", 1)


async def _resolve_provider_directory_profile_build(
    schema: str,
    run_id: str | None,
    dataset_fence: ProviderDirectoryArtifactDatasetFence,
) -> _ProviderDirectoryProfileBuild | None:
    selected_source_ids = await _provider_directory_profile_scope_source_ids(
        schema,
        {dataset.source_id for dataset in dataset_fence.datasets},
    )
    if not selected_source_ids:
        return None
    source_ids, dataset_ids = profile_artifact.profile_source_dataset_pairs(
        dataset_fence.datasets,
        selected_source_ids,
    )
    generation_id = (
        _clean_text(run_id)
        or "pdprofile_"
        + hashlib.sha1(
            "|".join(dataset_ids).encode("utf-8")
        ).hexdigest()[:32]
    )[:64]
    return _ProviderDirectoryProfileBuild(
        schema=schema,
        generation_id=generation_id,
        source_ids=tuple(source_ids),
        dataset_ids=tuple(dataset_ids),
        evidence_stage=profile_artifact.profile_evidence_stage_table_name(
            generation_id
        ),
        profile_stage=profile_artifact.profile_stage_table_name(generation_id),
    )


async def _create_provider_directory_profile_evidence_stage(
    build: _ProviderDirectoryProfileBuild,
    *,
    has_evidence_target: bool,
) -> None:
    evidence_stage_ref = _provider_directory_profile_build_ref(
        build,
        build.evidence_stage,
    )
    await db.status(
        _logged_provider_directory_profile_stage_sql(
            profile_artifact.profile_evidence_table_sql(
                build.schema,
                build.evidence_stage,
            )
        )
    )
    if has_evidence_target:
        await db.status(
            profile_artifact.copy_existing_evidence_sql(
                source_ref=_provider_directory_profile_build_ref(
                    build,
                    profile_artifact.PROFILE_EVIDENCE_TABLE,
                ),
                target_ref=evidence_stage_ref,
            ),
            source_ids=list(build.source_ids),
        )
    await db.status(
        profile_artifact.profile_evidence_insert_sql(
            target_ref=evidence_stage_ref,
            source_ref=_qt(
                build.schema,
                ProviderDirectorySource.__tablename__,
            ),
            practitioner_ref=_qt(
                build.schema,
                ProviderDirectoryPractitioner.__tablename__,
            ),
            role_ref=_qt(
                build.schema,
                ProviderDirectoryPractitionerRole.__tablename__,
            ),
            organization_ref=_qt(
                build.schema,
                ProviderDirectoryOrganization.__tablename__,
            ),
            service_ref=_qt(
                build.schema,
                ProviderDirectoryHealthcareService.__tablename__,
            ),
            endpoint_ref=_qt(
                build.schema,
                ProviderDirectoryEndpoint.__tablename__,
            ),
        ),
        source_ids=list(build.source_ids),
        dataset_ids=list(build.dataset_ids),
    )
    await _create_provider_directory_profile_indexes(
        build.schema,
        build.evidence_stage,
        evidence=True,
    )
    await db.status(f"ANALYZE {evidence_stage_ref};")


async def _create_provider_directory_profile_compact_stage(
    build: _ProviderDirectoryProfileBuild,
    *,
    has_existing_artifacts: bool,
) -> None:
    evidence_stage_ref = _provider_directory_profile_build_ref(
        build,
        build.evidence_stage,
    )
    profile_stage_ref = _provider_directory_profile_build_ref(
        build,
        build.profile_stage,
    )
    evidence_target_ref = _provider_directory_profile_build_ref(
        build,
        profile_artifact.PROFILE_EVIDENCE_TABLE,
    )
    await db.status(
        _logged_provider_directory_profile_stage_sql(
            profile_artifact.profile_table_sql(
                build.schema,
                build.profile_stage,
            )
        )
    )
    should_rebuild_all_profiles = not has_existing_artifacts
    if has_existing_artifacts:
        await db.status(
            profile_artifact.copy_unaffected_profiles_sql(
                profile_source_ref=_provider_directory_profile_build_ref(
                    build,
                    profile_artifact.PROFILE_TABLE,
                ),
                evidence_source_ref=evidence_target_ref,
                evidence_stage_ref=evidence_stage_ref,
                profile_stage_ref=profile_stage_ref,
            ),
            source_ids=list(build.source_ids),
        )
    await db.status(
        profile_artifact.profile_insert_sql(
            evidence_ref=evidence_stage_ref,
            target_ref=profile_stage_ref,
            old_evidence_ref=(
                evidence_target_ref if has_existing_artifacts else None
            ),
            rebuild_all=should_rebuild_all_profiles,
        ),
        source_ids=list(build.source_ids),
        generation_id=build.generation_id,
    )
    await _create_provider_directory_profile_indexes(
        build.schema,
        build.profile_stage,
        evidence=False,
    )
    await db.status(f"ANALYZE {profile_stage_ref};")


async def _prepare_provider_directory_profile_stages(
    build: _ProviderDirectoryProfileBuild,
    evidence_build_fence: ProviderDirectoryArtifactBuildFence,
    profile_build_fence: ProviderDirectoryArtifactBuildFence,
) -> tuple[
    ProviderDirectoryPreparedArtifactStage,
    ProviderDirectoryPreparedArtifactStage,
]:
    await _assert_provider_directory_logged_relation(
        build.schema,
        build.evidence_stage,
    )
    await _assert_provider_directory_logged_relation(
        build.schema,
        build.profile_stage,
    )
    return (
        ProviderDirectoryPreparedArtifactStage(
            schema=build.schema,
            stage_table=build.evidence_stage,
            target_relation=profile_artifact.PROFILE_EVIDENCE_TABLE,
            rename_stage_indexes=(
                _rename_provider_directory_profile_evidence_indexes
            ),
            build_fence=evidence_build_fence,
        ),
        ProviderDirectoryPreparedArtifactStage(
            schema=build.schema,
            stage_table=build.profile_stage,
            target_relation=profile_artifact.PROFILE_TABLE,
            rename_stage_indexes=(
                _rename_provider_directory_profile_table_indexes
            ),
            build_fence=profile_build_fence,
        ),
    )


async def _provider_directory_profile_metrics(
    build: _ProviderDirectoryProfileBuild,
    *,
    should_rebuild_all_profiles: bool,
) -> dict[str, Any]:
    metrics = await _provider_directory_profile_stage_metrics(
        build.schema,
        build.evidence_stage,
        build.profile_stage,
        list(build.source_ids),
    )
    metrics.update(
        {
            "generation_id": build.generation_id,
            "dataset_ids": sorted(set(build.dataset_ids)),
            "incremental": not should_rebuild_all_profiles,
        }
    )
    return metrics


async def _finalize_provider_directory_profile_stages(
    metrics: dict[str, Any],
    stages: tuple[
        ProviderDirectoryPreparedArtifactStage,
        ProviderDirectoryPreparedArtifactStage,
    ],
    *,
    defer_cutover: bool,
) -> dict[str, Any] | tuple[
    dict[str, Any],
    tuple[
        ProviderDirectoryPreparedArtifactStage,
        ProviderDirectoryPreparedArtifactStage,
    ],
]:
    if defer_cutover:
        return metrics, stages
    try:
        await _retry_provider_directory_artifact_bundle_promotion(stages)
    finally:
        for stage in reversed(stages):
            await _remove_provider_directory_artifact_stage(stage)
    return metrics


async def _has_provider_directory_profile_artifacts(schema: str) -> bool:
    has_evidence_target = await _table_exists(
        schema,
        profile_artifact.PROFILE_EVIDENCE_TABLE,
    )
    has_profile_target = await _table_exists(
        schema,
        profile_artifact.PROFILE_TABLE,
    )
    if has_evidence_target != has_profile_target:
        raise RuntimeError("provider_directory_profile_artifact_pair_incomplete")
    return has_evidence_target


async def _build_provider_directory_profile_stages(
    build: _ProviderDirectoryProfileBuild,
    evidence_build_fence: ProviderDirectoryArtifactBuildFence,
    profile_build_fence: ProviderDirectoryArtifactBuildFence,
) -> tuple[
    dict[str, Any],
    tuple[
        ProviderDirectoryPreparedArtifactStage,
        ProviderDirectoryPreparedArtifactStage,
    ],
]:
    has_existing_artifacts = await _has_provider_directory_profile_artifacts(
        build.schema
    )
    created_stage_tables: list[str] = []
    try:
        await _create_provider_directory_profile_evidence_stage(
            build,
            has_evidence_target=has_existing_artifacts,
        )
        created_stage_tables.append(build.evidence_stage)
        should_rebuild_all_profiles = not has_existing_artifacts
        await _create_provider_directory_profile_compact_stage(
            build,
            has_existing_artifacts=has_existing_artifacts,
        )
        created_stage_tables.append(build.profile_stage)
        metrics = await _provider_directory_profile_metrics(
            build,
            should_rebuild_all_profiles=should_rebuild_all_profiles,
        )
        stages = await _prepare_provider_directory_profile_stages(
            build,
            evidence_build_fence,
            profile_build_fence,
        )
        return metrics, stages
    except BaseException:
        for stage_table in reversed(created_stage_tables):
            await _remove_provider_directory_profile_stage_table(
                build.schema,
                stage_table,
            )
        raise


async def publish_provider_directory_profile(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    defer_cutover: bool = False,
) -> dict[str, Any] | tuple[
    dict[str, Any],
    tuple[
        ProviderDirectoryPreparedArtifactStage,
        ProviderDirectoryPreparedArtifactStage,
    ],
]:
    """Build source evidence and compact NPI profiles behind one atomic cutover."""
    schema = db_schema or _schema()
    dataset_fence = _PROVIDER_DIRECTORY_ARTIFACT_DATASET_FENCE.get()
    if dataset_fence is None:
        return {"skipped": True, "reason": "immutable_dataset_scope_required"}
    build = await _resolve_provider_directory_profile_build(
        schema,
        run_id,
        dataset_fence,
    )
    if build is None:
        return {
            "skipped": True,
            "reason": "no_profile_enabled_sources_in_scope",
        }
    async with contextlib.AsyncExitStack() as build_guards:
        evidence_build_fence = await build_guards.enter_async_context(
            _provider_directory_artifact_build_guard(
                schema,
                profile_artifact.PROFILE_EVIDENCE_TABLE,
            )
        )
        profile_build_fence = await build_guards.enter_async_context(
            _provider_directory_artifact_build_guard(
                schema,
                profile_artifact.PROFILE_TABLE,
            )
        )
        metrics, stages = await _build_provider_directory_profile_stages(
            build,
            evidence_build_fence,
            profile_build_fence,
        )
        return await _finalize_provider_directory_profile_stages(
            metrics,
            stages,
            defer_cutover=defer_cutover,
        )


async def _publish_provider_directory_profile_target(
    *,
    run_id: str | None,
    publish_artifacts_targets: set[str] | None,
    artifact_bundle: ProviderDirectoryArtifactBundle | None,
) -> tuple[dict[str, Any], str]:
    if not is_provider_directory_publish_target_enabled(
        publish_artifacts_targets,
        "profile",
    ):
        return (
            _provider_directory_publish_target_skipped(),
            "skipped Provider Directory doctor profile publish",
        )
    profile_options_by_name: dict[str, Any] = {"run_id": run_id}
    if artifact_bundle is not None:
        profile_options_by_name["defer_cutover"] = True
    profile_publish_result = await publish_provider_directory_profile(
        **profile_options_by_name,
    )
    profile_metrics = _collect_provider_directory_artifact_stage(
        profile_publish_result,
        artifact_bundle,
    )
    return (
        profile_metrics,
        "published Provider Directory doctor profiles; "
        f"rows={profile_metrics.get('profile_rows', 0)}",
    )


async def _publish_provider_directory_artifacts(
    *,
    run_id: str | None,
    metrics: dict[str, Any],
    seen_table: str | None = None,
    address_key_run_id: str | None = None,
    publish_scope_run_id: str | None | object = _PUBLISH_SCOPE_UNSET,
    source_ids: list[str] | tuple[str, ...] | None = None,
    publish_corroboration: bool = False,
    publish_artifacts_targets: set[str] | None = None,
) -> dict[str, Any]:
    """Publish provider directory artifacts for provider-directory serving."""
    artifact_bundle = _PROVIDER_DIRECTORY_ARTIFACT_BUNDLE.get()
    effective_publish_scope_run_id = (
        run_id if publish_scope_run_id is _PUBLISH_SCOPE_UNSET else publish_scope_run_id
    )
    metrics["publish_artifacts_targets"] = (
        sorted(publish_artifacts_targets) if publish_artifacts_targets is not None else "all"
    )
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=0,
        total=7,
        message="publishing Provider Directory address artifacts",
        metrics=metrics,
    )
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "location_contacts"):
        metrics["location_contacts_backfilled"] = await backfill_provider_directory_location_contacts()
        location_contacts_message = (
            "backfilled Provider Directory location contacts; "
            f"rows={metrics['location_contacts_backfilled'].get('location_contact_rows_updated', 0)}"
        )
    else:
        metrics["location_contacts_backfilled"] = _provider_directory_publish_target_skipped()
        location_contacts_message = "skipped Provider Directory location contact backfill"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=1,
        total=7,
        message=location_contacts_message,
        metrics=metrics,
    )
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "location_coordinates"):
        metrics["location_coordinates_backfilled"] = await backfill_provider_directory_location_coordinates(
            run_id=address_key_run_id, source_ids=source_ids, seen_table=seen_table,
        )
        location_coordinates_message = (
            "backfilled Provider Directory location coordinates; "
            f"rows={metrics['location_coordinates_backfilled']}"
        )
    else:
        metrics["location_coordinates_backfilled"] = _provider_directory_publish_target_skipped()
        location_coordinates_message = "skipped Provider Directory location coordinate backfill"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=2,
        total=7,
        message=location_coordinates_message,
        metrics=metrics,
    )
    if seen_table:
        await _prepare_provider_directory_import_seen_stage_lookup(seen_table)
    should_backfill_resource_id_npis = any(
        is_provider_directory_publish_target_enabled(publish_artifacts_targets, artifact_target_name)
        for artifact_target_name in (
            "resource_id_npis",
            "location_archive",
            "address_overlay",
            "profile",
            "corroboration",
        )
    )
    if should_backfill_resource_id_npis:
        resource_id_npi_backfill_run_id = address_key_run_id if address_key_run_id is not None else None
        metrics["resource_id_npis_backfilled"] = await backfill_provider_directory_resource_id_npis(
            run_id=resource_id_npi_backfill_run_id,
            source_ids=source_ids,
            seen_table=seen_table,
        )
    else:
        metrics["resource_id_npis_backfilled"] = _provider_directory_publish_target_skipped()
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "location_address_keys"):
        metrics["location_address_keys_stamped"] = await publish_provider_directory_location_address_keys(
            run_id=address_key_run_id, source_ids=source_ids, seen_table=seen_table,
        )
        location_address_keys_message = (
            "stamped Provider Directory location address keys; "
            f"rows={metrics['location_address_keys_stamped']}"
        )
    else:
        metrics["location_address_keys_stamped"] = _provider_directory_publish_target_skipped()
        location_address_keys_message = "skipped Provider Directory location address key stamping"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=3,
        total=7,
        message=location_address_keys_message,
        metrics=metrics,
    )
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "location_archive"):
        metrics["location_archive"] = await publish_provider_directory_location_archive(
            run_id=effective_publish_scope_run_id, source_ids=source_ids, seen_table=seen_table,
        )
    else:
        metrics["location_archive"] = _provider_directory_publish_target_skipped()
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "address_overlay"):
        address_overlay_options_by_name: dict[str, Any] = {
            "run_id": effective_publish_scope_run_id,
            "source_ids": source_ids,
        }
        if artifact_bundle is not None:
            address_overlay_options_by_name["defer_cutover"] = True
        address_overlay_result = await publish_provider_directory_address_overlay(
            **address_overlay_options_by_name,
        )
        metrics["address_overlay"] = _collect_provider_directory_artifact_stage(
            address_overlay_result,
            artifact_bundle,
        )
    else:
        metrics["address_overlay"] = _provider_directory_publish_target_skipped()
    address_artifact_message = (
        "published Provider Directory locations to address archive; "
        f"inserted={metrics['location_archive'].get('inserted', 0)} "
        f"updated={metrics['location_archive'].get('provenance_updates', 0)}"
    )
    if (
        not is_provider_directory_publish_target_enabled(publish_artifacts_targets, "location_archive")
        and not is_provider_directory_publish_target_enabled(publish_artifacts_targets, "address_overlay")
    ):
        address_artifact_message = "skipped Provider Directory location archive and address overlay publish"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=4,
        total=7,
        message=address_artifact_message,
        metrics=metrics,
    )
    metrics["profile"], profile_message = (
        await _publish_provider_directory_profile_target(
            run_id=run_id,
            publish_artifacts_targets=publish_artifacts_targets,
            artifact_bundle=artifact_bundle,
        )
    )
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=5,
        total=7,
        message=profile_message,
        metrics=metrics,
    )
    if is_provider_directory_publish_target_enabled(publish_artifacts_targets, "network_catalog"):
        network_catalog_options_by_name: dict[str, Any] = {
            "run_id": effective_publish_scope_run_id,
            "source_ids": source_ids,
        }
        if artifact_bundle is not None:
            network_catalog_options_by_name["defer_cutover"] = True
        network_catalog_result = await publish_provider_directory_network_catalog(
            **network_catalog_options_by_name,
        )
        metrics["network_catalog"] = _collect_provider_directory_artifact_stage(
            network_catalog_result,
            artifact_bundle,
        )
        network_catalog_message = (
            "published Provider Directory network catalog; "
            f"rows={metrics['network_catalog'].get('rows', 0)}"
        )
    else:
        metrics["network_catalog"] = _provider_directory_publish_target_skipped()
        network_catalog_message = "skipped Provider Directory network catalog publish"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=6,
        total=7,
        message=network_catalog_message,
        metrics=metrics,
    )
    metrics["publish_corroboration"] = publish_corroboration
    if publish_corroboration and is_provider_directory_publish_target_enabled(
        publish_artifacts_targets,
        "corroboration",
    ):
        metrics["ptg_corroboration_view_published"] = (
            await _is_provider_directory_corroboration_artifact_published(
                source_ids=source_ids,
                network_catalog_metrics=metrics["network_catalog"],
                artifact_bundle=artifact_bundle,
            )
        )
        message = "published Provider Directory PTG corroboration artifacts"
    elif publish_corroboration:
        metrics["ptg_corroboration_view_published"] = False
        metrics["ptg_corroboration_view_skipped"] = _provider_directory_publish_target_skipped()
        message = "skipped Provider Directory PTG corroboration artifacts"
    else:
        metrics["ptg_corroboration_view_published"] = False
        metrics["ptg_corroboration_view_skipped"] = {
            "reason": "publish_corroboration_disabled",
        }
        message = "skipped Provider Directory PTG corroboration artifacts"
    await _mark_provider_directory_progress(
        run_id,
        phase="provider-directory publishing artifacts",
        done=7,
        total=7,
        message=message,
        metrics=metrics,
    )
    return metrics

def _provider_directory_location_archive_stage_table_name(run_id: str | None = None) -> str:
    raw = run_id or f"{os.getpid()}_{time.time_ns()}"
    digest = hashlib.sha1(raw.encode("utf-8", errors="ignore")).hexdigest()[:16]
    return f"{PROVIDER_DIRECTORY_ADDRESS_ARCHIVE_STAGE_PREFIX}_{digest}"


def provider_directory_location_archive_stage_sql(
    db_schema: str | None = None,
    stage_table: str | None = None,
    *,
    run_id: str | None = None, source_ids: list[str] | tuple[str, ...] | None = None,
    seen_table: str | None = None,
) -> str:
    """Build SQL for provider directory location archive stage."""
    schema = db_schema or _schema()
    stage = stage_table or _provider_directory_location_archive_stage_table_name()
    stage_ref = _qt(schema, stage)
    location_ref = _qt(schema, "provider_directory_location")
    organization_ref = _qt(schema, "provider_directory_organization")
    uuid_re = r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$"
    location_scope_clauses: list[str] = []
    organization_scope_clauses: list[str] = []
    if seen_table:
        seen_ref = _qt(schema, seen_table)
        seen_run_filter = "AND seen.run_id = CAST(:run_id AS varchar)" if run_id is not None else ""
        location_scope_clauses.append(
            f"""EXISTS (
                SELECT 1
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = 'Location'
                   {seen_run_filter}
                   AND seen.source_id = loc.source_id
                   AND seen.resource_id = loc.resource_id
            )"""
        )
        organization_scope_clauses.append(
            f"""EXISTS (
                SELECT 1
                  FROM {seen_ref} AS seen
                 WHERE seen.resource_type = 'Organization'
                   {seen_run_filter}
                   AND seen.source_id = organization.source_id
                   AND seen.resource_id = organization.resource_id
            )"""
        )
    elif run_id is not None:
        location_scope_clauses.append("loc.last_seen_run_id = CAST(:run_id AS varchar)")
        organization_scope_clauses.append("organization.last_seen_run_id = CAST(:run_id AS varchar)")
    if source_ids:
        location_scope_clauses.append("loc.source_id = ANY(CAST(:source_ids AS varchar[]))")
        organization_scope_clauses.append("organization.source_id = ANY(CAST(:source_ids AS varchar[]))")
    location_scope_sql = "".join(f"\n           AND {clause}" for clause in location_scope_clauses)
    organization_scope_sql = "".join(f"\n           AND {clause}" for clause in organization_scope_clauses)
    return f"""
    CREATE UNLOGGED TABLE {stage_ref} AS
    WITH eligible AS (
        SELECT
            loc.address_key::uuid AS address_key,
            NULLIF(BTRIM(loc.first_line), '')::text AS first_line,
            NULLIF(BTRIM(loc.second_line), '')::text AS second_line,
            NULLIF(BTRIM(loc.city_name), '')::text AS city_name,
            NULLIF(BTRIM(COALESCE(NULLIF(loc.state_name, ''), loc.state_code)), '')::text AS state_name,
            NULLIF(BTRIM(COALESCE(NULLIF(loc.postal_code, ''), loc.zip5)), '')::text AS postal_code,
            COALESCE(NULLIF(BTRIM(loc.country_code), ''), 'US')::text AS country_code,
            loc.updated_at,
            loc.source_id,
            loc.resource_id
          FROM {location_ref} AS loc
         WHERE loc.address_key ~* '{uuid_re}'
           AND NULLIF(BTRIM(COALESCE(NULLIF(loc.state_name, ''), loc.state_code)), '') IS NOT NULL
           AND UPPER(NULLIF(BTRIM(COALESCE(NULLIF(loc.state_name, ''), loc.state_code)), ''))
                NOT IN ('UN', 'XX', 'ZZ', 'NULL', 'N/A')
           AND NULLIF(BTRIM(COALESCE(NULLIF(loc.postal_code, ''), loc.zip5)), '') IS NOT NULL
           AND (
                NULLIF(BTRIM(loc.first_line), '') IS NOT NULL
             OR NULLIF(BTRIM(loc.city_name), '') IS NOT NULL
           )
           AND COALESCE(
                NULLIF(
                    UPPER(regexp_replace(COALESCE(NULLIF(loc.country_code, ''), 'US'), '[^A-Z0-9]', '', 'g')),
                    ''
                ),
                'US'
           ) IN ('US', 'USA', 'UNITEDSTATES', 'UNITEDSTATESOFAMERICA', '840', '001')
           {location_scope_sql}
        UNION ALL
        SELECT
            {_q(schema)}.addr_key_v1(
                NULLIF(BTRIM(addr.value->'line'->>0), ''),
                NULLIF(BTRIM(addr.value->'line'->>1), ''),
                NULLIF(BTRIM(addr.value->>'city'), ''),
                NULLIF(BTRIM(addr.value->>'state'), ''),
                NULLIF(BTRIM(addr.value->>'postalCode'), ''),
                COALESCE(NULLIF(BTRIM(addr.value->>'country'), ''), 'US')
            ) AS address_key,
            NULLIF(BTRIM(addr.value->'line'->>0), '')::text AS first_line,
            NULLIF(BTRIM(addr.value->'line'->>1), '')::text AS second_line,
            NULLIF(BTRIM(addr.value->>'city'), '')::text AS city_name,
            NULLIF(BTRIM(addr.value->>'state'), '')::text AS state_name,
            NULLIF(BTRIM(addr.value->>'postalCode'), '')::text AS postal_code,
            COALESCE(NULLIF(BTRIM(addr.value->>'country'), ''), 'US')::text AS country_code,
            organization.updated_at,
            organization.source_id,
            organization.resource_id
          FROM {organization_ref} AS organization
          JOIN LATERAL jsonb_array_elements(
                COALESCE(organization.address_json::jsonb, '[]'::jsonb)
          ) WITH ORDINALITY AS addr(value, ordinal) ON TRUE
         WHERE organization.npi BETWEEN 1000000000 AND 9999999999
           AND organization.active IS DISTINCT FROM false
           AND NULLIF(BTRIM(addr.value->'line'->>0), '') IS NOT NULL
           AND NULLIF(BTRIM(addr.value->>'postalCode'), '') IS NOT NULL
           AND (
                NULLIF(BTRIM(addr.value->'line'->>0), '') IS NOT NULL
             OR NULLIF(BTRIM(addr.value->>'city'), '') IS NOT NULL
           )
           AND NULLIF(BTRIM(addr.value->>'state'), '') IS NOT NULL
           AND UPPER(NULLIF(BTRIM(addr.value->>'state'), ''))
                NOT IN ('UN', 'XX', 'ZZ', 'NULL', 'N/A')
           AND COALESCE(
                NULLIF(
                    UPPER(regexp_replace(COALESCE(NULLIF(addr.value->>'country', ''), 'US'), '[^A-Z0-9]', '', 'g')),
                    ''
                ),
                'US'
           ) IN ('US', 'USA', 'UNITEDSTATES', 'UNITEDSTATESOFAMERICA', '840', '001')
           {organization_scope_sql}
    )
    SELECT DISTINCT ON (address_key)
        address_key,
        first_line,
        second_line,
        city_name,
        state_name,
        postal_code,
        country_code
      FROM eligible
     WHERE address_key IS NOT NULL
     ORDER BY
        address_key,
        first_line IS NULL,
        length(COALESCE(first_line, '')) DESC,
        city_name IS NULL,
        length(COALESCE(city_name, '')) DESC,
        updated_at DESC NULLS LAST,
        source_id,
        resource_id;
    """


def _provider_directory_openaddresses_archive_backfill_sql(schema: str, stage_table: str) -> str:
    """Build an exact-key, ambiguity-guarded OpenAddresses archive update."""
    archive_ref = _qt(schema, "address_archive_v2")
    openaddresses_ref = _qt(schema, PROVIDER_DIRECTORY_OPENADDRESSES_TABLE)
    stage_ref = _qt(schema, stage_table)
    geo_source_type = _qt(schema, "address_archive_geo_source")
    return f"""
        WITH target_keys AS MATERIALIZED (
            SELECT archive.address_key
              FROM {stage_ref} AS stage_row
              JOIN {archive_ref} AS archive
                ON archive.address_key = stage_row.address_key
             WHERE archive.merged_into IS NULL
               AND archive.lat IS NULL
               AND archive.long IS NULL
        ),
        winners AS (
            SELECT target.address_key, candidate.*
              FROM target_keys AS target
              JOIN LATERAL (
                    SELECT avg(oa.lat)::numeric(11,8) AS lat,
                           avg(oa.long)::numeric(11,8) AS long,
                           min(oa.formatted_address) AS formatted_address,
                           min(oa.feature_id) AS place_id,
                           NULLIF(max(NULLIF(oa.accuracy, '')), '') AS accuracy
                      FROM {openaddresses_ref} AS oa
                     WHERE oa.address_key = target.address_key
                       AND ((oa.lat BETWEEN 24 AND 50 AND oa.long BETWEEN -125 AND -66)
                         OR (oa.lat BETWEEN 51 AND 72 AND oa.long BETWEEN -180 AND -129)
                         OR (oa.lat BETWEEN 18 AND 23 AND oa.long BETWEEN -161 AND -154)
                         OR (oa.lat BETWEEN 17 AND 19 AND oa.long BETWEEN -68 AND -64)
                         OR (oa.lat BETWEEN 13 AND 16 AND oa.long BETWEEN 144 AND 146)
                         OR (oa.lat BETWEEN -15 AND -10 AND oa.long BETWEEN -171 AND -168))
                    HAVING count(*) > 0
                       AND (count(*) = 1 OR (
                            max(oa.lat) - min(oa.lat) <= :coord_tolerance
                        AND max(oa.long) - min(oa.long) <= :coord_tolerance
                       ))
              ) AS candidate ON TRUE
        )
        UPDATE {archive_ref} AS archive
           SET lat = winners.lat,
               long = winners.long,
               formatted_address = COALESCE(archive.formatted_address, winners.formatted_address),
               place_id = COALESCE(archive.place_id, winners.place_id),
               geo_source = 'openaddresses'::{geo_source_type},
               geocode_source = 'openaddresses_address_key',
               geocode_quality = COALESCE(winners.accuracy, 'address_key_exact'),
               geocoded_at = now()
          FROM winners
         WHERE archive.address_key = winners.address_key
           AND archive.merged_into IS NULL
           AND archive.lat IS NULL
           AND archive.long IS NULL;
    """


async def _backfill_archive_openaddresses_coordinates(
    schema: str,
    stage_table: str,
) -> int:
    """Fill null archive coordinates for staged FHIR keys from safe OA matches."""
    if not await _table_exists(schema, PROVIDER_DIRECTORY_OPENADDRESSES_TABLE):
        return 0
    parsed_tolerance = _parse_coordinate_number(
        os.getenv("HLTHPRT_OPENADDRESSES_DUPLICATE_COORD_TOLERANCE")
    )
    coordinate_tolerance = (
        parsed_tolerance
        if parsed_tolerance is not None and parsed_tolerance >= 0
        else DEFAULT_PROVIDER_DIRECTORY_OPENADDRESSES_COORD_TOLERANCE
    )
    return _coerce_rowcount(
        await db.status(
            _provider_directory_openaddresses_archive_backfill_sql(schema, stage_table),
            coord_tolerance=coordinate_tolerance,
        )
    )


async def publish_provider_directory_location_archive(
    db_schema: str | None = None,
    *,
    run_id: str | None = None, source_ids: list[str] | tuple[str, ...] | None = None,
    stage_table: str | None = None,
    seen_table: str | None = None,
) -> dict[str, Any]:
    """Publish provider directory location archive for provider-directory serving."""
    schema = db_schema or _schema()
    if not await _address_canon_functions_available(schema):
        return {"skipped": True, "reason": "canonical_functions_unavailable"}
    if not await _table_exists(schema, "address_archive_v2"):
        return {"skipped": True, "reason": "address_archive_v2_unavailable"}
    if not await _table_exists(schema, "provider_directory_location"):
        return {"skipped": True, "reason": "provider_directory_location_unavailable"}
    stage = stage_table or _provider_directory_location_archive_stage_table_name(run_id)
    await db.status(f"DROP TABLE IF EXISTS {_qt(schema, stage)};")
    try:
        await db.status(
            provider_directory_location_archive_stage_sql(
                schema,
                stage,
                run_id=run_id, source_ids=source_ids,
                seen_table=seen_table,
            ),
            **(({"run_id": run_id} if run_id is not None else {}) | ({"source_ids": list(source_ids)} if source_ids else {})),
        )
        await db.status(f"ANALYZE {_qt(schema, stage)};")
        async with _provider_directory_active_artifact_dataset_transaction():
            stats = await resolve_into_archive(
                stage,
                {
                    "first_line": "first_line",
                    "second_line": "second_line",
                    "city": "city_name",
                    "state": "state_name",
                    "zip": "postal_code",
                    "country": "COALESCE(NULLIF(country_code, ''), 'US')",
                },
                source_bit=PROVIDER_DIRECTORY_ADDRESS_ARCHIVE_SOURCE_BIT,
                priority=PROVIDER_DIRECTORY_ADDRESS_ARCHIVE_PRIORITY,
                schema=schema,
            )
            archive_metric_dict = dict(stats.__dict__)
            archive_metric_dict["openaddresses_coordinate_backfill_rows"] = (
                await _backfill_archive_openaddresses_coordinates(
                    schema,
                    stage,
                )
            )
        return archive_metric_dict
    finally:
        await db.status(f"DROP TABLE IF EXISTS {_qt(schema, stage)};")


def _network_catalog_stage_table_name(run_id: str | None = None) -> str:
    raw_identifier = f"{run_id or 'full'}:{os.getpid()}:{time.time_ns()}:{os.urandom(8).hex()}"
    digest = hashlib.sha1(raw_identifier.encode("utf-8", errors="ignore")).hexdigest()[:16]
    return f"{PROVIDER_DIRECTORY_NETWORK_CATALOG_STAGE_PREFIX}_{digest}"


def _provider_directory_network_catalog_columns() -> tuple[str, ...]:
    return (
        "source_id",
        "network_resource_id",
        "provider_directory_network_name",
        "provider_directory_network_key",
        "provider_directory_issuer_key",
        "provider_directory_issuer_network_match_key",
        "aliases",
        "refs",
        "source_resource_counts",
        "insurance_plan_ref_count",
        "practitioner_role_ref_count",
        "organization_affiliation_ref_count",
        "distinct_ref_count",
        "source_org_name",
        "source_plan_name",
        "canonical_api_base",
        "observed_at",
        "published_at",
    )


def provider_directory_network_catalog_table_sql(
    db_schema: str | None = None,
    table_name: str | None = None,
) -> str:
    """Create the compact Provider Directory network catalog relation."""
    schema = db_schema if db_schema is not None else _schema()
    table_ref = _qt(schema, table_name or PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)
    return f"""
    CREATE TABLE IF NOT EXISTS {table_ref} (
        source_id varchar(64) NOT NULL,
        network_resource_id varchar(256) NOT NULL,
        provider_directory_network_name varchar(512) NOT NULL,
        provider_directory_network_key varchar NOT NULL,
        provider_directory_issuer_key varchar,
        provider_directory_issuer_network_match_key varchar,
        aliases jsonb NOT NULL DEFAULT '[]'::jsonb,
        refs jsonb NOT NULL DEFAULT '[]'::jsonb,
        source_resource_counts jsonb NOT NULL DEFAULT '{{}}'::jsonb,
        insurance_plan_ref_count bigint NOT NULL DEFAULT 0,
        practitioner_role_ref_count bigint NOT NULL DEFAULT 0,
        organization_affiliation_ref_count bigint NOT NULL DEFAULT 0,
        distinct_ref_count bigint NOT NULL DEFAULT 0,
        source_org_name varchar(256),
        source_plan_name varchar(512),
        canonical_api_base text,
        observed_at timestamp,
        published_at timestamp NOT NULL DEFAULT now(),
        PRIMARY KEY (source_id, network_resource_id)
    );
    """


async def _ensure_provider_directory_network_catalog_table(schema: str) -> None:
    await db.status(provider_directory_network_catalog_table_sql(schema))
    await _create_provider_directory_network_catalog_indexes(
        schema,
        PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE,
    )


async def _provider_directory_network_catalog_has_rows(schema: str) -> bool:
    return bool(
        await db.scalar(
            f"""
            SELECT EXISTS (
                SELECT 1
                  FROM {_qt(schema, PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)}
                 LIMIT 1
            );
            """
        )
    )


async def _ensure_provider_directory_network_catalog_populated(schema: str) -> dict[str, Any]:
    await _ensure_provider_directory_network_catalog_table(schema)
    missing_reason = await _network_catalog_missing_requirement(schema)
    relation = _qt(schema, PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)
    if missing_reason:
        return {
            "skipped": True,
            "reason": missing_reason,
            "relation": relation,
        }
    if await _provider_directory_network_catalog_has_rows(schema):
        return {
            "published": False,
            "reason": "already_populated",
            "relation": relation,
        }
    return await publish_provider_directory_network_catalog(schema)


def _network_catalog_index_name(table_name: str, suffix: str) -> str:
    return _bounded_identifier(f"{table_name}_{suffix}")


async def _create_provider_directory_network_catalog_indexes(schema: str, table_name: str) -> None:
    table_ref = _qt(schema, table_name)
    statements = (
        f"""
        CREATE UNIQUE INDEX IF NOT EXISTS {_q(_network_catalog_index_name(table_name, "source_network_idx"))}
            ON {table_ref} (source_id, network_resource_id);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(_network_catalog_index_name(table_name, "source_idx"))}
            ON {table_ref} (source_id);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(_network_catalog_index_name(table_name, "network_key_idx"))}
            ON {table_ref} (provider_directory_network_key);
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(_network_catalog_index_name(table_name, "issuer_network_key_idx"))}
            ON {table_ref} (provider_directory_issuer_network_match_key)
         WHERE provider_directory_issuer_network_match_key IS NOT NULL;
        """,
        f"""
        CREATE INDEX IF NOT EXISTS {_q(_network_catalog_index_name(table_name, "name_idx"))}
            ON {table_ref} (provider_directory_network_name);
        """,
    )
    for statement in statements:
        await db.status(statement)


async def _rename_network_catalog_stage_indexes(schema: str, stage_table: str) -> None:
    for suffix in PROVIDER_DIRECTORY_NETWORK_CATALOG_INDEX_SUFFIXES:
        stage_index_name = _network_catalog_index_name(stage_table, suffix)
        target_index_name = _network_catalog_index_name(PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE, suffix)
        if stage_index_name == target_index_name:
            continue
        await db.status(
            f"ALTER INDEX IF EXISTS {_qt(schema, stage_index_name)} RENAME TO {_q(target_index_name)};"
        )


PROVIDER_DIRECTORY_NETWORK_CATALOG_REQUIRED_TABLES = (
    "provider_directory_source",
    "provider_directory_insurance_plan",
    "provider_directory_practitioner_role",
    "provider_directory_organization_affiliation",
    "provider_directory_organization",
)


async def _network_catalog_missing_requirement(schema: str) -> str | None:
    for table_name in PROVIDER_DIRECTORY_NETWORK_CATALOG_REQUIRED_TABLES:
        if not await _table_exists(schema, table_name):
            return f"{table_name}_unavailable"
    return None


async def _network_catalog_scope_sources(
    schema: str,
    *,
    run_id: str | None,
    source_ids: list[str] | tuple[str, ...] | None,
) -> list[str]:
    cleaned = _clean_source_id_list(source_ids)
    if cleaned or not run_id:
        return cleaned
    rows = await db.all(
        f"""
        SELECT DISTINCT source_id
          FROM (
                SELECT source_id
                  FROM {_qt(schema, "provider_directory_insurance_plan")}
                 WHERE last_seen_run_id = :run_id
                   AND jsonb_array_length(COALESCE(network_refs::jsonb, '[]'::jsonb)) > 0
                UNION
                SELECT source_id
                  FROM {_qt(schema, "provider_directory_practitioner_role")}
                 WHERE last_seen_run_id = :run_id
                   AND jsonb_array_length(COALESCE(network_refs::jsonb, '[]'::jsonb)) > 0
                UNION
                SELECT source_id
                  FROM {_qt(schema, "provider_directory_organization_affiliation")}
                 WHERE last_seen_run_id = :run_id
                   AND jsonb_array_length(COALESCE(network_refs::jsonb, '[]'::jsonb)) > 0
          ) AS scoped
         WHERE source_id IS NOT NULL
         ORDER BY source_id;
        """,
        run_id=run_id,
    )
    return _clean_source_id_list([row[0] for row in rows])


def _provider_directory_network_catalog_scope_filter(
    alias: str,
    *,
    run_id: str | None,
    source_ids: list[str] | tuple[str, ...] | None,
) -> str:
    clauses: list[str] = []
    if run_id:
        clauses.append(f"{alias}.last_seen_run_id = CAST(:run_id AS varchar)")
    if source_ids:
        clauses.append(f"{alias}.source_id = ANY(CAST(:source_ids AS varchar[]))")
    return "".join(f"\n             AND {clause}" for clause in clauses)


def provider_directory_network_catalog_insert_sql(
    db_schema: str | None = None,
    stage_table: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
) -> str:
    """Build the scoped insert for resolved Provider Directory network Organizations."""
    schema = db_schema if db_schema is not None else _schema()
    stage_ref = _qt(schema, stage_table or _network_catalog_stage_table_name(run_id))
    ref_resource_id_expr = _sql_reference_resource_id("refs_raw.network_ref", "Organization")
    insurance_plan_scope = _provider_directory_network_catalog_scope_filter(
        "insurance_plan",
        run_id=run_id,
        source_ids=source_ids,
    )
    practitioner_role_scope = _provider_directory_network_catalog_scope_filter(
        "role",
        run_id=run_id,
        source_ids=source_ids,
    )
    affiliation_scope = _provider_directory_network_catalog_scope_filter(
        "affiliation",
        run_id=run_id,
        source_ids=source_ids,
    )
    return f"""
    INSERT INTO {stage_ref} ({", ".join(_provider_directory_network_catalog_columns())})
    WITH refs_raw AS MATERIALIZED (
        SELECT
            insurance_plan.source_id::varchar AS source_id,
            'InsurancePlan'::varchar AS source_resource_type,
            insurance_plan.resource_id::varchar AS source_resource_id,
            network_ref.value::varchar AS network_ref,
            insurance_plan.last_seen_run_id::varchar AS last_seen_run_id,
            insurance_plan.observed_at AS source_observed_at,
            insurance_plan.updated_at AS source_updated_at
          FROM {_qt(schema, "provider_directory_insurance_plan")} AS insurance_plan
         CROSS JOIN LATERAL jsonb_array_elements_text(
                COALESCE(insurance_plan.network_refs::jsonb, '[]'::jsonb)
         ) AS network_ref(value)
         WHERE NULLIF(BTRIM(network_ref.value), '') IS NOT NULL
           {insurance_plan_scope}
        UNION ALL
        SELECT
            role.source_id::varchar AS source_id,
            'PractitionerRole'::varchar AS source_resource_type,
            role.resource_id::varchar AS source_resource_id,
            network_ref.value::varchar AS network_ref,
            role.last_seen_run_id::varchar AS last_seen_run_id,
            role.observed_at AS source_observed_at,
            role.updated_at AS source_updated_at
          FROM {_qt(schema, "provider_directory_practitioner_role")} AS role
         CROSS JOIN LATERAL jsonb_array_elements_text(
                COALESCE(role.network_refs::jsonb, '[]'::jsonb)
         ) AS network_ref(value)
         WHERE role.active IS DISTINCT FROM false
           AND NULLIF(BTRIM(network_ref.value), '') IS NOT NULL
           {practitioner_role_scope}
        UNION ALL
        SELECT
            affiliation.source_id::varchar AS source_id,
            'OrganizationAffiliation'::varchar AS source_resource_type,
            affiliation.resource_id::varchar AS source_resource_id,
            network_ref.value::varchar AS network_ref,
            affiliation.last_seen_run_id::varchar AS last_seen_run_id,
            affiliation.observed_at AS source_observed_at,
            affiliation.updated_at AS source_updated_at
          FROM {_qt(schema, "provider_directory_organization_affiliation")} AS affiliation
         CROSS JOIN LATERAL jsonb_array_elements_text(
                COALESCE(affiliation.network_refs::jsonb, '[]'::jsonb)
         ) AS network_ref(value)
         WHERE affiliation.active IS DISTINCT FROM false
           AND NULLIF(BTRIM(network_ref.value), '') IS NOT NULL
           {affiliation_scope}
    ), refs AS MATERIALIZED (
        SELECT
            refs_raw.source_id,
            refs_raw.source_resource_type,
            refs_raw.source_resource_id,
            refs_raw.network_ref,
            {ref_resource_id_expr}::varchar AS network_resource_id,
            refs_raw.last_seen_run_id,
            refs_raw.source_observed_at,
            refs_raw.source_updated_at
          FROM refs_raw
         WHERE NULLIF(BTRIM(refs_raw.network_ref), '') IS NOT NULL
    ), joined AS MATERIALIZED (
        SELECT
            refs.source_id,
            refs.source_resource_type,
            refs.source_resource_id,
            refs.network_ref,
            refs.network_resource_id,
            refs.last_seen_run_id,
            refs.source_observed_at,
            refs.source_updated_at,
            NULLIF(BTRIM(network_org.name), '')::varchar AS provider_directory_network_name,
            COALESCE(network_org.aliases::jsonb, '[]'::jsonb) AS aliases,
            NULLIF(regexp_replace(lower(COALESCE(network_org.name, '')), '[^a-z0-9]+', '', 'g'), '')
                AS provider_directory_network_key,
            NULLIF(regexp_replace(lower(COALESCE(NULLIF(src.org_name, ''), src.plan_name, '')), '[^a-z0-9]+', '', 'g'), '')
                AS provider_directory_issuer_key,
            src.org_name::varchar AS source_org_name,
            src.plan_name::varchar AS source_plan_name,
            src.canonical_api_base::text AS canonical_api_base,
            GREATEST(
                COALESCE(refs.source_observed_at, TIMESTAMP 'epoch'),
                COALESCE(refs.source_updated_at, TIMESTAMP 'epoch'),
                COALESCE(network_org.observed_at, TIMESTAMP 'epoch'),
                COALESCE(network_org.updated_at, TIMESTAMP 'epoch'),
                COALESCE(src.updated_at, TIMESTAMP 'epoch')
            ) AS observed_at
          FROM refs
          JOIN {_qt(schema, "provider_directory_organization")} AS network_org
            ON network_org.source_id = refs.source_id
           AND network_org.resource_id = refs.network_resource_id
          JOIN {_qt(schema, "provider_directory_source")} AS src
            ON src.source_id = refs.source_id
         WHERE refs.network_resource_id IS NOT NULL
           AND network_org.active IS DISTINCT FROM false
           AND NULLIF(BTRIM(network_org.name), '') IS NOT NULL
    ), keyed AS MATERIALIZED (
        SELECT
            joined.*,
            CASE
                WHEN joined.provider_directory_issuer_key IS NOT NULL
                 AND joined.provider_directory_network_key IS NOT NULL
                    THEN joined.provider_directory_issuer_key || ':' || joined.provider_directory_network_key
                ELSE NULL
            END::varchar AS provider_directory_issuer_network_match_key
          FROM joined
         WHERE joined.provider_directory_network_key IS NOT NULL
    )
    SELECT
        keyed.source_id,
        keyed.network_resource_id,
        keyed.provider_directory_network_name,
        keyed.provider_directory_network_key,
        keyed.provider_directory_issuer_key,
        keyed.provider_directory_issuer_network_match_key,
        keyed.aliases,
        COALESCE(
            jsonb_agg(
                DISTINCT jsonb_build_object(
                    'resource_type', keyed.source_resource_type,
                    'resource_id', keyed.source_resource_id,
                    'ref', keyed.network_ref,
                    'last_seen_run_id', keyed.last_seen_run_id
                )
            ),
            '[]'::jsonb
        ) AS refs,
        jsonb_build_object(
            'InsurancePlan', COUNT(DISTINCT keyed.source_resource_id)
                FILTER (WHERE keyed.source_resource_type = 'InsurancePlan'),
            'PractitionerRole', COUNT(DISTINCT keyed.source_resource_id)
                FILTER (WHERE keyed.source_resource_type = 'PractitionerRole'),
            'OrganizationAffiliation', COUNT(DISTINCT keyed.source_resource_id)
                FILTER (WHERE keyed.source_resource_type = 'OrganizationAffiliation')
        ) AS source_resource_counts,
        (COUNT(DISTINCT keyed.source_resource_id)
            FILTER (WHERE keyed.source_resource_type = 'InsurancePlan'))::bigint
            AS insurance_plan_ref_count,
        (COUNT(DISTINCT keyed.source_resource_id)
            FILTER (WHERE keyed.source_resource_type = 'PractitionerRole'))::bigint
            AS practitioner_role_ref_count,
        (COUNT(DISTINCT keyed.source_resource_id)
            FILTER (WHERE keyed.source_resource_type = 'OrganizationAffiliation'))::bigint
            AS organization_affiliation_ref_count,
        COUNT(DISTINCT keyed.source_resource_type || ':' || keyed.source_resource_id || ':' || keyed.network_ref)::bigint
            AS distinct_ref_count,
        keyed.source_org_name,
        keyed.source_plan_name,
        keyed.canonical_api_base,
        MAX(keyed.observed_at) AS observed_at,
        now() AS published_at
      FROM keyed
  GROUP BY
        keyed.source_id,
        keyed.network_resource_id,
        keyed.provider_directory_network_name,
        keyed.provider_directory_network_key,
        keyed.provider_directory_issuer_key,
        keyed.provider_directory_issuer_network_match_key,
        keyed.aliases,
        keyed.source_org_name,
        keyed.source_plan_name,
        keyed.canonical_api_base;
    """


async def _copy_existing_network_catalog(
    stage_ref: str,
    target_ref: str,
    columns: str,
    source_ids: list[str],
) -> int:
    if not source_ids:
        return 0
    return _coerce_rowcount(
        await db.status(
            f"""
            INSERT INTO {stage_ref} ({columns})
            SELECT {columns}
              FROM {target_ref}
             WHERE NOT (source_id = ANY(CAST(:source_ids AS varchar[])));
            """,
            source_ids=source_ids,
        )
    )


async def _swap_network_catalog_stage(
    schema: str,
    stage_table: str,
    stage_ref: str,
    target_ref: str,
    build_fence: ProviderDirectoryArtifactBuildFence | None = None,
) -> None:
    del stage_ref, target_ref
    await _cutover_provider_directory_artifact_stage(
        schema=schema,
        stage_table=stage_table,
        target_relation=PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE,
        rename_stage_indexes=_rename_network_catalog_stage_indexes,
        build_fence=build_fence,
    )


async def publish_provider_directory_network_catalog(
    db_schema: str | None = None,
    *,
    run_id: str | None = None,
    source_ids: list[str] | tuple[str, ...] | None = None,
    defer_cutover: bool = False,
) -> Any:
    """Publish resolved Provider Directory networks without locking source tables."""
    schema = db_schema if db_schema is not None else _schema()
    missing_reason = await _network_catalog_missing_requirement(schema)
    if missing_reason:
        return {"skipped": True, "reason": missing_reason}
    await _ensure_provider_directory_network_catalog_table(schema)
    effective_source_ids = await _network_catalog_scope_sources(
        schema,
        run_id=run_id,
        source_ids=source_ids,
    )
    target_ref = _qt(schema, PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE)
    if run_id is not None and not effective_source_ids:
        return {
            "skipped": True,
            "reason": "no_scoped_sources",
            "source_ids": [],
            "relation": target_ref,
        }
    async with _provider_directory_artifact_build_guard(
        schema,
        PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE,
    ) as build_fence:
        stage_table = _network_catalog_stage_table_name(run_id)
        stage_ref = _qt(schema, stage_table)
        columns = ", ".join(_provider_directory_network_catalog_columns())
        query_param_dict: dict[str, Any] = {}
        if run_id is not None:
            query_param_dict["run_id"] = run_id
        if effective_source_ids:
            query_param_dict["source_ids"] = effective_source_ids

        await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
        try:
            await db.status(f"CREATE UNLOGGED TABLE {stage_ref} (LIKE {target_ref} INCLUDING DEFAULTS);")
            copied_existing = await _copy_existing_network_catalog(
                stage_ref,
                target_ref,
                columns,
                effective_source_ids,
            )
            inserted = _coerce_rowcount(
                await db.status(
                    provider_directory_network_catalog_insert_sql(
                        schema,
                        stage_table,
                        run_id=run_id,
                        source_ids=effective_source_ids,
                    ),
                    **query_param_dict,
                )
            )
            stage_rows = int(await db.scalar(f"SELECT COUNT(*) FROM {stage_ref};") or 0)
            await _create_provider_directory_network_catalog_indexes(schema, stage_table)
            await db.status(f"ANALYZE {stage_ref};")
            publish_metrics_by_field = {
                "published": True,
                "rows": stage_rows,
                "inserted": inserted,
                "copied_existing": copied_existing,
                "source_ids": effective_source_ids,
                "relation": target_ref,
            }
            if defer_cutover:
                await _prepare_provider_directory_artifact_stage(
                    schema,
                    stage_table,
                )
                return (
                    publish_metrics_by_field,
                    ProviderDirectoryPreparedArtifactStage(
                        schema=schema,
                        stage_table=stage_table,
                        target_relation=PROVIDER_DIRECTORY_NETWORK_CATALOG_TABLE,
                        rename_stage_indexes=_rename_network_catalog_stage_indexes,
                        build_fence=build_fence,
                    ),
                )
            await _swap_network_catalog_stage(schema, stage_table, stage_ref, target_ref, build_fence)
            return publish_metrics_by_field
        except Exception:
            try:
                await db.status(f"DROP TABLE IF EXISTS {stage_ref};")
            except Exception:  # pragma: no cover - cleanup best effort
                LOGGER.warning("Failed to clean Provider Directory network catalog stage %s", stage_ref, exc_info=True)
            raise


async def publish_provider_directory_address_corroboration_if_available(
    db_schema: str | None = None,
    *,
    refresh_network_catalog: bool = True,
    source_ids: list[str] | tuple[str, ...] | None = None,
) -> bool:
    """Publish provider directory address corroboration if available for provider-directory serving."""
    schema = db_schema or _schema()
    if not await _table_exists(schema, "entity_address_unified"):
        return False
    cleaned_source_ids = _clean_source_id_list(source_ids)
    await publish_provider_directory_address_corroboration_table(
        schema,
        refresh_network_catalog=refresh_network_catalog,
        **({"source_ids": cleaned_source_ids} if cleaned_source_ids else {}),
    )
    return True


async def _ensure_provider_directory_tables() -> None:
    schema = _schema()
    await db.status(f"CREATE SCHEMA IF NOT EXISTS {_q(schema)};")
    for model in (*SOURCE_MODELS, *CANONICAL_RESOURCE_MODELS):
        await db.create_table(model.__table__, checkfirst=True)
        await _ensure_provider_directory_model_columns(model, schema)
    await _ensure_provider_directory_source_column_types(schema)
    for model in (*SOURCE_MODELS, *CANONICAL_RESOURCE_MODELS):
        for index in getattr(model, "__my_additional_indexes__", []) or []:
            name = index.get("name") or "_".join(index.get("index_elements", ()))
            using = f"USING {index.get('using')} " if index.get("using") else ""
            where = f" WHERE {index.get('where')}" if index.get("where") else ""
            elements = _provider_directory_index_elements_sql(model, index)
            included_columns = ", ".join(
                _q(column_name) for column_name in index.get("include", ())
            )
            include = (
                f" INCLUDE ({included_columns})" if included_columns else ""
            )
            unique = "UNIQUE " if index.get("unique") else ""
            await db.status(
                f"CREATE {unique}INDEX IF NOT EXISTS {name} "
                f"ON {_qt(schema, model.__tablename__)} "
                f"{using}({elements}){include}{where};"
            )
    await _ensure_provider_directory_import_seen_table(schema)


async def _ensure_provider_directory_source_column_types(schema: str) -> None:
    current_data_type = _clean_text(
        await db.scalar(
            """
            SELECT data_type
              FROM information_schema.columns
             WHERE table_schema = :schema_name
               AND table_name = 'provider_directory_source'
               AND column_name = 'data_quality_checked';
            """,
            schema_name=schema,
        )
    ).lower()
    if not current_data_type or current_data_type == "text":
        return
    await db.status(
        f"""
        ALTER TABLE IF EXISTS {_qt(schema, "provider_directory_source")}
            ALTER COLUMN data_quality_checked TYPE text;
        """
    )


async def _ensure_provider_directory_model_columns(model: Any, schema: str) -> None:
    rows = await db.all(
        """
        SELECT column_name
          FROM information_schema.columns
         WHERE table_schema = :schema
           AND table_name = :table_name
        """,
        schema=schema,
        table_name=model.__tablename__,
    )
    existing = {_clean_text((row._mapping if hasattr(row, "_mapping") else row).get("column_name")) for row in rows}
    table_ref = _qt(schema, model.__tablename__)
    dialect = postgresql.dialect()
    for column in model.__table__.columns:
        if column.name in existing:
            continue
        column_ddl = str(CreateColumn(column).compile(dialect=dialect)).strip()
        if not column_ddl:
            continue
        await db.status(f"ALTER TABLE {table_ref} ADD COLUMN IF NOT EXISTS {column_ddl};")


async def _ensure_provider_directory_import_seen_table(schema: str | None = None) -> None:
    schema = schema or _schema()
    seen_ref = _qt(schema, PROVIDER_DIRECTORY_IMPORT_SEEN_TABLE)
    await db.status(
        f"""
        CREATE UNLOGGED TABLE IF NOT EXISTS {seen_ref} (
            run_id varchar(64) NOT NULL,
            resource_type varchar(64) NOT NULL,
            source_id varchar(64) NOT NULL,
            resource_id varchar(256) NOT NULL,
            seen_at timestamp NOT NULL DEFAULT now(),
            PRIMARY KEY (run_id, resource_type, source_id, resource_id)
        );
        """
    )
    # The primary key is (run_id, resource_type, source_id, resource_id), so it
    # already supports the stale-delete prefix lookup. The old prefix index only
    # doubled index writes during large imports.
    await db.status(
        f"""
        DROP INDEX IF EXISTS {_qt(schema, "provider_directory_import_seen_source_idx")};
        """
    )


async def _ensure_provider_directory_import_seen_stage_table(
    run_id: str | None,
    *,
    schema: str | None = None,
) -> str | None:
    if not run_id:
        return None
    schema = schema or _schema()
    stage_table = _provider_directory_import_seen_stage_table_name(run_id)
    stage_ref = _qt(schema, stage_table)
    await db.status(
        f"""
        CREATE UNLOGGED TABLE IF NOT EXISTS {stage_ref} (
            run_id varchar(64) NOT NULL,
            resource_type varchar(64) NOT NULL,
            source_id varchar(64) NOT NULL,
            resource_id varchar(256) NOT NULL,
            seen_at timestamp NOT NULL DEFAULT now()
        );
        """
    )
    await db.status(f"TRUNCATE TABLE {stage_ref};")
    return stage_table


async def _drop_provider_directory_import_seen_stage_table(
    stage_table: str | None,
    *,
    schema: str | None = None,
) -> None:
    if not stage_table:
        return
    schema = schema or _schema()
    await db.status(f"DROP TABLE IF EXISTS {_qt(schema, stage_table)};")


async def _prepare_provider_directory_import_seen_stage_lookup(
    stage_table: str,
    *,
    schema: str | None = None,
) -> None:
    schema = schema or _schema()
    stage_ref = _qt(schema, stage_table)
    index_name = f"{stage_table}_lookup_idx"
    await db.status(
        f"""
        CREATE INDEX IF NOT EXISTS {_q(index_name)}
            ON {stage_ref} (resource_type, source_id, resource_id);
        """
    )
    await db.status(f"ANALYZE {stage_ref};")


def _dedupe_rows_by_primary_key(primary_keys: list[str], rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    deduped: dict[tuple[Any, ...], dict[str, Any]] = {}
    for row in rows:
        key = tuple(row.get(primary_key) for primary_key in primary_keys)
        if any(value is None for value in key):
            continue
        deduped[key] = row
    return list(deduped.values())


def _max_rows_per_statement(column_count: int) -> int:
    return max(1, min(500, 30000 // max(column_count, 1)))


def _copy_upsert_enabled() -> bool:
    return os.getenv("HLTHPRT_PROVIDER_DIRECTORY_COPY_UPSERT", "1").lower() not in {
        "0",
        "false",
        "no",
        "off",
    }


def _seen_stage_enabled() -> bool:
    return os.getenv("HLTHPRT_PROVIDER_DIRECTORY_SEEN_STAGE", "1").lower() not in {
        "0",
        "false",
        "no",
        "off",
    }


def _copy_upsert_min_rows() -> int:
    try:
        return max(int(os.getenv("HLTHPRT_PROVIDER_DIRECTORY_COPY_UPSERT_MIN_ROWS", "100")), 1)
    except ValueError:
        return 100


def _location_address_key_batch_size() -> int:
    try:
        return max(
            int(
                os.getenv(
                    "HLTHPRT_PROVIDER_DIRECTORY_ADDRESS_KEY_BATCH_SIZE",
                    str(DEFAULT_LOCATION_ADDRESS_KEY_BATCH_SIZE),
                )
            ),
            1,
        )
    except ValueError:
        return DEFAULT_LOCATION_ADDRESS_KEY_BATCH_SIZE


def _location_coordinate_batch_size() -> int:
    try:
        return max(
            int(
                os.getenv(
                    "HLTHPRT_PROVIDER_DIRECTORY_COORDINATE_BATCH_SIZE",
                    str(DEFAULT_LOCATION_COORDINATE_BATCH_SIZE),
                )
            ),
            1,
        )
    except ValueError:
        return DEFAULT_LOCATION_COORDINATE_BATCH_SIZE


def _short_error(err: BaseException) -> str:
    message = str(getattr(err, "orig", err)).replace("\n", " ").strip()
    if len(message) > 240:
        return f"{message[:240]}..."
    return message


def _stage_table_name() -> str:
    return f"pd_stage_{os.getpid()}_{time.time_ns()}"


def _provider_directory_import_seen_stage_table_name(run_id: str) -> str:
    digest = hashlib.sha1(run_id.encode("utf-8", errors="ignore")).hexdigest()[:16]
    return f"{PROVIDER_DIRECTORY_IMPORT_SEEN_STAGE_PREFIX}_{digest}"


def _json_columns(table) -> set[str]:
    result: set[str] = set()
    for column in table.columns:
        type_name = column.type.__class__.__name__.upper()
        if "JSON" in type_name:
            result.add(column.name)
    return result


def _json_default(value: Any) -> Any:
    if isinstance(value, (datetime.date, datetime.datetime)):
        return value.isoformat()
    return str(value)


def _strip_postgres_nuls(value: Any) -> Any:
    if isinstance(value, str):
        return value.replace("\x00", "")
    if isinstance(value, list):
        return [_strip_postgres_nuls(item) for item in value]
    if isinstance(value, tuple):
        return tuple(_strip_postgres_nuls(item) for item in value)
    if isinstance(value, dict):
        return {
            _strip_postgres_nuls(key): _strip_postgres_nuls(item)
            for key, item in value.items()
        }
    return value


def _copy_record(row: dict[str, Any], columns: list[str], json_columns: set[str]) -> tuple[Any, ...]:
    values: list[Any] = []
    for column in columns:
        value = _strip_postgres_nuls(row.get(column))
        if value is not None and column in json_columns:
            value = json.dumps(value, sort_keys=True, default=_json_default)
        values.append(value)
    return tuple(values)


PROVIDER_DIRECTORY_RUN_METADATA_COLUMNS = frozenset({"last_seen_run_id", "observed_at", "updated_at"})
PROVIDER_DIRECTORY_SOURCE_PROBE_STATE_COLUMNS = frozenset(
    {
        "last_probe_status",
        "last_probe_status_code",
        "last_probe_error",
        "last_probe_run_id",
        "last_probed_at",
    }
)
PROVIDER_DIRECTORY_LOCATION_ADDRESS_KEY_INPUT_COLUMNS = (
    "first_line",
    "second_line",
    "city_name",
    "state_name",
    "state_code",
    "postal_code",
    "country_code",
)


def _preserve_null_location_address_key(table) -> bool:
    return table.name == ProviderDirectoryLocation.__tablename__


def _location_address_key_update_expression(table, excluded):
    raw_address_changed = or_(
        *(
            getattr(table.c, column).is_distinct_from(getattr(excluded, column))
            for column in PROVIDER_DIRECTORY_LOCATION_ADDRESS_KEY_INPUT_COLUMNS
        )
    )
    return case(
        (excluded.address_key.isnot(None), excluded.address_key),
        (raw_address_changed, None),
        else_=table.c.address_key,
    )


def _location_address_key_update_sql(
    *,
    target_prefix: str,
    incoming_prefix: str,
) -> str:
    raw_address_changed = " OR ".join(
        f"{target_prefix}.{_q(column)} IS DISTINCT FROM {incoming_prefix}.{_q(column)}"
        for column in PROVIDER_DIRECTORY_LOCATION_ADDRESS_KEY_INPUT_COLUMNS
    )
    address_key = _q("address_key")
    return (
        f"CASE "
        f"WHEN {incoming_prefix}.{address_key} IS NOT NULL THEN {incoming_prefix}.{address_key} "
        f"WHEN {raw_address_changed} THEN NULL "
        f"ELSE {target_prefix}.{address_key} "
        f"END"
    )


def _effective_update_expression(table, statement, column: str):
    excluded_value = getattr(statement.excluded, column)
    if (
        table.name == ProviderDirectoryCanonicalResource.__tablename__
        and column == "payload_json"
    ):
        return case(
            (excluded_value.isnot(None), excluded_value),
            (
                table.c.payload_hash.is_distinct_from(
                    statement.excluded.payload_hash
                ),
                None,
            ),
            else_=table.c.payload_json,
        )
    if table.name == ProviderDirectoryCanonicalResource.__tablename__ and column == "first_seen_run_id":
        return func.coalesce(table.c.first_seen_run_id, excluded_value)
    if (
        table.name == ProviderDirectoryAPIEndpoint.__tablename__
        and column in {"first_seen_at", "created_at"}
    ):
        return func.coalesce(getattr(table.c, column), excluded_value)
    if table.name == ProviderDirectorySource.__tablename__ and column == "metadata_json":
        target_metadata = func.coalesce(
            table.c.metadata_json.cast(JSONB), func.jsonb_build_object()
        )
        incoming_metadata = func.coalesce(
            excluded_value.cast(JSONB), func.jsonb_build_object()
        )
        merged_metadata = target_metadata.op("||")(incoming_metadata)
        return case(
            (
                func.coalesce(
                    incoming_metadata.op("->>")(
                        "provider_directory_acquisition_enabled"
                    ),
                    "false",
                )
                == "true",
                merged_metadata.op("-")(
                    "provider_directory_acquisition_blocked_reason"
                ),
            ),
            else_=merged_metadata,
        )
    if table.name == ProviderDirectorySource.__tablename__ and column in PROVIDER_DIRECTORY_SOURCE_PROBE_STATE_COLUMNS:
        return case(
            (statement.excluded.last_probe_status.is_(None), getattr(table.c, column)),
            else_=excluded_value,
        )
    if column == "address_key" and _preserve_null_location_address_key(table):
        return _location_address_key_update_expression(table, statement.excluded)
    return excluded_value


def _effective_update_sql(table, column: str, *, target_prefix: str, incoming_prefix: str) -> str:
    if (
        table.name == ProviderDirectoryCanonicalResource.__tablename__
        and column == "payload_json"
    ):
        payload_json = _q("payload_json")
        payload_hash = _q("payload_hash")
        return (
            "CASE "
            f"WHEN {incoming_prefix}.{payload_json} IS NOT NULL "
            f"THEN {incoming_prefix}.{payload_json} "
            f"WHEN {target_prefix}.{payload_hash} IS DISTINCT FROM "
            f"{incoming_prefix}.{payload_hash} THEN NULL "
            f"ELSE {target_prefix}.{payload_json} END"
        )
    if table.name == ProviderDirectoryCanonicalResource.__tablename__ and column == "first_seen_run_id":
        return f"COALESCE({target_prefix}.{_q(column)}, {incoming_prefix}.{_q(column)})"
    if (
        table.name == ProviderDirectoryAPIEndpoint.__tablename__
        and column in {"first_seen_at", "created_at"}
    ):
        return f"COALESCE({target_prefix}.{_q(column)}, {incoming_prefix}.{_q(column)})"
    if table.name == ProviderDirectorySource.__tablename__ and column == "metadata_json":
        quoted = _q(column)
        merged_metadata = (
            f"COALESCE({target_prefix}.{quoted}::jsonb, '{{}}'::jsonb) "
            f"|| COALESCE({incoming_prefix}.{quoted}::jsonb, '{{}}'::jsonb)"
        )
        return (
            "CASE WHEN COALESCE("
            f"{incoming_prefix}.{quoted}::jsonb ->> "
            "'provider_directory_acquisition_enabled', 'false') = 'true' "
            f"THEN ({merged_metadata}) - "
            "'provider_directory_acquisition_blocked_reason' "
            f"ELSE {merged_metadata} END"
        )
    if table.name == ProviderDirectorySource.__tablename__ and column in PROVIDER_DIRECTORY_SOURCE_PROBE_STATE_COLUMNS:
        quoted = _q(column)
        probe_status = _q("last_probe_status")
        return (
            f"CASE WHEN {incoming_prefix}.{probe_status} IS NULL "
            f"THEN {target_prefix}.{quoted} "
            f"ELSE {incoming_prefix}.{quoted} "
            f"END"
        )
    if column == "address_key" and _preserve_null_location_address_key(table):
        return _location_address_key_update_sql(
            target_prefix=target_prefix,
            incoming_prefix=incoming_prefix,
        )
    return f"{incoming_prefix}.{_q(column)}"


async def _mark_resource_rows_seen(
    model,
    rows: list[dict[str, Any]],
    run_id: str | None,
    *,
    seen_table: str | None = None,
) -> int:
    resource_type = RESOURCE_TYPES_BY_MODEL.get(model)
    if not run_id or not resource_type or not rows:
        return 0
    seen: dict[tuple[str, str], tuple[str, str]] = {}
    for row in rows:
        source_id = _clean_text(row.get("source_id"))
        resource_id = _clean_text(row.get("resource_id"))
        if source_id and resource_id:
            seen[(source_id, resource_id)] = (source_id, resource_id)
    if not seen:
        return 0
    items = list(seen.values())
    if _copy_upsert_enabled() and len(items) >= _copy_upsert_min_rows():
        try:
            return await _copy_mark_resource_rows_seen(resource_type, items, run_id, seen_table=seen_table)
        except Exception as exc:  # pragma: no cover - exercised on driver-specific fallback paths
            print(f"Provider Directory COPY seen fallback for {resource_type}: {_short_error(exc)}")
    max_rows = _max_rows_per_statement(4)
    total = 0
    seen_ref = _qt(_schema(), seen_table or PROVIDER_DIRECTORY_IMPORT_SEEN_TABLE)
    conflict_sql = (
        ""
        if seen_table
        else "ON CONFLICT (run_id, resource_type, source_id, resource_id) DO NOTHING"
    )
    for offset in range(0, len(items), max_rows):
        batch = items[offset : offset + max_rows]
        params: dict[str, Any] = {
            "run_id": run_id,
            "resource_type": resource_type,
        }
        values_sql: list[str] = []
        for idx, (source_id, resource_id) in enumerate(batch):
            params[f"source_id_{idx}"] = source_id
            params[f"resource_id_{idx}"] = resource_id
            values_sql.append(
                f"(:run_id, :resource_type, :source_id_{idx}, :resource_id_{idx})"
            )
        await db.status(
            f"""
            INSERT INTO {seen_ref} (run_id, resource_type, source_id, resource_id)
            VALUES {", ".join(values_sql)}
            {conflict_sql};
            """,
            **params,
        )
        total += len(batch)
    return total


async def _copy_mark_resource_rows_seen(
    resource_type: str,
    items: list[tuple[str, str]],
    run_id: str,
    *,
    seen_table: str | None = None,
) -> int:
    schema = _schema()
    if seen_table:
        columns = ["run_id", "resource_type", "source_id", "resource_id"]
        records = [(run_id, resource_type, source_id, resource_id) for source_id, resource_id in items]
        async with db.acquire() as conn:
            raw_conn = conn.raw_connection
            driver_conn = getattr(raw_conn, "driver_connection", raw_conn)
            copy_method = getattr(driver_conn, "copy_records_to_table", None)
            if copy_method is None:
                raise NotImplementedError("active database driver lacks copy_records_to_table")
            await copy_method(seen_table, schema_name=schema, columns=columns, records=records)
        return len(items)

    seen_ref = _qt(schema, PROVIDER_DIRECTORY_IMPORT_SEEN_TABLE)
    stage_table = _stage_table_name()
    columns = ["run_id", "resource_type", "source_id", "resource_id"]
    records = [(run_id, resource_type, source_id, resource_id) for source_id, resource_id in items]
    async with db.acquire() as conn:
        await conn.status(
            f"""
            CREATE TEMP TABLE {_q(stage_table)}
            (LIKE {seen_ref} INCLUDING DEFAULTS) ON COMMIT DROP;
            """
        )
        raw_conn = conn.raw_connection
        driver_conn = getattr(raw_conn, "driver_connection", raw_conn)
        copy_method = getattr(driver_conn, "copy_records_to_table", None)
        if copy_method is None:
            raise NotImplementedError("active database driver lacks copy_records_to_table")
        await copy_method(stage_table, columns=columns, records=records)
        quoted_columns = ", ".join(_q(column) for column in columns)
        await conn.status(
            f"""
            INSERT INTO {seen_ref} ({quoted_columns})
            SELECT DISTINCT {quoted_columns}
            FROM {_q(stage_table)}
            ON CONFLICT (run_id, resource_type, source_id, resource_id) DO NOTHING;
            """
        )
    return len(items)


async def _clear_resource_rows_seen(run_id: str | None) -> int:
    if not run_id:
        return 0
    return int(
        await db.status(
            f"""
            DELETE FROM {_qt(_schema(), PROVIDER_DIRECTORY_IMPORT_SEEN_TABLE)}
             WHERE run_id = CAST(:run_id AS varchar);
            """,
            run_id=run_id,
        )
        or 0
    )


def _canonical_resource_payload(row: dict[str, Any]) -> dict[str, Any]:
    return {
        key: value
        for key, value in row.items()
        if key
        not in {
            "source_id",
            "last_seen_run_id",
            "observed_at",
            "updated_at",
        }
    }


def _canonical_resource_rows(
    model,
    rows: list[dict[str, Any]],
    *,
    canonical_api_base: str | None,
    run_id: str | None,
    store_payload: bool = True,
) -> list[dict[str, Any]]:
    resource_type = RESOURCE_TYPES_BY_MODEL.get(model)
    api_base = _canonical_base(canonical_api_base)
    if not resource_type or not api_base:
        return []
    seen: dict[str, dict[str, Any]] = {}
    for row in rows:
        resource_id = _clean_text(row.get("resource_id"))
        if not resource_id:
            continue
        payload = _canonical_resource_payload(row)
        payload_hash = hashlib.sha256(
            json.dumps(payload, sort_keys=True, default=_json_default).encode("utf-8")
        ).hexdigest()
        observed_at = row.get("observed_at") or _now()
        seen[resource_id] = {
            "canonical_api_base": api_base,
            "resource_type": resource_type,
            "resource_id": resource_id,
            "resource_url": row.get("resource_url"),
            "fhir_meta": row.get("fhir_meta"),
            "fhir_self_url": row.get("fhir_self_url"),
            "fhir_fetch_url": row.get("fhir_fetch_url"),
            "fhir_fetch_mode": row.get("fhir_fetch_mode"),
            "payload_hash": payload_hash,
            "payload_json": payload if store_payload else None,
            "first_seen_run_id": run_id,
            "last_seen_run_id": run_id,
            "observed_at": observed_at,
            "updated_at": row.get("updated_at") or observed_at,
        }
    return list(seen.values())


def _endpoint_dataset_resource_rows(
    model: type,
    rows: list[dict[str, Any]],
    *,
    dataset_id: str | None,
) -> list[dict[str, Any]]:
    resource_type = RESOURCE_TYPES_BY_MODEL.get(model)
    if not dataset_id or not resource_type:
        return []
    resources_by_id: dict[str, dict[str, Any]] = {}
    for row in rows:
        resource_id = _clean_text(row.get("resource_id"))
        if not resource_id:
            continue
        payload = _canonical_resource_payload(row)
        resources_by_id[resource_id] = {
            "dataset_id": dataset_id,
            "resource_type": resource_type,
            "resource_id": resource_id,
            "payload_hash": hashlib.sha256(
                json.dumps(
                    payload,
                    sort_keys=True,
                    default=_json_default,
                ).encode("utf-8")
            ).hexdigest(),
            "payload_json": payload,
        }
    return [resources_by_id[resource_id] for resource_id in sorted(resources_by_id)]


def _source_resource_edge_rows(
    model,
    rows: list[dict[str, Any]],
    *,
    canonical_api_base: str | None,
    source_ids: list[str],
    run_id: str | None,
) -> list[dict[str, Any]]:
    resource_type = RESOURCE_TYPES_BY_MODEL.get(model)
    api_base = _canonical_base(canonical_api_base)
    if not resource_type or not api_base or not source_ids:
        return []
    resource_ids = {
        resource_id
        for row in rows
        if (resource_id := _clean_text(row.get("resource_id")))
    }
    observed_at = _now()
    return [
        {
            "source_id": source_id,
            "canonical_api_base": api_base,
            "resource_type": resource_type,
            "resource_id": resource_id,
            "last_seen_run_id": run_id,
            "observed_at": observed_at,
            "updated_at": observed_at,
        }
        for source_id in source_ids
        for resource_id in sorted(resource_ids)
    ]


def _upsert_changed_row_predicate(table, statement, columns: list[str], primary_keys: list[str]):
    payload_columns = [
        column
        for column in columns
        if column not in primary_keys and column not in PROVIDER_DIRECTORY_RUN_METADATA_COLUMNS
    ]
    if not payload_columns:
        return None
    predicates = []
    for column in payload_columns:
        current_value = getattr(table.c, column)
        excluded_value = _effective_update_expression(table, statement, column)
        if isinstance(current_value.type, SQLAlchemyJSON):
            current_value = current_value.cast(JSONB)
            excluded_value = excluded_value.cast(JSONB)
        predicates.append(current_value.is_distinct_from(excluded_value))
    return or_(
        *predicates
    )


def _copy_upsert_changed_where_sql(table, columns: list[str], primary_keys: list[str]) -> str:
    payload_columns = [
        column
        for column in columns
        if column not in primary_keys and column not in PROVIDER_DIRECTORY_RUN_METADATA_COLUMNS
    ]
    predicates: list[str] = []
    json_columns = _json_columns(table)
    target_table = _q(table.name)
    for column in payload_columns:
        quoted = _q(column)
        excluded_sql = _effective_update_sql(
            table,
            column,
            target_prefix=target_table,
            incoming_prefix="EXCLUDED",
        )
        if column in json_columns:
            predicates.append(
                f"{target_table}.{quoted}::jsonb IS DISTINCT FROM {excluded_sql}::jsonb"
            )
        else:
            predicates.append(f"{target_table}.{quoted} IS DISTINCT FROM {excluded_sql}")
    return " OR ".join(predicates)


def _copy_stage_primary_key_join_sql(
    primary_keys: list[str],
    *,
    target_alias: str = "target_row",
    stage_alias: str = "stage_row",
) -> str:
    return " AND ".join(
        f"{target_alias}.{_q(column)} = {stage_alias}.{_q(column)}"
        for column in primary_keys
    )


def _copy_stage_changed_where_sql(
    table,
    columns: list[str],
    primary_keys: list[str],
    *,
    target_alias: str = "target_row",
    stage_alias: str = "stage_row",
) -> str:
    payload_columns = [
        column
        for column in columns
        if column not in primary_keys and column not in PROVIDER_DIRECTORY_RUN_METADATA_COLUMNS
    ]
    missing_predicate = f"{target_alias}.{_q(primary_keys[0])} IS NULL"
    predicates = [missing_predicate]
    json_columns = _json_columns(table)
    for column in payload_columns:
        quoted = _q(column)
        incoming_sql = _effective_update_sql(
            table,
            column,
            target_prefix=target_alias,
            incoming_prefix=stage_alias,
        )
        if column in json_columns:
            predicates.append(
                f"{target_alias}.{quoted}::jsonb IS DISTINCT FROM {incoming_sql}::jsonb"
            )
        else:
            predicates.append(f"{target_alias}.{quoted} IS DISTINCT FROM {incoming_sql}")
    return " OR ".join(predicates)


async def _upsert_rows_values(
    model,
    normalized: list[dict[str, Any]],
    columns: list[str],
    primary_keys: list[str],
    *,
    skip_unchanged: bool,
) -> int:
    if not normalized:
        return 0
    max_rows_per_statement = _max_rows_per_statement(len(columns))
    if len(normalized) > max_rows_per_statement:
        total = 0
        for offset in range(0, len(normalized), max_rows_per_statement):
            total += await _upsert_rows_values(
                model,
                normalized[offset : offset + max_rows_per_statement],
                columns,
                primary_keys,
                skip_unchanged=skip_unchanged,
            )
        return total
    table = model.__table__
    async with db.session() as session:
        statement = pg_insert(table).values(normalized)
        update_columns = {
            column.name: _effective_update_expression(table, statement, column.name)
            for column in table.columns
            if column.name not in primary_keys
        }
        update_where = _upsert_changed_row_predicate(table, statement, columns, primary_keys) if skip_unchanged else None
        statement = statement.on_conflict_do_update(
            index_elements=primary_keys,
            set_=update_columns,
            where=update_where,
        )
        await session.execute(statement)
    return len(normalized)


async def _copy_upsert_rows(
    model,
    normalized: list[dict[str, Any]],
    columns: list[str],
    primary_keys: list[str],
    *,
    skip_unchanged: bool,
) -> int:
    """Copy upsert rows into the destination tables."""
    table = model.__table__
    schema = table.schema or _schema()
    stage_table = _stage_table_name()
    target_ref = _qt(schema, table.name)
    quoted_stage = _q(stage_table)
    quoted_columns = ", ".join(_q(column) for column in columns)
    quoted_conflict = ", ".join(_q(column) for column in primary_keys)
    update_columns = [column for column in columns if column not in primary_keys]
    if update_columns:
        target_table = _q(table.name)
        conflict_sql = (
            "DO UPDATE SET "
            + ", ".join(
                f"{_q(column)} = "
                f"{_effective_update_sql(table, column, target_prefix=target_table, incoming_prefix='EXCLUDED')}"
                for column in update_columns
            )
        )
        update_where = _copy_upsert_changed_where_sql(table, columns, primary_keys) if skip_unchanged else ""
        if update_where:
            conflict_sql = f"{conflict_sql} WHERE {update_where}"
    else:
        conflict_sql = "DO NOTHING"

    json_columns = _json_columns(table)
    records = [_copy_record(row, columns, json_columns) for row in normalized]
    select_sql = f"SELECT {quoted_columns}\n            FROM {quoted_stage}"
    if skip_unchanged:
        stage_alias = "stage_row"
        target_alias = "target_row"
        changed_where = _copy_stage_changed_where_sql(
            table,
            columns,
            primary_keys,
            target_alias=target_alias,
            stage_alias=stage_alias,
        )
        primary_key_join = _copy_stage_primary_key_join_sql(
            primary_keys,
            target_alias=target_alias,
            stage_alias=stage_alias,
        )
        select_columns = ", ".join(f"{stage_alias}.{_q(column)}" for column in columns)
        select_sql = f"""
            SELECT {select_columns}
            FROM {quoted_stage} AS {stage_alias}
            LEFT JOIN {target_ref} AS {target_alias}
              ON {primary_key_join}
            WHERE {changed_where}
            """
    async with db.acquire() as conn:
        await conn.status(
            f"""
            CREATE TEMP TABLE {quoted_stage}
            (LIKE {target_ref} INCLUDING DEFAULTS) ON COMMIT DROP;
            """
        )
        raw_conn = conn.raw_connection
        driver_conn = getattr(raw_conn, "driver_connection", raw_conn)
        copy_method = getattr(driver_conn, "copy_records_to_table", None)
        if copy_method is None:
            raise NotImplementedError("active database driver lacks copy_records_to_table")
        await copy_method(stage_table, columns=columns, records=records)
        if skip_unchanged:
            await conn.status(f"ANALYZE {quoted_stage};")
        await conn.status(
            f"""
            INSERT INTO {target_ref} ({quoted_columns})
            {select_sql}
            ON CONFLICT ({quoted_conflict}) {conflict_sql};
            """
        )
    return len(normalized)


async def _upsert_rows(
    model,
    rows: list[dict[str, Any]],
    *,
    skip_unchanged: bool = False,
) -> int:
    if not rows:
        return 0
    if model is ProviderDirectoryLocation and _location_contact_fields_missing(rows):
        rows = _attach_location_contact_fields(rows)
    table = model.__table__
    columns = [column.name for column in table.columns]
    primary_keys = [column.name for column in table.primary_key.columns]
    rows = _dedupe_rows_by_primary_key(primary_keys, rows)
    if not rows:
        return 0
    normalized = [{key: row.get(key) for key in columns} for row in rows]
    if _copy_upsert_enabled() and len(normalized) >= _copy_upsert_min_rows():
        try:
            return await _copy_upsert_rows(
                model,
                normalized,
                columns,
                primary_keys,
                skip_unchanged=skip_unchanged,
            )
        except Exception as exc:  # pragma: no cover - exercised on driver-specific fallback paths
            print(f"Provider Directory COPY upsert fallback for {model.__tablename__}: {_short_error(exc)}")
    return await _upsert_rows_values(
        model,
        normalized,
        columns,
        primary_keys,
        skip_unchanged=skip_unchanged,
    )


def _status_row_count(status: Any) -> int:
    if isinstance(status, int):
        return status
    if not status:
        return 0
    match = re.search(r"(\d+)(?!.*\d)", str(status))
    return int(match.group(1)) if match else 0


def provider_directory_location_contact_backfill_sql(schema: str) -> str:
    """Build SQL for provider directory location contact backfill."""
    table_ref = _qt(schema, ProviderDirectoryLocation.__tablename__)
    phone_number = _canonical_contact_number_expr("loc.telephone_number", "loc.country_code")
    phone_extension = _contact_extension_expr("loc.telephone_number")
    fax_number_digits = _canonical_contact_number_expr("loc.fax_number", "loc.country_code")
    fax_extension = _contact_extension_expr("loc.fax_number")
    return f"""
        WITH computed AS (
            SELECT loc.source_id,
                   loc.resource_id,
                   {phone_number}::varchar AS phone_number,
                   {phone_extension}::varchar AS phone_extension,
                   {fax_number_digits}::varchar AS fax_number_digits,
                   {fax_extension}::varchar AS fax_extension
              FROM {table_ref} AS loc
             WHERE NULLIF(BTRIM(COALESCE(loc.telephone_number, '')), '') IS NOT NULL
                OR NULLIF(BTRIM(COALESCE(loc.fax_number, '')), '') IS NOT NULL
        )
        UPDATE {table_ref} AS target
           SET phone_number = computed.phone_number,
               phone_extension = computed.phone_extension,
               fax_number_digits = computed.fax_number_digits,
               fax_extension = computed.fax_extension,
               updated_at = now()
          FROM computed
         WHERE target.source_id = computed.source_id
           AND target.resource_id = computed.resource_id
           AND (
                target.phone_number IS DISTINCT FROM computed.phone_number
             OR target.phone_extension IS DISTINCT FROM computed.phone_extension
             OR target.fax_number_digits IS DISTINCT FROM computed.fax_number_digits
             OR target.fax_extension IS DISTINCT FROM computed.fax_extension
           );
    """


async def backfill_provider_directory_location_contacts() -> dict[str, Any]:
    """Backfill provider directory location contacts for existing provider-directory rows."""
    await _ensure_provider_directory_tables()
    updated = _status_row_count(await db.status(provider_directory_location_contact_backfill_sql(_schema())))
    summary = {"location_contact_rows_updated": updated}
    print("PROVIDER_DIRECTORY_CONTACT_BACKFILL_DONE\t" + json.dumps(summary, sort_keys=True, default=str))
    return summary


def _canonical_backfill_resource_sql(resource_type: str, table_name: str) -> tuple[str, str]:
    """Build SQL for canonical backfill resource."""
    schema = _schema()
    source_ref = _qt(schema, "provider_directory_source")
    resource_ref = _qt(schema, table_name)
    canonical_ref = _qt(schema, ProviderDirectoryCanonicalResource.__tablename__)
    edge_ref = _qt(schema, ProviderDirectorySourceResource.__tablename__)
    canonical_target = _q(ProviderDirectoryCanonicalResource.__tablename__)
    edge_target = _q(ProviderDirectorySourceResource.__tablename__)
    resource_type_literal = _sql_string_literal(resource_type)
    payload_sql = (
        "(to_jsonb(r) - 'source_id' - 'last_seen_run_id' - 'observed_at' - 'updated_at')"
    )
    base_sql = "COALESCE(NULLIF(src.canonical_api_base, ''), NULLIF(src.api_base, ''))"
    rows_where = (
        f"{base_sql} IS NOT NULL "
        "AND NULLIF(r.source_id, '') IS NOT NULL "
        "AND NULLIF(r.resource_id, '') IS NOT NULL"
    )
    canonical_sql = f"""
        INSERT INTO {canonical_ref} (
            canonical_api_base,
            resource_type,
            resource_id,
            resource_url,
            fhir_meta,
            fhir_self_url,
            fhir_fetch_url,
            fhir_fetch_mode,
            payload_hash,
            payload_json,
            first_seen_run_id,
            last_seen_run_id,
            observed_at,
            updated_at
        )
        SELECT canonical_api_base,
               resource_type,
               resource_id,
               resource_url,
               fhir_meta,
               fhir_self_url,
               fhir_fetch_url,
               fhir_fetch_mode,
               payload_hash,
               payload_json,
               first_seen_run_id,
               last_seen_run_id,
               observed_at,
               updated_at
          FROM (
            SELECT DISTINCT ON ({base_sql}, r.resource_id)
                   {base_sql} AS canonical_api_base,
                   {resource_type_literal} AS resource_type,
                   r.resource_id,
                   r.resource_url,
                   r.fhir_meta,
                   r.fhir_self_url,
                   r.fhir_fetch_url,
                   r.fhir_fetch_mode,
                   md5(({payload_sql})::text) AS payload_hash,
                   {payload_sql} AS payload_json,
                   r.last_seen_run_id AS first_seen_run_id,
                   r.last_seen_run_id,
                   r.observed_at,
                   COALESCE(r.updated_at, r.observed_at) AS updated_at
              FROM {resource_ref} AS r
              JOIN {source_ref} AS src
                ON src.source_id = r.source_id
             WHERE {rows_where}
             ORDER BY {base_sql},
                      r.resource_id,
                      r.updated_at DESC NULLS LAST,
                      r.observed_at DESC NULLS LAST,
                      r.source_id
          ) AS ranked
        ON CONFLICT (canonical_api_base, resource_type, resource_id) DO UPDATE
            SET resource_url = EXCLUDED.resource_url,
                fhir_meta = EXCLUDED.fhir_meta,
                fhir_self_url = EXCLUDED.fhir_self_url,
                fhir_fetch_url = EXCLUDED.fhir_fetch_url,
                fhir_fetch_mode = EXCLUDED.fhir_fetch_mode,
                payload_hash = EXCLUDED.payload_hash,
                payload_json = EXCLUDED.payload_json,
                first_seen_run_id = COALESCE(
                    {canonical_target}.first_seen_run_id,
                    EXCLUDED.first_seen_run_id
                ),
                last_seen_run_id = EXCLUDED.last_seen_run_id,
                observed_at = EXCLUDED.observed_at,
                updated_at = EXCLUDED.updated_at;
    """
    edge_sql = f"""
        INSERT INTO {edge_ref} (
            source_id,
            canonical_api_base,
            resource_type,
            resource_id,
            last_seen_run_id,
            observed_at,
            updated_at
        )
        SELECT DISTINCT r.source_id,
               {base_sql} AS canonical_api_base,
               {resource_type_literal} AS resource_type,
               r.resource_id,
               r.last_seen_run_id,
               r.observed_at,
               COALESCE(r.updated_at, r.observed_at) AS updated_at
          FROM {resource_ref} AS r
          JOIN {source_ref} AS src
            ON src.source_id = r.source_id
         WHERE {rows_where}
        ON CONFLICT (source_id, resource_type, resource_id) DO UPDATE
            SET canonical_api_base = EXCLUDED.canonical_api_base,
                last_seen_run_id = EXCLUDED.last_seen_run_id,
                observed_at = EXCLUDED.observed_at,
                updated_at = EXCLUDED.updated_at;
    """
    return canonical_sql, edge_sql


async def backfill_provider_directory_canonical_resources(
    *,
    resources: str | None = None,
) -> dict[str, Any]:
    """Backfill provider directory canonical resources for existing provider-directory rows."""
    await _ensure_provider_directory_tables()
    selected = _selected_resources(resources)
    summary: dict[str, Any] = {
        "resources": {},
        "canonical_rows": 0,
        "source_edge_rows": 0,
    }
    for resource_type in selected:
        model = RESOURCE_MODELS_BY_TYPE.get(resource_type)
        if model is None:
            continue
        canonical_sql, edge_sql = _canonical_backfill_resource_sql(resource_type, model.__tablename__)
        canonical_rows = _status_row_count(await db.status(canonical_sql))
        source_edge_rows = _status_row_count(await db.status(edge_sql))
        summary["resources"][resource_type] = {
            "canonical_rows": canonical_rows,
            "source_edge_rows": source_edge_rows,
        }
        summary["canonical_rows"] += canonical_rows
        summary["source_edge_rows"] += source_edge_rows
    print("PROVIDER_DIRECTORY_CANONICAL_BACKFILL_DONE\t" + json.dumps(summary, sort_keys=True, default=str))
    return summary


def _seed_rows_from_sqlite(path: Path, *, limit: int | None = None, source_query: str | None = None) -> list[dict[str, Any]]:
    conn = sqlite3.connect(str(path))
    conn.row_factory = sqlite3.Row
    try:
        sql = "SELECT * FROM payers"
        params: list[Any] = []
        if source_query:
            sql += " WHERE lower(org_name) LIKE ? OR lower(plan_name) LIKE ?"
            needle = f"%{source_query.lower()}%"
            params.extend([needle, needle])
        sql += " ORDER BY id"
        if limit and limit > 0:
            sql += " LIMIT ?"
            params.append(limit)
        return [dict(row) for row in conn.execute(sql, params).fetchall()]
    finally:
        conn.close()


def _seed_row_matches_query(row: dict[str, Any], source_query: str | None) -> bool:
    query = _clean_text(source_query)
    if not query:
        return True
    needle = query.lower()
    return any(
        needle in (_clean_text(row.get(field)) or "").lower()
        for field in ("org_name", "plan_name")
    )


def _seed_row_has_importable_provider_directory_override(row: dict[str, Any]) -> bool:
    source_row = _source_row_from_seed(row)
    metadata = source_row.get("metadata_json") or {}
    if not metadata.get("provider_directory_override"):
        return False
    validation = (_clean_text(source_row.get("last_validated_status")) or "").lower()
    return validation in {"", "valid", "auth_required"}


def _seed_row_has_recoverable_provider_directory_base(row: dict[str, Any]) -> bool:
    if _seed_row_has_importable_provider_directory_override(row):
        return True
    source_row = _source_row_from_seed(row)
    metadata = source_row.get("metadata_json") or {}
    return metadata.get("provider_directory_base_normalization") == "resource_or_metadata_parent_base"


class _AmeriHealthCaritasCatalogParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self._in_cell = False
        self._cell_text: list[str] = []
        self._row: list[str] = []
        self._row_links: list[str] = []
        self.rows: list[tuple[list[str], list[str]]] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        """Capture catalog link metadata from an opening HTML tag."""
        if tag in {"td", "th"}:
            self._in_cell = True
            self._cell_text = []
        if tag == "a" and self._in_cell:
            href = dict(attrs).get("href")
            if href:
                self._row_links.append(href)

    def handle_data(self, data: str) -> None:
        """Accumulate visible catalog text for the active link."""
        if self._in_cell:
            self._cell_text.append(data)

    def handle_endtag(self, tag: str) -> None:
        """Finalize the active catalog link when its HTML tag closes."""
        if tag in {"td", "th"} and self._in_cell:
            self._row.append(" ".join(" ".join(self._cell_text).split()))
            self._cell_text = []
            self._in_cell = False
        if tag == "tr" and self._row:
            self.rows.append((self._row, self._row_links))
            self._row = []
            self._row_links = []


class _HtmlLinkParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self._href: str | None = None
        self._text: list[str] = []
        self.links: list[tuple[str, str]] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        """Capture candidate URLs from an opening HTML tag."""
        if tag != "a" or self._href is not None:
            return
        href = dict(attrs).get("href")
        if not href:
            return
        self._href = href
        self._text = []

    def handle_data(self, data: str) -> None:
        """Accumulate visible text for the active HTML link."""
        if self._href is not None:
            self._text.append(data)

    def handle_endtag(self, tag: str) -> None:
        """Finalize the active HTML link when its tag closes."""
        if tag != "a" or self._href is None:
            return
        self.links.append((" ".join(" ".join(self._text).split()), self._href))
        self._href = None
        self._text = []


def _provider_api_base_from_url(url: str | None) -> str | None:
    text = _clean_text(url)
    if not text or "/provider-api" not in text:
        return None
    prefix = text.split("/provider-api", 1)[0]
    return _canonical_base(f"{prefix}/provider-api")


def _provider_directory_base_from_metadata_url(url: str | None) -> str | None:
    text = _clean_text(url)
    if not text:
        return None
    parsed = urllib.parse.urlsplit(text)
    if not parsed.scheme or not parsed.netloc:
        return None
    path = parsed.path.rstrip("/")
    if not path.lower().endswith("/metadata"):
        return None
    base_path = path[: -len("/metadata")].rstrip("/")
    if not base_path:
        return None
    return _canonical_base(urllib.parse.urlunsplit((parsed.scheme, parsed.netloc, base_path, "", "")))


def _extract_urls_from_text(value: str | None) -> list[str]:
    text = (_clean_text(value) or "").replace("\xa0", " ")
    urls: list[str] = []
    for match in URL_IN_TEXT_RE.finditer(text):
        url = match.group(0).strip().rstrip(".,;")
        if url and url not in urls:
            urls.append(url)
    return urls


def _resource_type_from_provider_directory_url(url: str | None) -> str | None:
    canonical = _canonical_base(url)
    if not canonical:
        return None
    parsed = urllib.parse.urlsplit(canonical)
    segments = [segment for segment in parsed.path.strip("/").split("/") if segment]
    if not segments:
        return None
    resource_type_by_key = {resource_type.lower(): resource_type for resource_type in DEFAULT_RESOURCES}
    return resource_type_by_key.get(segments[-1].lower())


def _provider_directory_base_from_catalog_url(url: str | None) -> str | None:
    canonical = _canonical_base(url)
    if not canonical:
        return None
    return _resource_or_metadata_parent_base(canonical) or canonical


def _base_path(value: str | None) -> str:
    parsed = urllib.parse.urlsplit(value or "")
    return parsed.path.rstrip("/").lower()


def _cms_sma_bases_are_related(left: str | None, right: str | None) -> bool:
    left_base = _canonical_base(left)
    right_base = _canonical_base(right)
    if not left_base or not right_base:
        return False
    left_parts = urllib.parse.urlsplit(left_base)
    right_parts = urllib.parse.urlsplit(right_base)
    if left_parts.netloc.lower() != right_parts.netloc.lower():
        return False
    left_path = _base_path(left_base)
    right_path = _base_path(right_base)
    return (
        left_path == right_path
        or not left_path
        or not right_path
        or left_path.startswith(f"{right_path}/")
        or right_path.startswith(f"{left_path}/")
    )


def _cms_sma_selected_api_base(production_base: str, capability_bases: list[str]) -> str:
    for capability_base in capability_bases:
        if _cms_sma_bases_are_related(production_base, capability_base):
            return capability_base
    return production_base


def _cms_sma_header_key(value: str | None) -> str:
    return re.sub(r"[^a-z0-9]+", " ", (_clean_text(value) or "").lower()).strip()


def _cms_sma_column_index(
    headers: list[str],
    keys: set[str],
    *,
    start: int = 0,
) -> int | None:
    for index, value in enumerate(headers[start:], start=start):
        if _cms_sma_header_key(value) in keys:
            return index
    return None


def _cms_sma_cell(row: list[str], index: int | None) -> str | None:
    if index is None or index >= len(row):
        return None
    return _clean_text(row[index])


def _cms_sma_endpoint_directory_seed_rows_from_csv(
    csv_text: str,
    *,
    source_query: str | None = None,
    source_url: str = CMS_SMA_ENDPOINT_DIRECTORY_URL,
) -> list[dict[str, Any]]:
    """Run the cms sma endpoint directory seed rows from csv step within provider-directory ingestion."""
    rows = list(csv.reader(io.StringIO(csv_text)))
    if len(rows) < 2:
        return []
    section_headers = rows[0]
    field_headers = rows[1]
    provider_start = next(
        (
            index
            for index, value in enumerate(section_headers)
            if _cms_sma_header_key(value) == "provider directory endpoint information"
        ),
        0,
    )
    state_col = _cms_sma_column_index(field_headers, {"state"})
    source_date_col = _cms_sma_column_index(field_headers, {"information as of date date completing the survey"})
    prod_col = _cms_sma_column_index(field_headers, {"provider directory production base url"}, start=provider_start)
    status_col = _cms_sma_column_index(field_headers, {"status drop down list"}, start=provider_start)
    cap_col = _cms_sma_column_index(field_headers, {"fhir capability statement link"}, start=provider_start)
    public_col = _cms_sma_column_index(field_headers, {"is the api public y n drop down list"}, start=provider_start)
    refresh_col = _cms_sma_column_index(
        field_headers,
        {"data refresh frequency e g real time hourly daily weekly monthly"},
        start=provider_start,
    )
    version_col = _cms_sma_column_index(field_headers, {"fhir version drop down list"}, start=provider_start)
    if state_col is None or prod_col is None or status_col is None or public_col is None:
        return []

    seed_rows: list[dict[str, Any]] = []
    for row in rows[2:]:
        state = _cms_sma_cell(row, state_col)
        if not state:
            continue
        status = _cms_sma_cell(row, status_col)
        public_value = _cms_sma_cell(row, public_col)
        status_key = (status or "").strip().lower()
        if status_key not in CMS_SMA_TRACKED_PROVIDER_DIRECTORY_STATUSES:
            continue
        if not (public_value or "").strip().lower().startswith("y"):
            continue
        validation_status = (
            CMS_SMA_CATALOG_VALIDATION_STATUS
            if status_key == "active"
            else CMS_SMA_CATALOG_IN_DEVELOPMENT_STATUS
        )

        production_urls = _extract_urls_from_text(_cms_sma_cell(row, prod_col))
        capability_urls = _extract_urls_from_text(_cms_sma_cell(row, cap_col))
        capability_bases: list[str] = []
        capability_url_by_base: dict[str, str] = {}
        for capability_url in capability_urls:
            capability_base = _provider_directory_base_from_metadata_url(capability_url)
            if not capability_base:
                continue
            _append_unique(capability_bases, capability_base)
            capability_url_by_base.setdefault(capability_base, capability_url)

        groups: dict[str, dict[str, Any]] = {}

        def group_for(api_base: str) -> dict[str, Any]:
            """Return the seed group bucket for one CMS endpoint row."""
            group = groups.setdefault(
                api_base,
                {
                    "api_base": api_base,
                    "endpoints": {},
                    "equivalent_api_bases": [],
                    "metadata_url": None,
                },
            )
            for capability_base, capability_url in capability_url_by_base.items():
                if _cms_sma_bases_are_related(api_base, capability_base):
                    group["metadata_url"] = group["metadata_url"] or capability_url
                    _append_unique(group["equivalent_api_bases"], capability_base)
            return group

        for production_url in production_urls:
            production_base = _provider_directory_base_from_catalog_url(production_url)
            if not production_base:
                continue
            api_base = _cms_sma_selected_api_base(production_base, capability_bases)
            group = group_for(api_base)
            _append_unique(group["equivalent_api_bases"], production_base)
            _append_unique(group["equivalent_api_bases"], production_url)
            resource_type = _resource_type_from_provider_directory_url(production_url)
            endpoint_field = RESOURCE_ENDPOINT_FIELDS.get(resource_type or "")
            if endpoint_field and endpoint_field not in group["endpoints"]:
                group["endpoints"][endpoint_field] = production_url

        if not groups:
            for capability_base in capability_bases:
                group = group_for(capability_base)
                group["metadata_url"] = group["metadata_url"] or capability_url_by_base.get(capability_base)

        source_date = _cms_sma_cell(row, source_date_col)
        refresh = _cms_sma_cell(row, refresh_col)
        fhir_version = _cms_sma_cell(row, version_col)
        state_key = re.sub(r"[^a-z0-9]+", "-", state.lower()).strip("-")
        for group in groups.values():
            api_base = group["api_base"]
            digest = hashlib.sha1(f"{state}|{api_base}".encode("utf-8")).hexdigest()[:8]
            metadata = {
                "provider_directory_source_catalog": CMS_SMA_ENDPOINT_DIRECTORY_SOURCE,
                "provider_directory_confirmed_catalog_url": source_url,
                "provider_directory_catalog_status": status,
                "provider_directory_catalog_public": public_value,
                "provider_directory_equivalent_api_bases": group["equivalent_api_bases"],
            }
            if group["metadata_url"]:
                metadata["provider_directory_confirmed_metadata_url"] = group["metadata_url"]
            seed_row = {
                "id": f"cms-sma-{state_key}-{digest}",
                "org_name": f"State of {state}",
                "plan_name": f"{state} Medicaid Provider Directory",
                "api_base": api_base,
                "auth_type": "none",
                "last_validated_status": validation_status,
                "requires_registration": False,
                "fhir_version": fhir_version,
                "source": CMS_SMA_ENDPOINT_DIRECTORY_SOURCE,
                "source_detail": f"CMS SMA Endpoint Directory public Provider Directory row state={state}",
                "source_url": source_url,
                "source_date": source_date,
                "note": (
                    "Catalog-discovered public Provider Directory endpoint from the CMS State Medicaid "
                    "Agency Endpoint Directory; live probe validation controls resource import."
                ),
                "metadata_json": metadata,
                **group["endpoints"],
            }
            if refresh:
                seed_row["data_quality_checked"] = refresh
            if _seed_row_matches_query(seed_row, source_query):
                seed_rows.append(seed_row)
    return seed_rows


def _external_splash_target_url(href: str | None, *, source_url: str) -> str | None:
    text = _clean_text(href)
    if not text:
        return None
    absolute = urllib.parse.urljoin(source_url, text)
    parsed = urllib.parse.urlsplit(absolute)
    params = urllib.parse.parse_qs(parsed.query)
    for key in ("splash", "url"):
        values = params.get(key)
        if values:
            return values[0]
    return absolute


def _amerihealth_caritas_seed_rows_from_catalog_html(
    html_text: str,
    *,
    source_query: str | None = None,
    source_url: str = AMERIHEALTH_CARITAS_DOC_URL,
    source_date: str | None = None,
) -> list[dict[str, Any]]:
    parser = _AmeriHealthCaritasCatalogParser()
    parser.feed(html_text)
    rows: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for cells, links in parser.rows:
        if len(cells) < 2 or cells[0].strip().lower() == "planid":
            continue
        plan_code = _clean_text(cells[0])
        plan_name = _clean_text(cells[1])
        provider_base = next(
            (
                base
                for href in links
                if (base := _provider_api_base_from_url(href))
            ),
            None,
        )
        if not plan_code or not plan_name or not provider_base:
            continue
        key = (plan_code.lower(), _payer_alias_key(plan_name), provider_base)
        if key in seen:
            continue
        seen.add(key)
        row = {
            "id": f"amerihealth-caritas-{plan_code.lower()}-{hashlib.sha1(plan_name.encode('utf-8')).hexdigest()[:8]}",
            "org_name": "AmeriHealth Caritas",
            "plan_name": plan_name,
            "api_base": provider_base,
            "auth_type": "none",
            "last_validated_status": "valid",
            "requires_registration": False,
            "source": "amerihealth-caritas-developer-portal",
            "source_detail": f"official AmeriHealth Caritas Provider Directory API plan_code={plan_code}",
            "source_url": source_url,
            "source_date": source_date,
            "note": "Supplemental Provider Directory source from AmeriHealth Caritas developer portal.",
            "metadata_json": {
                "provider_directory_confirmed_base": provider_base,
                "provider_directory_confirmed_catalog_url": source_url,
                "provider_directory_confirmed_metadata_url": f"{provider_base}/metadata",
                "provider_directory_plan_code": plan_code,
                "provider_directory_supported_resources": list(
                    AMERIHEALTH_CARITAS_SUPPORTED_RESOURCES
                ),
            },
        }
        if _seed_row_matches_query(row, source_query):
            rows.append(row)
    return rows


def _read_text_from_path_or_url(path: str | None, url: str, *, timeout: int) -> tuple[str, str]:
    clean_path = _clean_text(path)
    if clean_path:
        return Path(clean_path).read_text(encoding="utf-8"), clean_path
    request = urllib.request.Request(url, headers={"User-Agent": USER_AGENT})
    with urllib.request.urlopen(request, timeout=timeout) as response:
        return response.read().decode("utf-8", errors="replace"), url


def _seed_rows_from_amerihealth_caritas_catalog(
    *,
    source_query: str | None = None,
    timeout: int = 30,
    catalog_path: str | None = None,
    catalog_url: str | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    url = (
        _clean_text(catalog_url)
        or _clean_text(os.getenv(AMERIHEALTH_CARITAS_DOC_URL_ENV))
        or AMERIHEALTH_CARITAS_DOC_URL
    )
    text, source = _read_text_from_path_or_url(catalog_path, url, timeout=timeout)
    rows = _amerihealth_caritas_seed_rows_from_catalog_html(
        text,
        source_query=source_query,
        source_url=source,
    )
    return rows, {"source": source, "rows": len(rows)}


def _contra_costa_seed_row(
    provider_base: str,
    *,
    source_url: str,
    source_date: str | None = None,
    note_suffix: str | None = None,
) -> dict[str, Any]:
    note = "Supplemental Provider Directory source from Contra Costa Health APIs for Developers page."
    if note_suffix:
        note = f"{note} {note_suffix}"
    return {
        "id": f"contra-costa-health-plan-{hashlib.sha1(provider_base.encode('utf-8')).hexdigest()[:8]}",
        "org_name": "Contra Costa Health Plan",
        "plan_name": "Contra Costa Health Plan Provider Directory",
        "api_base": provider_base,
        "auth_type": "none",
        "last_validated_status": "valid",
        "requires_registration": False,
        "is_medicaid_mco": True,
        "source": "contra-costa-health-developer-page",
        "source_detail": "official Contra Costa Health Provider Directory API base URL",
        "source_url": source_url,
        "source_date": source_date,
        "note": note,
        "metadata_json": {
            "provider_directory_confirmed_base": provider_base,
            "provider_directory_supported_resources": list(
                PUBLIC_DIRECTORY_SEVEN_RESOURCES
            ),
            "provider_directory_expected_nonempty_resources": sorted(
                STATE_EXPECTED_NONEMPTY_RESOURCES
            ),
            "provider_directory_pagination_mode": "opaque_next_link_token",
        },
    }


def _contra_costa_seed_rows_from_developer_html(
    html_text: str,
    *,
    source_query: str | None = None,
    source_url: str = CONTRA_COSTA_PROVIDER_DIRECTORY_DOC_URL,
    source_date: str | None = None,
) -> list[dict[str, Any]]:
    parser = _HtmlLinkParser()
    parser.feed(html_text)
    rows: list[dict[str, Any]] = []
    seen: set[str] = set()
    for label, href in parser.links:
        label_key = re.sub(r"[^a-z0-9]+", "", (_clean_text(label) or "").lower())
        if "providerdirectoryapibaseurl" not in label_key:
            continue
        target_url = _external_splash_target_url(href, source_url=source_url)
        provider_base = _provider_directory_base_from_metadata_url(target_url)
        if not provider_base or provider_base in seen:
            continue
        seen.add(provider_base)
        row = _contra_costa_seed_row(provider_base, source_url=source_url, source_date=source_date)
        if _seed_row_matches_query(row, source_query):
            rows.append(row)
    return rows


def _contra_costa_fallback_seed_rows(
    *,
    source_query: str | None = None,
    source_url: str = CONTRA_COSTA_PROVIDER_DIRECTORY_DOC_URL,
) -> list[dict[str, Any]]:
    row = _contra_costa_seed_row(
        CONTRA_COSTA_PROVIDER_DIRECTORY_BASE,
        source_url=source_url,
        note_suffix=(
            "The official page can block automated fetches, so the importer retains the "
            "confirmed public metadata base as a fallback."
        ),
    )
    return [row] if _seed_row_matches_query(row, source_query) else []


def _seed_rows_from_contra_costa_catalog(
    *,
    source_query: str | None = None,
    timeout: int = 30,
    catalog_path: str | None = None,
    catalog_url: str | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    url = (
        _clean_text(catalog_url)
        or _clean_text(os.getenv(CONTRA_COSTA_PROVIDER_DIRECTORY_DOC_URL_ENV))
        or CONTRA_COSTA_PROVIDER_DIRECTORY_DOC_URL
    )
    try:
        text, source = _read_text_from_path_or_url(catalog_path, url, timeout=timeout)
    except Exception as exc:
        rows = _contra_costa_fallback_seed_rows(source_query=source_query, source_url=url)
        return rows, {
            "source": url,
            "rows": len(rows),
            "fallback": True,
            "error": _short_error(exc),
        }
    rows = _contra_costa_seed_rows_from_developer_html(
        text,
        source_query=source_query,
        source_url=source,
    )
    if rows:
        return rows, {"source": source, "rows": len(rows)}
    rows = _contra_costa_fallback_seed_rows(source_query=source_query, source_url=source)
    return rows, {"source": source, "rows": len(rows), "fallback": True}


def _seed_rows_from_cms_sma_endpoint_directory(
    *,
    source_query: str | None = None,
    timeout: int = 30,
    catalog_path: str | None = None,
    catalog_url: str | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    url = (
        _clean_text(catalog_url)
        or _clean_text(os.getenv(CMS_SMA_ENDPOINT_DIRECTORY_URL_ENV))
        or CMS_SMA_ENDPOINT_DIRECTORY_URL
    )
    text, source = _read_text_from_path_or_url(catalog_path, url, timeout=timeout)
    rows = _cms_sma_endpoint_directory_seed_rows_from_csv(
        text,
        source_query=source_query,
        source_url=source,
    )
    return rows, {"source": source, "rows": len(rows)}


def _provider_directory_blocker_seed_rows(*, source_query: str | None = None) -> list[dict[str, Any]]:
    try:
        registry = json.loads(
            PROVIDER_DIRECTORY_BLOCKER_REGISTRY_PATH.read_text(encoding="utf-8")
        )
        registry_entries = validate_blocker_registry(registry)
    except (OSError, json.JSONDecodeError, SupportDocumentationError) as exc:
        raise RuntimeError("Provider Directory blocker registry is invalid") from exc
    blocker_rows = []
    for registry_entry in registry_entries:
        source_url = _clean_text(registry_entry.get("source_url"))
        blocked_reason = _clean_text(registry_entry.get("reason"))
        access_requirement = _clean_text(registry_entry.get("access_requirement"))
        row_id = _clean_text(registry_entry.get("id"))
        org_name = _clean_text(registry_entry.get("display_name"))
        plan_name = _clean_text(registry_entry.get("plan_name"))
        blocker_rows.append(
            {
                "id": row_id,
                "org_name": org_name,
                "plan_name": plan_name,
                "api_base": None,
                "auth_type": access_requirement.replace("-", " "),
                "last_validated_status": PROVIDER_DIRECTORY_CATALOG_BLOCKED_STATUS,
                "requires_registration": registry_entry.get("requires_registration") is True,
                "source": PROVIDER_DIRECTORY_BLOCKER_REGISTRY_SOURCE,
                "source_detail": _clean_text(registry_entry.get("source_detail")),
                "source_url": source_url,
                "note": _clean_text(registry_entry.get("note")),
                "metadata_json": {
                    "provider_directory_blocked": True,
                    "provider_directory_blocked_reason": blocked_reason,
                    "provider_directory_blocked_operational_status": registry_entry[
                        "operational_status"
                    ],
                    "provider_directory_blocked_acquisition_method": registry_entry[
                        "acquisition_method"
                    ],
                    "provider_directory_documented_resources": registry_entry[
                        "documented_resources"
                    ],
                    "provider_directory_live_verification": registry_entry[
                        "live_verification"
                    ],
                    "provider_directory_reviewed_at": registry_entry["reviewed_at"],
                    "provider_directory_confirmed_catalog_url": source_url,
                },
            }
        )
    return [row for row in blocker_rows if _seed_row_matches_query(row, source_query)]


